# ║  Sets three module-level flags BEFORE any tkinter import so a           ║
# ║  headless container can import this file without display errors.        ║
# ║                                                                          ║
# ║  RUNTIME_MODE : str  — "local" | "web" | "headless"                    ║
# ║  UI_AVAILABLE : bool — True only when tkinter can open a display        ║
# ║  WEB_AVAILABLE: bool — True when fastapi + uvicorn are importable       ║
