import os as _os
import sys as _sys

_env_mode = _os.environ.get("FLIR_RUNTIME", "").strip().lower()
if _env_mode in ("web", "local", "headless"):
    RUNTIME_MODE: str = _env_mode
else:
    _fw_keys = ("fastapi", "uvicorn", "flask", "gunicorn", "starlette")
    if any(k in _sys.modules for k in _fw_keys):
        RUNTIME_MODE = "web"
    elif _sys.platform.startswith("linux") and not (
        _os.environ.get("DISPLAY") or _os.environ.get("WAYLAND_DISPLAY")
    ):
        RUNTIME_MODE = "headless"
    else:
        try:
            import tkinter as _tk_probe
            _r = _tk_probe.Tk(); _r.withdraw(); _r.destroy()
            del _tk_probe, _r
            RUNTIME_MODE = "local"
        except Exception:
            RUNTIME_MODE = "headless"

UI_AVAILABLE: bool = (RUNTIME_MODE == "local")
"""True when the process has a live display and can open tkinter windows."""

