# ============================================================================
# DUPLICATE IMAGE TRACKING AND CLEANUP SYSTEM (v3.30.25 FIX-DUPLICATES)
# ============================================================================
# CRITICAL FIX: Hash-based duplicate detection to prevent reprocessing the
# same image multiple times and accumulating duplicates across folders.
# Tracks processed images by content hash (SHA-256) in a persistent JSON DB.
# ============================================================================

import hashlib

class ImageDuplicateTracker:
    """Hash-based duplicate detection system to prevent image reprocessing."""
    def __init__(self, db_file='processed_images_hash.json'):
        self.db_file = Path(db_file)
        self.processed_hashes: dict = {}  # hash -> {filename, path, timestamp, destination}
        self._load_database()
    
    def _load_database(self):
        """Load tracking database from JSON"""
        if self.db_file.exists():
            try:
                with open(self.db_file, 'r', encoding='utf-8') as f:
                    data = json.load(f)
                    self.processed_hashes = data.get('processed_hashes', {})
                logging.info(f"[DuplicateTracker] Loaded {len(self.processed_hashes)} tracked images")
            except Exception as e:
                logging.warning(f"[DuplicateTracker] Could not load DB: {e}")
                self.processed_hashes = {}
    
    def _save_database(self):
        """Save tracking database to JSON"""
        try:
            with open(self.db_file, 'w', encoding='utf-8') as f:
                json.dump({'processed_hashes': self.processed_hashes}, f, indent=2)
        except Exception as e:
            logging.error(f"[DuplicateTracker] Could not save DB: {e}")
    
    def get_file_hash(self, filepath: str) -> str:
        """Calculate SHA-256 hash of file content"""
        try:
            with open(filepath, 'rb') as f:
                return hashlib.sha256(f.read()).hexdigest()
        except Exception as e:
            logging.warning(f"[DuplicateTracker] Error hashing {filepath}: {e}")
            return ""
    
    def is_duplicate(self, filepath: str) -> bool:
        """Check if this image has already been processed"""
        file_hash = self.get_file_hash(filepath)
        if not file_hash:
            return False
        return file_hash in self.processed_hashes
    
    def mark_processed(self, filepath: str, destination: str):
        """Mark image as processed"""
        file_hash = self.get_file_hash(filepath)
        if file_hash:
            self.processed_hashes[file_hash] = {
                'filename': os.path.basename(filepath),
                'original_path': str(filepath),
                'destination': str(destination),
                'timestamp': datetime.now().isoformat()
            }
            self._save_database()
    
    def get_duplicate_info(self, filepath: str) -> dict:
        """Get info about when/where this duplicate was processed"""
        file_hash = self.get_file_hash(filepath)
        return self.processed_hashes.get(file_hash, {})

# Global duplicate tracker instance
_DUPLICATE_TRACKER = ImageDuplicateTracker()

def cleanup_not_marked_duplicates(output_dir: Path) -> int:
    """Remove images from not_marked/ that exist in visual_annotated/."""
    removed = 0
    nm_dir = output_dir / "not_marked"
    vis_dir = output_dir.parent / "visual_annotated" / "visual"
    
    if not nm_dir.exists():
        return 0
    
    if not vis_dir.exists():
        return 0
    
    # Build set of stems that exist in visual_annotated
    visual_stems = {p.stem.replace('_visual', '') for p in vis_dir.glob("*_visual.jpg")}
    
    # Remove matching images from not_marked
    for nm_img in list(nm_dir.glob("*.jpg")) + list(nm_dir.glob("*.JPG")):
        if nm_img.stem in visual_stems:
            try:
                nm_img.unlink()
                logging.info(f"[Cleanup] Removed duplicate from not_marked: {nm_img.name}")
                removed += 1
                
                # Also remove associated JSON
                nm_json = nm_dir / "jsons" / f"{nm_img.stem}.json"
                if nm_json.exists():
                    nm_json.unlink()
                    
            except Exception as e:
                logging.warning(f"[Cleanup] Could not remove {nm_img.name}: {e}")
    
    return removed

def audit_all_duplicates(base_dir: Path) -> dict:
    """Scan all output folders and report duplicates by content hash."""
    from collections import defaultdict
    
    hash_to_files = defaultdict(list)
    folders_to_scan = [
        'not_marked',
        'visual_annotated/visual',
        'visual_annotated/annotated', 
        'annotated/original_ir'
    ]
    
    for folder_rel in folders_to_scan:
        folder_path = base_dir / folder_rel
        if folder_path.exists():
            for img in folder_path.rglob("*.jpg"):
                img_hash = _DUPLICATE_TRACKER.get_file_hash(str(img))
                if img_hash:
                    hash_to_files[img_hash].append(str(img.relative_to(base_dir)))
    
    # Find actual duplicates (hash appears in multiple locations)
    duplicates = {h: files for h, files in hash_to_files.items() if len(files) > 1}
    
    return {
        'total_images': sum(len(files) for files in hash_to_files.values()),
        'unique_images': len(hash_to_files),
        'duplicate_sets': len(duplicates),
        'duplicate_files': sum(len(files) - 1 for files in duplicates.values()),
        'duplicates': duplicates
    }

