def write_folder_manifest(folder: Path, key: str) -> None:
    """FEAT-MANIFEST-001 (v3.30.26.1): Write folder_manifest.json to ``folder``."""
    if not folder or not isinstance(folder, Path):
        return
    manifest_path = folder / "folder_manifest.json"
    if manifest_path.exists():
        return   # already written — no-op

    content = _FOLDER_MANIFESTS.get(key)
    if content is None:
        # Fallback for folders not listed above — write a minimal manifest
        content = {
            "folder": folder.name + "/",
            "purpose": f"Output subfolder managed by FLIR Thermal App v{APP_VERSION}.",
            "written_by": ["unknown"],
            "schema_summary": "See application documentation.",
        }

    manifest = {
        "_manifest_version": 1,
        "_generated_by": f"FLIR Thermal App v{APP_VERSION}",
        "_generated_at": datetime.now().isoformat(),
        **content,
    }
    try:
        folder.mkdir(parents=True, exist_ok=True)
        with open(manifest_path, "w", encoding="utf-8") as mf:
            json.dump(manifest, mf, indent=2)
        logging.debug(f"[Manifest] Written: {manifest_path}")
    except OSError as _me:
        logging.warning(f"[Manifest] Could not write {manifest_path}: {_me}")


# ============================================================================
# REPORT HELPER FUNCTIONS (FIX-09, FIX-11 v3.30.1.39)
# ============================================================================
# WHY defined at module level: These pure functions are used in multiple
# methods (_populate_template_tables, _generate_reports_for_folder,
# _build_report_data_qc).  Module-level definition avoids code duplication
# and makes unit-testing straightforward.

def _convert_object_distance_to_ft(raw_value, *, default_m: float = 1.0) -> str:
    """Convert FLIR EXIF ObjectDistance (always metres) to a feet string; validates 0.1–100 m range (FIX-09)."""
    METRES_TO_FEET = 3.28084
    MIN_METRES     = 0.1    # Closest typical FLIR inspection distance
    MAX_METRES     = 100.0  # Maximum practical thermal inspection distance
    try:
        dist_m = float(raw_value)
    except (TypeError, ValueError):
        logging.warning(
            f"ObjectDistance '{raw_value}' is not a valid float; "
            f"using default {default_m} m"
        )
        dist_m = default_m

    # Validate range — FLIR EXIF is always metres; out-of-range means wrong units
    # or a bad metadata edit.
    if not (MIN_METRES <= dist_m <= MAX_METRES):
        logging.warning(
            f"ObjectDistance {dist_m:.3f} m is outside expected FLIR range "
            f"({MIN_METRES}–{MAX_METRES} m).  "
            f"Possible wrong unit in metadata (expected metres)."
        )

    dist_ft = dist_m * METRES_TO_FEET
    return f"{dist_ft:.2f} ft"


def _fmt_datetime(raw: str) -> str:
    """Format a raw FLIR EXIF DateTimeOriginal string ("YYYY:MM:DD HH:MM:SS") to "YYYY-MM-DD  HH:MM" for reports (FIX-11)."""
    if not raw or not raw.strip():
        return "N/A"
    try:
        # Standard EXIF format: YYYY:MM:DD HH:MM:SS
        dt = datetime.strptime(raw.strip(), "%Y:%m:%d %H:%M:%S")
        return dt.strftime("%Y-%m-%d  %H:%M")
    except (ValueError, AttributeError):
        # Non-standard format — return as-is (don't corrupt the value)
        return raw.strip() or "N/A"


def _round_val_to_int(val, default: str = "N/A") -> str:
    """Round a numeric value to the nearest integer string for reports; used for camera range fields only (NOT spot temps)."""
    if val is None or str(val).strip() in ("", "N/A"):
        return default
    try:
        return str(round(float(val)))
    except (TypeError, ValueError):
        return default


def _fmt_celsius(val, default: float = 20.0, precision: int = 2) -> str:
    """Format a Celsius temperature for display — always in °C (no conversion).
    Kept for backward-compat call sites that don't have a unit parameter.
    """
    return _fmt_temp(val, unit='C', default_c=default, precision=precision)


def _fmt_temp(val, unit: str = 'C', default_c: float = 20.0, precision: int = 2) -> str:
    """Format a temperature value (stored in °C) for display in the requested unit.

    WHY THIS HELPER EXISTS (BUG-NEGZERO-001 / BUG-UNIT-001, v3.30.25.16):
        • Prevents "-0.00" from K→C float artifacts (abs < 0.005 → clamped to 0.00)
        • Converts °C → °F when unit=='F' so reports match the user's TempUnit setting
        • val is ALWAYS expected in °C — conversion happens here at display time

    Args:
        val:       Raw value (°C). May be float, int, or numeric string.
        unit:      'C' or 'F'. Kelvin not supported for report display.
        default_c: Fallback in °C if val is None/invalid.
        precision: Decimal places (default 2).

    Returns:
        Formatted string e.g. "20.00", "-6.00", "68.00" (no unit symbol).
    """
    try:
        fv = float(val) if val not in (None, '', 'N/A') else default_c
    except (ValueError, TypeError):
        fv = default_c
    if unit == 'F':
        fv = fv * FAHRENHEIT_SCALE + FAHRENHEIT_OFFSET
    # Kill -0.00 / +0.00 display artifacts: clamp near-zero to exactly 0.0
    threshold = 0.5 * (10 ** -precision)   # 0.005 for precision=2
    if abs(fv) < threshold:
        fv = 0.0
    return f"{fv:.{precision}f}"


def _fmt_range(val, unit: str = 'C', default: str = 'N/A') -> str:
    """Format a camera range value (stored in °C) as a rounded integer in the requested unit.

    BUG-UNIT-001 FIX (v3.30.25.16): Range Max/Min are stored in °C in the CSV.
    When TempUnit == 'F' they must be converted before display in reports.

    Args:
        val:     Range value in °C (numeric or string).
        unit:    'C' or 'F'.
        default: Returned as-is when val is None/invalid.

    Returns:
        Rounded integer string e.g. '120', '-20', '248', '-4'.
    """
    if val is None or str(val).strip() in ('', 'N/A'):
        return default
    try:
        fv = float(val)
        if unit == 'F':
            fv = fv * FAHRENHEIT_SCALE + FAHRENHEIT_OFFSET
        return str(round(fv))
    except (TypeError, ValueError):
        return default


def _validate_and_correct_csv_spot_order(
    row: dict,
    ann_folder: "Path",
    stem: str,
    unit: str,
) -> tuple:
    """Cross-check and correct Spot1..Spot4 column order in a CSV row dict.

    REPORT-SPORDER-001 (v3.30.25.21):
    WHY THIS IS NEEDED:
        The batch detection pipeline writes Spot1..Spot4 from `temps_vals`, which
        is indexed by YOLO detection order (Y-sorted, top→bottom).  The JSON sidecar
        stores spot_meters with correct spatial IDs (SP1=TL, SP2=TR, SP3=BL,
        SP4=BR) assigned by _assign_spatial_ids().  When detection order differs
        from spatial order (e.g. SP2 was detected first), Spot1 in the CSV holds
        SP2's temperature.  The same transposition happens on QC saves that were
        made before BUG-CSV-SPORDER-001 was fixed.

        This function is called ONCE per row, immediately before report_data is
        built, so corrections are applied to the in-memory row dict without
        touching the CSV file on disk.  A separate corrected row is also returned
        so the caller can optionally rewrite the CSV in-place after report generation.

    LOOKUP ORDER (mirrors _json_path_for):
        1. ann_folder / qc_jsons / {stem}.json   (QC override takes precedence)
        2. ann_folder / detection_jsons / {stem}.json
        3. ann_folder / {stem}.json              (legacy flat layout)

    Args:
        row:        A csv.DictReader row dict — modified in-place on mismatch.
        ann_folder: Path to the annotated/ folder (parent of qc_jsons/ etc.).
        stem:       Image filename stem (no extension, no suffix like _visual).
        unit:       Temperature unit string, e.g. "C" or "F".

    Returns:
        (corrected: bool, n_swapped: int, json_source: str)
            corrected   — True if at least one column was updated.
            n_swapped   — number of Spot columns that changed value.
            json_source — which JSON file was used ("" if none found).
    """
    # ── Step 1: locate JSON sidecar ──────────────────────────────────────────
    _ann = Path(ann_folder)
    _candidates = [
        _ann / "qc_jsons"        / f"{stem}.json",
        _ann / "detection_jsons" / f"{stem}.json",
        _ann / f"{stem}.json",
    ]
    json_path = next((p for p in _candidates if p.exists()), None)
    if json_path is None:
        # No JSON available — cannot validate; leave row unchanged.
        return False, 0, ""

    # ── Step 2: load spot_meters and sort by SP ID ────────────────────────────
    try:
        with open(json_path, "r", encoding="utf-8") as _jf:
            _jdata = json.load(_jf)
    except Exception as _je:
        logging.warning(
            f"REPORT-SPORDER-001: could not read JSON {json_path.name}: {_je} "
            f"— skipping spot-order validation for {stem}"
        )
        return False, 0, str(json_path)

    spot_meters = _jdata.get("spot_meters") or _jdata.get("spotmeters") or []
    if not spot_meters:
        return False, 0, str(json_path)

    def _sp_num(s):
        """Extract integer from 'SPn' id; unknown ids sort last (9)."""
        _id = s.get("id", "SP9")
        try:
            return int(_id[2:]) if _id.startswith("SP") and _id[2:].isdigit() else 9
        except (ValueError, IndexError):
            return 9

    # Build {sp_number: temperature_celsius} from JSON, e.g. {1: 26.5, 2: 27.6, ...}
    _json_map: dict = {}
    for _s in spot_meters:
        _n = _sp_num(_s)
        if 1 <= _n <= 4:
            _tc = _s.get("temperature_celsius")
            _tp = _s.get("temp")
            _tv = _tc if _tc is not None else _tp
            if _tv is not None:
                try:
                    _json_map[_n] = float(_tv)
                except (TypeError, ValueError):
                    pass

    if not _json_map:
        return False, 0, str(json_path)

    # ── Step 3: compare JSON SP temps against current CSV Spot columns ────────
    _unit_lbl  = f"°{unit}"
    _col_names = {n: f"Spot{n} ({_unit_lbl})" for n in range(1, 5)}
    _TOL       = 0.15   # °C tolerance — rounding differences are expected

    # Read what CSV currently has for each position
    _csv_vals: dict = {}
    for _n, _col in _col_names.items():
        _sv = row.get(_col, "")
        if _sv and str(_sv).strip() not in ("", "N/A"):
            try:
                _csv_vals[_n] = float(_sv)
            except (TypeError, ValueError):
                pass

    if not _csv_vals:
        return False, 0, str(json_path)

    # Quick check: does each Spot{n} already match SP{n}?  If all within tolerance, skip.
    _all_match = all(
        abs(_csv_vals.get(_n, float("nan")) - _tv) <= _TOL
        for _n, _tv in _json_map.items()
        if _n in _csv_vals
    )
    if _all_match:
        return False, 0, str(json_path)

    # ── Step 4: mismatch detected — rewrite Spot columns from JSON SP IDs ────
    # Only overwrite columns for which the JSON has a value; leave others untouched.
    _n_swapped = 0
    for _n, _jt in _json_map.items():
        _col = _col_names.get(_n)
        if _col is None:
            continue
        _new_val = f"{_jt:.1f}"
        _old_val = row.get(_col, "")
        if _old_val != _new_val:
            row[_col] = _new_val
            _n_swapped += 1

    # Max Δ — derived directly from the JSON spot temps (not re-read from row).
    # JSON does not store Max Δ as a field; it stores per-spot temperatures, so
    # we compute max minus min from _json_map values — the same source just used
    # to correct the Spot columns above.
    _delta_col = next((k for k in row if "Max" in k and "\u0394" in k), None)
    if _delta_col and len(_json_map) >= 2:
        _temps_from_json = list(_json_map.values())
        row[_delta_col] = f"{max(_temps_from_json) - min(_temps_from_json):.1f}"

    logging.info(
        f"REPORT-SPORDER-001: corrected {_n_swapped} Spot column(s) for {stem} "
        f"using {json_path.name} — CSV had {_csv_vals}, JSON SP map: {_json_map}"
    )
    return True, _n_swapped, str(json_path)


def _is_anomalous_status(status: str) -> bool:
    """Return True if a CSV Status is NOT one of {"OK","Manual OK","Manually Corrected"} — allowlist-based exclusion for reports and training export (FIX-34)."""
    s = str(status).strip()
    # Normalise: strip sub-qualifiers like "Manual OK" prefix in "Manual OK - …"
    # so the comparison is reliable even if extra detail was appended.
    _ACCEPTED = {"OK", "Manual OK", "Manually Corrected", "OK (Low Conf)"}  # low-conf recovered images are valid
    return s not in _ACCEPTED


