# ============================================================================
# ASTM E1934 THRESHOLD MAPPING (Expert Audit P2 — v3.30.18)
# ============================================================================
# WHY: The Excellent/Acceptable/Marginal/Failed inspection grades already exist
# in the application.  Mapping them to the ASTM E1934 standard (ΔT threshold
# tables for electrical components) adds defensibility for clients requiring
# standards-compliant inspection reports, and is primarily a configuration change.
#
# ASTM E1934 "Standard Guide for Examining Electrical and Mechanical Equipment
# with Infrared Thermography" — Table 1: ΔT Classification for Electrical Systems
#
# These thresholds define the temperature DIFFERENCE between the suspected fault
# component and an equivalent component under the same load (or ambient reference).
# They are load-dependent; the table below assumes ≥ 40% rated load.
# Operators can override per-site via the [ASTM] section of settings.ini.
#
# REFERENCE: ASTM E1934-99a (reapproved 2014), Section 6.2, Table 1.
# Also cross-referenced: NETA MTS-2019 Table 100.18 for electrical connections.
# ============================================================================

ASTM_E1934_THRESHOLDS = {
    # Grade       : (ΔT_max°C,  ASTM severity description,            Recommended action)
    "Normal"      : (1.0,  "ΔT < 1°C — No deficiency",               "Continue normal maintenance schedule"),
    "Monitor"     : (10.0, "1 ≤ ΔT < 10°C — Possible deficiency",    "Monitor at next scheduled inspection"),
    "Marginal"    : (25.0, "10 ≤ ΔT < 25°C — Deficiency",            "Schedule repair at next planned outage"),
    "Critical"    : (40.0, "25 ≤ ΔT < 40°C — Serious deficiency",    "Repair as soon as possible"),
    "Immediately" : (None, "ΔT ≥ 40°C — Critical deficiency",        "Take immediate corrective action"),
}

# IEC 60079-7 E2 classification thresholds (hazardous-area electrical equipment).
# Used when ASTM mode is "IEC" in settings (different client requirements).
IEC_60079_THRESHOLDS = {
    "Compliant"   : (5.0,  "ΔT < 5°C",           "No action required"),
    "Advisory"    : (15.0, "5 ≤ ΔT < 15°C",      "Log and monitor"),
    "Action"      : (30.0, "15 ≤ ΔT < 30°C",     "Schedule inspection"),
    "Emergency"   : (None, "ΔT ≥ 30°C",           "Immediate shutdown assessment"),
}


def get_astm_e1934_grade(delta_t_celsius: float) -> dict:
    """Return the ASTM E1934 classification for a given ΔT value."""
    delta_t = abs(delta_t_celsius)

    # Check for operator-configured overrides in [ASTM] section of settings.ini
    # Allows site-specific threshold adjustments for load < 40% or exotic components.
    try:
        mode = CFG.get("ASTM", "Mode", "ASTM_E1934")
        thresholds = ASTM_E1934_THRESHOLDS if mode != "IEC" else IEC_60079_THRESHOLDS
    except Exception:
        thresholds = ASTM_E1934_THRESHOLDS

    # Walk thresholds in severity order (lowest ΔT first)
    prev_max = 0.0
    for grade_label, (dt_max, description, action) in thresholds.items():
        if dt_max is None or delta_t < dt_max:
            return {
                "grade":       grade_label,
                "delta_t":     round(delta_t, 2),
                "delta_t_max": dt_max,
                "delta_t_min": round(prev_max, 1),
                "description": description,
                "action":      action,
                "standard":    "ASTM E1934" if mode != "IEC" else "IEC 60079-7",
            }
        prev_max = dt_max

    # Fallback (should not be reached if thresholds have a None-capped entry)
    last_grade, (_, last_desc, last_action) = list(thresholds.items())[-1]
    return {
        "grade":       last_grade,
        "delta_t":     round(delta_t, 2),
        "delta_t_max": None,
        "delta_t_min": round(prev_max, 1),
        "description": last_desc,
        "action":      last_action,
        "standard":    "ASTM E1934",
    }


def format_astm_report_line(delta_t_celsius: float, component_name: str = "") -> str:
    """Format a single-line ASTM E1934 classification for inclusion in inspection"""
    info = get_astm_e1934_grade(delta_t_celsius)
    prefix = f"{component_name} | " if component_name else ""
    return (
        f"{prefix}ΔT={info['delta_t']:.1f}°C | "
        f"{info['standard']}: {info['grade']} | "
        f"{info['action']}"
    )


