# ============================================================================
# ENTERPRISE AUDIT TRACE LOGGER  (P3 – v3.30.15)
# ============================================================================
# Writes a structured, append-only JSONL audit log to SCRIPT_DIR/audit_trace.jsonl.
# Every significant user action and system event is recorded with a monotonic
# session_id so individual batch runs can be extracted from the combined log.
#
# JSONL format (one JSON object per line):
#   {"ts": ISO8601, "session": UUID4, "event": str, "detail": {...}}
#
# Typical events:
#   APP_START, BATCH_START, BATCH_END, IMAGE_PROCESSED, QC_SAVE,
#   EXPORT_START, EXPORT_COMPLETE, TRAIN_START, TRAIN_END,
#   PLANCK_VALIDATION, REPORT_GENERATED, SETTINGS_CHANGED
# ============================================================================


# ╔══════════════════════════════════════════════════════════════════════════╗
# ║  SECTION 07 — AUDIT TRACE LOGGER                                            ║
# ║  WAL-safe JSONL audit log. Never raises — audit failure is non-fatal.      ║
# ╚══════════════════════════════════════════════════════════════════════════╝

class AuditTraceLogger:
    """Singleton enterprise audit logger.  Thread-safe append to audit_trace.jsonl."""
    _instance: Optional["AuditTraceLogger"] = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._init()
        return cls._instance

    def _init(self):
        self._lock = threading.Lock()
        self.session_id = str(uuid.uuid4())
        # Lazy path — SCRIPT_DIR is defined later in the module
        self._log_path: Optional[Path] = None
        self._pending: list = []  # buffer until SCRIPT_DIR is available
        self._ready = False

    def _ensure_ready(self) -> bool:
        """Resolve log path once SCRIPT_DIR is bound."""
        if self._ready:
            return True
        try:
            _script_dir = Path(__file__).parent.resolve()
            self._log_path = _script_dir / "audit_trace.jsonl"
            self._ready = True
            # Replay any WAL sidecar from a prior crash BEFORE flushing pending buffer
            self._replay_wal()
            # Flush pending buffer through WAL path so each line is committed safely
            if self._pending:
                with self._lock:
                    for line in self._pending:
                        self._wal_append(line)
                    self._pending.clear()
            return True
        except Exception:
            return False

    def log(self, event: str, detail: Optional[dict] = None) -> None:
        """Append one audit record.  Never raises — audit failure is non-fatal."""
        try:
            record = {
                "ts":      datetime.now().isoformat(timespec="seconds"),
                "session": self.session_id,
                "event":   event,
                "detail":  detail or {},
            }
            line = json.dumps(record, ensure_ascii=False, default=str)
            if self._ensure_ready() and self._log_path is not None:
                with self._lock:
                    self._wal_append(line)
            else:
                with self._lock:
                    self._pending.append(line)
        except Exception:
            pass  # Audit failure must never crash the application

    def _wal_append(self, line: str) -> None:
        """WAL-safe append of a single JSONL line to the audit log."""
        try:
            wal_path = self._log_path.with_suffix(".jsonl.wal")

            # ── Step 1: Write WAL sidecar (durable marker) ───────────────────
            with open(wal_path, "w", encoding="utf-8") as wal_fh:
                wal_fh.write(line + "\n")
                wal_fh.flush()
                try:
                    import os as _os
                    _os.fsync(wal_fh.fileno())   # force to disk before proceeding
                except OSError:
                    pass  # fsync unavailable on some platforms (e.g. network filesystems)

            # ── Step 2: Append to main JSONL ─────────────────────────────────
            with open(self._log_path, "a", encoding="utf-8") as fh:
                fh.write(line + "\n")

            # ── Step 3: Unlink WAL sidecar (commit) ──────────────────────────
            try:
                wal_path.unlink()
            except OSError:
                pass  # Best-effort; will be replayed harmlessly next time
        except Exception as _wal_err:
            # Fallback: if WAL machinery fails, write directly (degrade gracefully)
            logging.debug(f"AuditTraceLogger WAL error ({_wal_err}); falling back to direct append")
            try:
                with open(self._log_path, "a", encoding="utf-8") as fh:
                    fh.write(line + "\n")
            except Exception:
                pass

    def _replay_wal(self) -> None:
        """Replay any surviving WAL sidecar from a previous crashed session."""
        try:
            if self._log_path is None:
                return
            wal_path = self._log_path.with_suffix(".jsonl.wal")
            if not wal_path.exists():
                return
            wal_content = wal_path.read_text(encoding="utf-8").strip()
            if wal_content:
                with open(self._log_path, "a", encoding="utf-8") as fh:
                    fh.write(wal_content + "\n")
                logging.info("AuditTraceLogger: replayed 1 record from WAL sidecar (previous crash recovery)")
            wal_path.unlink()
        except Exception:
            pass  # WAL replay failure is non-fatal

    def new_session(self) -> str:
        """Start a new logical session (e.g. new batch run). Returns new session ID."""
        self.session_id = str(uuid.uuid4())
        return self.session_id


# Module-level singleton — import anywhere; call AUDIT.log(...)
AUDIT = AuditTraceLogger()


# ============================================================================
# DATASET FINGERPRINTING  (P1 – v3.30.15)
# ============================================================================
def compute_dataset_fingerprint(dataset_root: Path, extra_content: str = "") -> str:
    """Return a short SHA-256 fingerprint of a YOLO dataset directory tree."""
    try:
        h = hashlib.sha256()
        # ── 1. Image filename + size pairs (deterministic, fast) ──────────────
        for split in ("train", "val"):
            img_dir = dataset_root / "images" / split
            if not img_dir.exists():
                img_dir = dataset_root / "images"
            if not img_dir.exists():
                continue
            for img in sorted(img_dir.iterdir()):
                if img.is_file():
                    h.update(f"{img.name}:{img.stat().st_size}\n".encode())
        # ── 2. data.yaml content — catches class/path/split changes ──────────
        yaml_path = dataset_root / "data.yaml"
        if yaml_path.exists():
            try:
                h.update(b"[data.yaml]\n")
                h.update(yaml_path.read_bytes())
            except OSError:
                pass
        # ── 3. Optional hyperparameter blob (training runs) ───────────────────
        if extra_content:
            h.update(b"[hyperparams]\n")
            h.update(extra_content.encode("utf-8", errors="replace"))
        return h.hexdigest()[:12]
    except Exception:
        return "unknown"


