# UTILITY FUNCTIONS - CRITICAL SAFETY (A-002, A-003)
# ============================================================================

def safe_divide(numerator: Union[float, np.ndarray], 
                denominator: Union[float, np.ndarray], 
                default: float = 0.0) -> Union[float, np.ndarray]:
    """Zero-safe division for scalars and numpy arrays — returns default when |denominator| ≤ 1e-10 (A-002)."""
    if isinstance(denominator, np.ndarray):
        result = np.full_like(numerator, default, dtype=np.float32)
        mask = np.abs(denominator) > EPSILON
        result[mask] = numerator[mask] / denominator[mask]
        return result
    else:
        return numerator / denominator if abs(denominator) > EPSILON else default


def safe_array_access(array: np.ndarray, 
                      indices: Union[int, Tuple[int, ...]], 
                      default: Any = None) -> Any:
    """Bounds-safe numpy array element read — returns default instead of raising IndexError (A-003)."""
    try:
        if isinstance(indices, int):
            indices = (indices,)
        for idx, dim_size in zip(indices, array.shape):
            if idx < 0 or idx >= dim_size:
                return default
        return array[indices]
    except (IndexError, TypeError, ValueError):
        return default


def get_class_from_filename(filename: str) -> int:
    """Return internal taxonomy class ID from filename (0=LBD_T1, 1=LBD_T2, 2=TBX, 3=LBD_T3/default). NEVER write this to YOLO labels — use get_yolo_class_id() instead."""
    filename_lower = filename.lower()

    if "tbx" in filename_lower:
        return 2                              # TBX — Terminal Box (2 spots)
    elif "midpoint" in filename_lower or "gaia" in filename_lower:
        return 1                              # LBD_Type_2 (6 spots)
    elif ("unbridled" in filename_lower or
          "sypert"    in filename_lower or
          "ridgley"   in filename_lower):
        return 0                              # LBD_Type_1 (4 spots)
    else:
        return 3                              # LBD_Type_3 — default (4 spots, generic name)


def get_yolo_class_id(filename: str) -> int:
    """Always returns 0 — the ONLY function to call when writing YOLO label class IDs. Training is always nc=1/class-0; MultiClass is post-detection only (v3.30.5 user request)."""
    # [USER REQUEST v3.30.5] Always return 0.
