# ║  SECTION 06 — FILE I/O UTILITIES                                        ║
# ║  atomic_write_json / safe_write_json / safe_read_json / sanitize paths  ║
# ╚══════════════════════════════════════════════════════════════════════════╝

def atomic_write_json(filepath: Path, 
                      data: Dict, 
                      use_lock: bool = True,
                      indent: int = JSON_INDENT) -> None:
    """Crash-safe JSON file write: temp-file → atomic rename + optional FileLock."""
    filepath = Path(filepath)
    temp_file = filepath.with_suffix('.tmp')
    lock_file = filepath.with_suffix('.lock')
    
    try:
        if use_lock and FILELOCK_AVAILABLE:
            # Use file locking for concurrent safety
            with FileLock(str(lock_file), timeout=FILE_LOCK_TIMEOUT):
                # Write to temp file
                with open(temp_file, 'w', encoding='utf-8') as f:
                    json.dump(data, f, indent=indent)
                
                # Atomic rename
                temp_file.replace(filepath)
        else:
            # No locking (single-user mode)
            with open(temp_file, 'w', encoding='utf-8') as f:
                json.dump(data, f, indent=indent)
            temp_file.replace(filepath)
    
    except FileLockTimeout:
        logging.error(f"Failed to acquire file lock for {filepath.name}")
        raise
    except IOError as e:
        logging.error(f"Failed to write {filepath.name}: {e}")
        raise
    finally:
        # Cleanup temp file if it exists
        if temp_file.exists():
            temp_file.unlink()


def atomic_write_csv(filepath: Path, 
                     rows: List[List[Any]], 
                     use_lock: bool = True) -> None:
    """Crash-safe CSV file write: temp-file → atomic rename + optional FileLock."""
    filepath = Path(filepath)
    temp_file = filepath.with_suffix('.tmp')
    lock_file = filepath.with_suffix('.lock')
    
    try:
        if use_lock and FILELOCK_AVAILABLE:
            with FileLock(str(lock_file), timeout=FILE_LOCK_TIMEOUT):
                with open(temp_file, 'w', newline='', encoding='utf-8') as f:
                    writer = csv.writer(f)
                    writer.writerows(rows)
                temp_file.replace(filepath)
        else:
            with open(temp_file, 'w', newline='', encoding='utf-8') as f:
                writer = csv.writer(f)
                writer.writerows(rows)
            temp_file.replace(filepath)
    
    except FileLockTimeout:
        logging.error(f"Failed to acquire file lock for {filepath.name}")
        raise
    except IOError as e:
        logging.error(f"Failed to write {filepath.name}: {e}")
        raise
    finally:
        if temp_file.exists():
            temp_file.unlink()



# FIX-CSV-001 v3.30.24: sanity CSV schema validator
# Validates Report_*.csv files: required columns present, no duplicate filenames,
# rows sorted by Filename, all expected columns in correct order.
_CSV_REQUIRED_COLS = (
    "Filename", "Status", "Expected_Spots", "Detected_Spots",
    "Max Δ", "Geometry_Valid",
)

def validate_report_csv(csv_path: Path) -> dict:
    """Validate a Report_*.csv file for schema compliance (FIX-CSV-001)."""
    result: dict = {"ok": True, "warnings": [], "errors": []}
    if not csv_path.exists():
        result.update({"ok": False, "errors": [f"File not found: {csv_path}"]})
        return result

    try:
        with open(csv_path, newline="", encoding="utf-8") as _f:
            rows = list(csv.DictReader(_f))
    except Exception as _re:
        result.update({"ok": False, "errors": [f"Read error: {_re}"]})
        return result

    if not rows:
        result["warnings"].append("CSV has no data rows.")
        return result

    actual_cols = set(rows[0].keys()) if rows else set()

    # Check required columns (partial match — Δ may have unit suffix)
    for req in _CSV_REQUIRED_COLS:
        if not any(req in col for col in actual_cols):
            result["errors"].append(f"Missing required column containing '{req}'")
            result["ok"] = False

    # Duplicate filename detection
    filenames = [r.get("Filename", "") for r in rows]
    seen: set = set()
    dups = [fn for fn in filenames if fn in seen or seen.add(fn)]  # type: ignore[func-returns-value]
    if dups:
        result["warnings"].append(f"Duplicate Filename values ({len(dups)}): {dups[:5]}")

    # Sort-order check (advisory)
    if filenames != sorted(filenames):
        result["warnings"].append("Rows are not sorted by Filename.")

    if result["errors"]:
        logging.error(f"[validate_report_csv] {csv_path.name}: {result['errors']}")
    if result["warnings"]:
        logging.warning(f"[validate_report_csv] {csv_path.name}: {result['warnings']}")
    else:
        logging.info(f"[validate_report_csv] {csv_path.name}: schema OK ✓")
    return result



# WHY: File-saving calls accept folder paths from filedialog and from
# settings.ini.  A crafted path like "../../etc/passwd" passed via the API or
# a malformed settings.ini could write outside the intended directory.
#
# APPROACH: sanitize_output_path() resolves the path to an absolute canonical
# form (symlinks, .., . all resolved) and asserts that the resolved path
# starts with the expected allowed root.  Raises ValueError on violations so
# callers can catch and show a user-visible error rather than silently writing
# to an unintended location.
#
# CALLED BY: any function that builds a write path from user-supplied input.
# Key call sites: export_detections_to_training(), save_quality_metadata(),
# rebuild_rjpeg(), _save_csv_row(), and any future file-write helper.
# ============================================================================

def sanitize_output_path(
    candidate: Union[str, Path],
    allowed_root: Union[str, Path],
    *,
    create_parents: bool = False,
    check_suffix: Optional[str] = None,
) -> Path:
    """
        Resolve candidate to an absolute path and verify it lives under allowed_root.
        Args:
    """
    if not candidate:
        raise ValueError("sanitize_output_path: candidate path is empty")

    # Resolve both paths to canonical absolute form (no symlinks, no ..)
    resolved_candidate = Path(candidate).resolve()
    resolved_root      = Path(allowed_root).resolve()

    # Path.is_relative_to() is Python 3.9+.  For 3.8 compatibility we use
    # string prefix matching on the string representation with a trailing sep,
    # to avoid false positives like /allowed/dir matching /allowed/directory.
    root_str      = str(resolved_root)
    candidate_str = str(resolved_candidate)

    # Ensure the root string ends with os.sep for prefix matching
    import os as _os_path
    root_prefix = root_str if root_str.endswith(_os_path.sep) else root_str + _os_path.sep

    # Allow the path to equal the root exactly OR start with root + sep
    if candidate_str != root_str and not candidate_str.startswith(root_prefix):
        raise ValueError(
            f"Path traversal denied: '{candidate_str}' is outside "
            f"the allowed root '{root_str}'"
        )

    # Optional suffix check (e.g. ensure we only write .json files)
    if check_suffix is not None:
        if resolved_candidate.suffix.lower() != check_suffix.lower():
            raise ValueError(
                f"Path suffix mismatch: expected '{check_suffix}', "
                f"got '{resolved_candidate.suffix}' for '{candidate_str}'"
            )

    # Safe to create parent directories now that traversal is confirmed clean
    if create_parents:
        resolved_candidate.parent.mkdir(parents=True, exist_ok=True)

    return resolved_candidate


def sanitize_error_message(error: Exception, 
                           filepath: Optional[Path] = None) -> str:
    """
        Strip full filesystem paths from exception messages before showing to users (A-009).
        Example:
    """
    error_str = str(error)
    
    # If filepath provided, replace full path with just filename
    if filepath:
        filename = filepath.name
        # Replace any occurrence of full path with just filename
        error_str = error_str.replace(str(filepath), filename)
        error_str = error_str.replace(str(filepath.absolute()), filename)
    
    # Remove common path patterns (re imported at module level)
    # Remove Unix-style paths
    error_str = re.sub(r'/[^/\s]+/', '', error_str)
    # Remove Windows-style paths  
    error_str = re.sub(r'[A-Z]:\\[^\\s]+\\', '', error_str)
    
    return error_str


def get_camera_planck_constants(camera_model: str) -> Dict[str, float]:
    """Look up Planck radiometric calibration constants for a FLIR camera model."""
    # Try exact match first
    if camera_model in CAMERA_PLANCK_CONSTANTS:
        return CAMERA_PLANCK_CONSTANTS[camera_model]
    
    # Try partial match (e.g., "E75" in "FLIR E75")
    for model_key in CAMERA_PLANCK_CONSTANTS:
        if camera_model in model_key or model_key in camera_model:
            logging.info(f"Matched '{camera_model}' to '{model_key}' constants")
            return CAMERA_PLANCK_CONSTANTS[model_key]
    
    # Fallback to default
    logging.warning(f"Unknown camera '{camera_model}', using {DEFAULT_CAMERA_MODEL} defaults")
    return CAMERA_PLANCK_CONSTANTS[DEFAULT_CAMERA_MODEL]


def safe_get_meta(meta: Dict, key: str, default: Any = None) -> Any:
    """Safely retrieve a metadata value with key-variant fallbacks."""
    # 1. Exact match — fastest path; most common after FIX #2b strips prefixes
    if key in meta:
        return meta[key]

    # 2. FLIR group prefix (PyExifTool with 'FLIR:all' tag group)
    flir_key = f"FLIR:{key}"
    if flir_key in meta:
        return meta[flir_key]

    # 3. APP1 group prefix — v3.30.1.12 FIX #2a:
    #    PyExifTool get_tags() places FLIR radiometric data (PlanckR1, PlanckB,
    #    etc.) under the APP1 IFD group by default. This was the root cause of
    #    'Planck R1: NOT FOUND' in the logs and wrong temperatures for all images.
    app1_key = f"APP1:{key}"
    if app1_key in meta:
        return meta[app1_key]

    # 4. Composite group prefix (exiftool computed/derived tags)
    composite_key = f"Composite:{key}"
    if composite_key in meta:
        return meta[composite_key]

    # 5. EXIF group prefix (standard EXIF tags sometimes returned grouped)
    exif_key = f"EXIF:{key}"
    if exif_key in meta:
        return meta[exif_key]

    # 6. Case-insensitive scan — last resort; O(n) but rarely reached
    key_lower = key.lower()
    for k in meta:
        if k.lower() == key_lower:
            return meta[k]

    return default


# ============================================================================
# LOGGING SETUP (A-008: Log Rotation)
# ============================================================================

def setup_logging(log_file: Optional[Path] = None,
                  level: int = logging.DEBUG) -> None:
    """
        Configure logging with rotation support (A-008, FIX-LOG-001 v3.30.24).
        Console: WARNING+ (quiet by default).
        File:    DEBUG+  (full trace in rotating log).
    """
    logger = logging.getLogger()
    logger.setLevel(logging.DEBUG)   # root captures all; handlers filter

    # Remove existing handlers to avoid duplicate output on re-call
    for handler in logger.handlers[:]:
        logger.removeHandler(handler)

    _con_fmt  = logging.Formatter('%(asctime)s [%(levelname)s] %(message)s',
                                   datefmt='%H:%M:%S')
    _file_fmt = logging.Formatter(
        '%(asctime)s [%(levelname)-8s] %(name)s — %(message)s',
        datefmt='%Y-%m-%d %H:%M:%S'
    )

    # Console — WARNING+ so INFO spam doesn't flood the terminal
    console_handler = logging.StreamHandler()
    console_handler.setLevel(logging.WARNING)
    console_handler.setFormatter(_con_fmt)
    logger.addHandler(console_handler)

    # Rotating file — DEBUG+ for full diagnostics (FIX-LOG-001)
    if log_file:
        try:
            log_file = Path(log_file)
            log_file.parent.mkdir(parents=True, exist_ok=True)
            file_handler = RotatingFileHandler(
                filename=str(log_file),
                maxBytes=LOG_MAX_BYTES,        # 10 MB
                backupCount=LOG_BACKUP_COUNT,  # 5 archives
                encoding='utf-8'
            )
            file_handler.setLevel(logging.DEBUG)
            file_handler.setFormatter(_file_fmt)
            logger.addHandler(file_handler)
            logging.info(
                f"✓ Log rotation enabled: {log_file.name} "
                f"(max {LOG_MAX_BYTES/1024/1024:.0f} MB, {LOG_BACKUP_COUNT} backups)"
            )
        except Exception as e:
            logging.error(f"Failed to setup file logging: {e}")


# Initialize logging — FIX-LOG-001 v3.30.24: anchor to SCRIPT_DIR, not cwd
setup_logging(SCRIPT_DIR / "flir_thermal_app.log")

