# CLAHE CACHE (ML-002: CLAHE Result Caching)
# ============================================================================


# ╔══════════════════════════════════════════════════════════════════════════╗
# ║  SECTION 08 — CLAHE CACHE                                                   ║
# ║  Thread-safe LRU cache for CLAHE-processed thermal images.                 ║
# ╚══════════════════════════════════════════════════════════════════════════╝

class CLAHECache:
    """LRU cache for CLAHE preprocessing results (ML-002)."""
    
    def __init__(self, max_size: int = CLAHE_CACHE_MAX_SIZE):
        """Initialize CLAHE cache."""
        self.max_size = max_size
        self.cache: Dict[str, np.ndarray] = {}
        self.access_order: List[str] = []
        self.hits = 0
        self.misses = 0
        self.lock = threading.Lock()
    
    def _generate_key(self, image: np.ndarray, 
                      clip_limit: float, 
                      tile_size: Tuple[int, int]) -> str:
        """
            Generate cache key from image and parameters.
            Args:
        """
        # Use image hash + parameters as key
        image_hash = hashlib.md5(image.tobytes()).hexdigest()[:16]
        param_str = f"{clip_limit:.2f}_{tile_size[0]}x{tile_size[1]}"
        return f"{image_hash}_{param_str}"
    
    def get(self, image: np.ndarray, 
            clip_limit: float, 
            tile_size: Tuple[int, int]) -> Optional[np.ndarray]:
        """
            Get cached CLAHE result if available.
            Args:
        """
        with self.lock:
            key = self._generate_key(image, clip_limit, tile_size)
            
            if key in self.cache:
                # Cache hit - update access order
                self.hits += 1
                self.access_order.remove(key)
                self.access_order.append(key)
                return self.cache[key].copy()
            else:
                # Cache miss
                self.misses += 1
                return None
    
    def put(self, image: np.ndarray, 
            clip_limit: float, 
            tile_size: Tuple[int, int], 
            result: np.ndarray) -> None:
        """
            Store CLAHE result in cache.
            Args:
        """
        with self.lock:
            key = self._generate_key(image, clip_limit, tile_size)

            # FIX v3.30.9 BUG-1: Remove existing access_order entry BEFORE appending.
            # Without this guard, calling put() twice with the same key creates a
            # duplicate entry in access_order:
            #   access_order = [..., 'K', ..., 'K']   ← two slots for same key
            # During eviction, pop(0) removes the first 'K', then del cache['K']
            # succeeds and the cache entry is gone.  The second stale 'K' remains
            # in access_order; on the NEXT eviction, pop(0) returns 'K' again but
            # cache['K'] no longer exists → KeyError crash.
            # Removing first (O(n) but cache is bounded to max_size, typically 50)
            # ensures at most one slot per key at all times — consistent with LRU
            # semantics where a re-put promotes the key to most-recently-used.
            if key in self.cache:
                # Key already exists — remove its current access_order slot so the
                # append below places it as most-recently-used (promotes it).
                try:
                    self.access_order.remove(key)
                except ValueError:
                    pass  # Defensive: access_order and cache should be in sync

            # Update cache value and mark as most-recently-used
            self.cache[key] = result.copy()
            self.access_order.append(key)

            # Evict LRU entry if over size limit
            while len(self.cache) > self.max_size:
                lru_key = self.access_order.pop(0)
                # Guard: only delete if key still exists (defensive against any
                # future desync between cache dict and access_order list)
                if lru_key in self.cache:
                    del self.cache[lru_key]
    
    def get_stats(self) -> Dict[str, Any]:
        """Get cache statistics."""
        total = self.hits + self.misses
        hit_ratio = safe_divide(self.hits, total, 0.0) * 100
        
        return {
            'size': len(self.cache),
            'max_size': self.max_size,
            'hits': self.hits,
            'misses': self.misses,
            'hit_ratio': hit_ratio
        }
    
    def cleanup(self) -> None:
        """Clear cache and reset statistics (H-004)."""
        with self.lock:
            self.cache.clear()
            self.access_order.clear()
            self.hits = 0
            self.misses = 0
            logging.info("CLAHE cache cleaned up")
    
    def __del__(self):
        """Destructor ensures cleanup (H-004)."""
        self.cleanup()


# Global CLAHE cache instance
CLAHE_CACHE = CLAHECache()

