# ║  SECTION 09 — MODEL MANAGER                                                 ║
# ║  Singleton YOLO model loader with GPU/CPU auto-detection.                  ║
# ╚══════════════════════════════════════════════════════════════════════════╝

class ModelManager:

    """Singleton YOLO model manager for instance caching (C-005/ML-001)."""
    _instance = None
    _model = None
    _current_path = None
    # TODO-01 FIX v3.30.1.15: Use RLock so get_model() can be called
    # from within batch_predict() without deadlocking. threading.Lock is
    # NOT reentrant — a second acquire() from the same thread blocks forever.
    _lock = threading.RLock()
    
    # FIX-MODEL-001 v3.30.24: auto-detect best available device once at class level
    @classmethod
    def _resolve_device(cls) -> str:
        """Return 'cuda' if GPU is available, else 'cpu'. Cached in CFG."""
        if TORCH_AVAILABLE and torch.cuda.is_available():
            return "cuda"
        return "cpu"

    @classmethod
    def _warmup(cls) -> None:
        """Run one dummy inference to pre-allocate GPU/CPU buffers (FIX-MODEL-001)."""
        if cls._model is None:
            return
        try:
            dummy = np.zeros((64, 64, 3), dtype=np.uint8)
            cls._model(dummy, verbose=False)
            logging.info("[ModelManager] Warmup inference complete.")
        except Exception as _wu_err:
            logging.debug(f"[ModelManager] Warmup skipped: {_wu_err}")

    @classmethod
    def get_model(cls, model_path: str):
        """Get YOLO model instance (cached)."""
        with cls._lock:  # Thread-safe access
            model_path = str(model_path)  # Normalize Path to str
            
            # Return cached model if same path
            if cls._model is not None and cls._current_path == model_path:
                logging.debug(f"Using cached YOLO model: {Path(model_path).name}")
                return cls._model
            
            # FIX-MODEL-001: resolve device with GPU→CPU fallback before loading
            device = cls._resolve_device()
            logging.info(f"Loading YOLO model: {model_path}  device={device}")
            try:
                cls._model = YOLO(model_path)
                # Move to resolved device; YOLO accepts 'cuda'/'cpu' string
                cls._model.to(device)
                cls._current_path = model_path
                logging.info(f"✓ YOLO model cached: {Path(model_path).name} on {device}")
                cls._warmup()  # pre-allocate buffers; avoids first-inference latency spike
            except RuntimeError as _cuda_err:
                # GPU load failed — retry on CPU (FIX-MODEL-001: GPU→CPU safety net)
                if device == "cuda":
                    logging.warning(f"[ModelManager] GPU load failed ({_cuda_err}); retrying on CPU")
                    try:
                        cls._model = YOLO(model_path)
                        cls._model.to("cpu")
                        cls._current_path = model_path
                        logging.info("✓ YOLO model cached on CPU (GPU fallback)")
                        cls._warmup()
                    except Exception as _cpu_err:
                        logging.error(f"[ModelManager] CPU fallback also failed: {_cpu_err}")
                        cls._model = None
                        cls._current_path = None
                else:
                    logging.error(f"[ModelManager] Failed to load YOLO model '{model_path}': {_cuda_err}")
                    cls._model = None
                    cls._current_path = None
            except Exception as _load_err:
                logging.error(f"[ModelManager] Failed to load YOLO model '{model_path}': {_load_err}")
                cls._model = None
                cls._current_path = None
            return cls._model
    
    @classmethod
    def batch_predict(cls, model_path: str, images: list, conf: float = 0.4, 
                     iou: float = 0.45, max_det: int = 50) -> list:
        """
            Batch inference for GPU efficiency (B1: Batch Inference).
            Args:
        """
        model = cls.get_model(model_path)
        
        # Determine batch size based on device
        device = str(getattr(model, 'device', 'cpu'))
        
        if 'cuda' in device.lower():
            batch_size = BATCH_SIZE_GPU  # 16 for GPU
            logging.debug(f"Using GPU batch inference (batch_size={batch_size})")
        else:
            batch_size = BATCH_SIZE_CPU  # 4 for CPU
            logging.debug(f"Using CPU batch inference (batch_size={batch_size})")
        
        # Process in batches
        all_results = []
        num_images = len(images)
        
        for i in range(0, num_images, batch_size):
            batch = images[i:i+batch_size]
            
            # Run inference on batch
            batch_results = model(
                batch,
                conf=conf,
                iou=iou,
                max_det=max_det,
                verbose=False
            )
            
            all_results.extend(batch_results)
            
            logging.debug(f"Processed batch {i//batch_size + 1}/{(num_images + batch_size - 1)//batch_size}")
        
        return all_results
    
    @classmethod
    def clear_cache(cls):
        """Release cached model from memory."""
        with cls._lock:
            if cls._model is not None:
                logging.info("Releasing cached YOLO model")
                del cls._model
                cls._model = None
                cls._current_path = None
                gc.collect()
    
    @classmethod
    def __del__(cls):
        """Cleanup on shutdown."""
        cls.clear_cache()


