def detect_bad_pixels(thermal_array: np.ndarray, threshold: float = 3.0) -> np.ndarray:
    """Detect bad/dead pixels in thermal imagery (A2: Bad Pixel Detection)."""
    if thermal_array.ndim != 2:
        logging.warning(f"Bad pixel detection expects 2D array, got {thermal_array.ndim}D")
        return np.zeros_like(thermal_array, dtype=bool)
    
    # Use median filtering to detect outliers.
    # BUG-IMPORT-002 FIX (v3.30.24): scipy.ndimage.median_filter was imported
    # unconditionally inside the function body, raising ImportError when scipy
    # is absent. Now guarded by the module-level SCIPY_AVAILABLE flag with a
    # numpy-only fallback (uniform_filter approximation) so the pipeline
    # degrades gracefully instead of crashing.
    if SCIPY_AVAILABLE:
        from scipy.ndimage import median_filter
        median = median_filter(thermal_array, size=3)
    else:
        # Numpy-only approximation: use a 3×3 sliding window via stride tricks.
        # Less accurate than true median but sufficient for outlier detection.
        logging.debug("scipy unavailable — using numpy uniform_filter fallback for bad-pixel detection")
        from numpy.lib.stride_tricks import sliding_window_view
        try:
            windows = sliding_window_view(thermal_array, (3, 3))
            padded = np.pad(
                windows.reshape(windows.shape[0], windows.shape[1], -1).mean(axis=2),
                ((1, 1), (1, 1)), mode='edge'
            )
            median = padded
        except Exception:
            # Last-resort: no median filtering possible
            return np.zeros_like(thermal_array, dtype=bool)
    
    # Compute deviation from local median
    deviation = np.abs(thermal_array - median)
    
    # Compute global statistics
    median_dev = np.median(deviation[np.isfinite(deviation)])
    
    # Mark pixels as bad if deviation > threshold * median absolute deviation
    bad_mask = deviation > (threshold * median_dev * 1.4826)  # 1.4826 = robust scaling
    
    bad_count = np.sum(bad_mask)
    if bad_count > 0:
        logging.debug(f"Detected {bad_count} bad pixels ({bad_count/thermal_array.size*100:.2f}%)")
    
    return bad_mask


def interpolate_bad_pixels(thermal_array: np.ndarray, bad_mask: np.ndarray) -> np.ndarray:
    """Interpolate bad pixels using neighboring values (A2: Bad Pixel Interpolation)."""
    if not np.any(bad_mask):
        return thermal_array.copy()
    
    # BUG-IMPORT-002 FIX (v3.30.24): scipy.interpolate.griddata was imported
    # unconditionally inside the function body. Now guarded by SCIPY_AVAILABLE
    # with a simple nearest-neighbour fallback using numpy alone.
    result = thermal_array.copy()
    h, w = thermal_array.shape
    
    # Create coordinate grids
    y_coords, x_coords = np.mgrid[0:h, 0:w]
    
    # Good pixels for interpolation
    good_mask = ~bad_mask & np.isfinite(thermal_array)
    
    if np.sum(good_mask) < 4:
        logging.warning("Not enough good pixels for interpolation")
        return result
    
    if SCIPY_AVAILABLE:
        from scipy.interpolate import griddata
        # Points and values for interpolation
        points = np.column_stack((y_coords[good_mask], x_coords[good_mask]))
        values = thermal_array[good_mask]
        # Bad pixel coordinates
        bad_points = np.column_stack((y_coords[bad_mask], x_coords[bad_mask]))
        # Interpolate
        interpolated = griddata(points, values, bad_points, method='linear')
        # Fill in interpolated values
        result[bad_mask] = interpolated
    else:
        # Numpy-only nearest-neighbour fallback: replace each bad pixel with
        # the mean of its valid 3×3 neighbourhood. Simple but effective for
        # isolated bad pixels, which is the common case.
        logging.debug("scipy unavailable — using numpy neighbourhood fallback for bad-pixel interpolation")
        bad_ys, bad_xs = np.where(bad_mask)
        for by, bx in zip(bad_ys, bad_xs):
            y0, y1 = max(0, by - 1), min(h, by + 2)
            x0, x1 = max(0, bx - 1), min(w, bx + 2)
            neighbourhood = thermal_array[y0:y1, x0:x1]
            valid = neighbourhood[np.isfinite(neighbourhood) & ~bad_mask[y0:y1, x0:x1]]
            if valid.size > 0:
                result[by, bx] = valid.mean()
    
    logging.debug(f"Interpolated {np.sum(bad_mask)} bad pixels")
    
    return result


def advanced_glint_detection(thermal_array: np.ndarray, 
                             sensitivity: float = 2.5,
                             min_area: int = 5) -> np.ndarray:
    """
        Advanced multi-scale glint detection for metal surfaces (A1: Advanced Glint).
        Detects specular reflections on metal that cause false hot spots.
    """
    if thermal_array.ndim != 2:
        return np.zeros_like(thermal_array, dtype=bool)
    
    # Compute temperature gradient (glints have sharp edges)
    grad_y, grad_x = np.gradient(thermal_array)
    gradient_magnitude = np.sqrt(grad_y**2 + grad_x**2)
    
    # Threshold on gradient (glints have high gradients)
    grad_threshold = np.nanpercentile(gradient_magnitude, 95)
    high_gradient = gradient_magnitude > (grad_threshold / sensitivity)
    
    # Morphological operations to connect glint regions.
    # BUG-IMPORT-002 FIX (v3.30.24): scipy.ndimage.binary_dilation and label
    # were imported unconditionally inside the function. Now guarded by
    # SCIPY_AVAILABLE with a numpy-only fallback (manual dilation via
    # np.pad + np.maximum.reduce).
    if SCIPY_AVAILABLE:
        from scipy.ndimage import binary_dilation, label
        dilated = binary_dilation(high_gradient, iterations=2)
        labeled, num_features = label(dilated)
        # Filter by size (remove small noise)
        glint_mask = np.zeros_like(thermal_array, dtype=bool)
        for i in range(1, num_features + 1):
            region = labeled == i
            if np.sum(region) >= min_area:
                glint_mask |= region
    else:
        # Numpy-only fallback: manual 3×3 dilation (two passes) + simple
        # connected-component approximation via np.diff (column/row breaks).
        # Less accurate than scipy but avoids a hard dependency crash.
        logging.debug("scipy unavailable — using numpy dilation fallback for glint detection")
        dilated = high_gradient.copy()
        for _ in range(2):
            padded = np.pad(dilated, 1, mode='constant')
            dilated = (
                padded[:-2, :-2] | padded[:-2, 1:-1] | padded[:-2, 2:]  |
                padded[1:-1, :-2] | dilated           | padded[1:-1, 2:] |
                padded[2:,  :-2] | padded[2:,  1:-1] | padded[2:,  2:]
            )
        # Treat entire dilated mask as a single region for size filter
        glint_mask = dilated if np.sum(dilated) >= min_area else np.zeros_like(thermal_array, dtype=bool)
        num_features = 1 if np.any(glint_mask) else 0
    
    glint_count = num_features
    if glint_count > 0:
        logging.debug(f"Detected {glint_count} potential glint regions")
    
    return glint_mask


def thermal_noise_reduction(thermal_array: np.ndarray, 
                            strength: float = 1.0) -> np.ndarray:
    """
        Thermal-specific noise reduction (A3: Thermal Noise Reduction).
        Uses non-local means denoising optimized for thermal imagery.
    """
    if thermal_array.ndim != 2:
        return thermal_array
    
    # Normalize for processing
    valid_mask = np.isfinite(thermal_array)
    if not np.any(valid_mask):
        return thermal_array
    
    t_min, t_max = np.nanmin(thermal_array), np.nanmax(thermal_array)
    
    # Avoid division by zero
    if abs(t_max - t_min) < EPSILON:
        return thermal_array
    
    normalized = (thermal_array - t_min) / (t_max - t_min + EPSILON)
    
    # Convert to 8-bit for OpenCV processing
    img_8bit = (normalized * MAX_RGB_VALUE).astype(np.uint8)
    
    # Non-local means denoising (preserves edges better than bilateral)
    # h parameter controls strength (3-15 typical, we scale by strength)
    h_value = int(5 * strength)
    h_value = max(3, min(15, h_value))  # Clamp to valid range
    
    denoised_8bit = cv2.fastNlMeansDenoising(
        img_8bit,
        h=h_value,
        templateWindowSize=7,
        searchWindowSize=21
    )
    
    # Convert back to temperature scale
    denoised_normalized = denoised_8bit.astype(np.float32) / MAX_RGB_VALUE
    denoised = denoised_normalized * (t_max - t_min) + t_min
    
    # Restore NaN/inf values
    denoised[~valid_mask] = thermal_array[~valid_mask]
    
    logging.debug(f"Applied thermal noise reduction (strength={strength:.1f})")
    
    return denoised


def validate_temperature_range(thermal_array: np.ndarray,
                               expected_min: float = MIN_TEMPERATURE_C,
                               expected_max: float = MAX_TEMPERATURE_C) -> dict:
    """
        Validate temperature readings against expected ranges (A4: Validation).
        Checks if thermal data is within physically reasonable bounds
    """
    valid_mask = np.isfinite(thermal_array)
    valid_data = thermal_array[valid_mask]
    
    if len(valid_data) == 0:
        return {
            'valid': False,
            'min_temp': np.nan,
            'max_temp': np.nan,
            'mean_temp': np.nan,
            'out_of_range_percent': 100.0,
            'warnings': ['No valid temperature data']
        }
    
    t_min = np.min(valid_data)
    t_max = np.max(valid_data)
    t_mean = np.mean(valid_data)
    
    warnings = []
    
    # Check range
    out_of_range = (valid_data < expected_min) | (valid_data > expected_max)
    out_of_range_pct = np.sum(out_of_range) / len(valid_data) * 100
    
    if t_min < expected_min:
        warnings.append(f"Minimum temperature ({t_min:.1f}°C) below expected ({expected_min:.1f}°C)")
    
    if t_max > expected_max:
        warnings.append(f"Maximum temperature ({t_max:.1f}°C) above expected ({expected_max:.1f}°C)")
    
    if out_of_range_pct > 10:
        warnings.append(f"{out_of_range_pct:.1f}% of pixels outside expected range")
    
    # Check for suspicious values
    if abs(t_max - t_min) < 1.0:
        warnings.append(f"Very low temperature range ({t_max - t_min:.2f}°C) - possible bad calibration")
    
    valid = len(warnings) == 0
    
    if not valid:
        logging.warning(f"Temperature validation failed: {warnings}")
    
    return {
        'valid': valid,
        'min_temp': float(t_min),
        'max_temp': float(t_max),
        'mean_temp': float(t_mean),
        'out_of_range_percent': float(out_of_range_pct),
        'warnings': warnings
    }


