# ML PIPELINE OPTIMIZATIONS (Phase B - Natalie's Enhancements)
# ============================================================================

def calibrate_confidence_threshold(image_quality_score: float,
                                  base_threshold: float = YOLO_CONFIDENCE_DEFAULT,
                                  min_threshold: float = 0.3,
                                  max_threshold: float = 0.6) -> float:
    """
        Adaptive confidence threshold based on image quality (B3: Confidence Calibration).
        Adjusts detection confidence threshold based on thermal image quality.
    """
    # Clamp quality score to [0, 1]
    quality = np.clip(image_quality_score, 0.0, 1.0)
    
    # Inverse relationship: better quality → lower threshold
    # Linear interpolation between min and max
    adjusted_threshold = max_threshold - (quality * (max_threshold - min_threshold))
    
    # Clamp to valid range
    calibrated = np.clip(adjusted_threshold, min_threshold, max_threshold)
    
    logging.debug(f"Calibrated confidence: {base_threshold:.2f} → {calibrated:.2f} (quality={quality:.2f})")
    
    return float(calibrated)


def assess_thermal_quality(thermal_array: np.ndarray) -> float:
    """Assess thermal image quality (B3: Quality Assessment)."""
    valid_mask = np.isfinite(thermal_array)
    valid_data = thermal_array[valid_mask]
    
    if len(valid_data) < 100:
        return 0.0  # Not enough data
    
    # Factor 1: Valid pixel ratio (should be close to 1.0)
    valid_ratio = np.sum(valid_mask) / thermal_array.size
    
    # Factor 2: Temperature variance (contrast indicator)
    variance = np.var(valid_data)
    # Normalize variance (thermal images typically 0-500 variance)
    variance_score = min(variance / 500.0, 1.0)
    
    # Factor 3: Noise level (estimate from high-frequency components)
    # Lower noise = higher quality
    if thermal_array.shape[0] > 10 and thermal_array.shape[1] > 10:
        # Compute gradient as noise proxy
        grad_y, grad_x = np.gradient(thermal_array)
        grad_magnitude = np.sqrt(grad_y**2 + grad_x**2)
        noise_estimate = np.nanmean(grad_magnitude)
        # Inverse: high noise = low score
        noise_score = max(1.0 - (noise_estimate / 10.0), 0.0)
    else:
        noise_score = 0.5  # Unknown
    
    # Weighted combination
    quality_score = (
        0.3 * valid_ratio +
        0.4 * variance_score +
        0.3 * noise_score
    )
    
    return float(np.clip(quality_score, 0.0, 1.0))


# ============================================================================
# FILE LOCKING UTILITIES (A-001: Atomic & Safe File Operations)
# ============================================================================

def safe_write_json(filepath: Path, data: dict) -> None:
    """Thin public wrapper around atomic_write_json for all JSON writes in the pipeline."""
    # Delegate entirely to atomic_write_json which provides:
    #   - temp-file write → atomic rename (crash-safe)
    #   - FileLock when filelock library is available (concurrent-safe)
    #   - temp-file cleanup in finally block
    atomic_write_json(filepath, data)


def safe_read_json(filepath: Path, default: dict = None) -> dict:
    """Read and parse a JSON file with full error handling."""
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            return json.load(f)
    except FileNotFoundError:
        logging.debug(f"JSON file not found: {filepath}")
        return default if default is not None else {}
    except json.JSONDecodeError as e:
        logging.error(f"Corrupt JSON file {filepath}: {e}")
        return default if default is not None else {}
    except Exception as e:
        logging.error(f"Failed to read JSON {filepath}: {e}")
        return default if default is not None else {}


