class CancelFlag:
    """TODO-031: Thread-safe cancellation token for long-running batch operations."""
    def __init__(self):
        self._event = threading.Event()

    def set(self):
        """Signal cancellation (called from UI thread via self.after())."""
        self._event.set()

    def clear(self):
        """Reset for a fresh batch run (called before starting a new batch)."""
        self._event.clear()

    def is_set(self) -> bool:
        """Return True if cancellation has been requested."""
        return self._event.is_set()


class BatchProgress:
    """TODO-031: ETA calculation and throughput tracking for batch operations."""
    _PHASES = ("Loading", "Inference", "Post-processing", "Finished")

    def __init__(self, total: int):
        self.total = total          # Total image count for this batch run
        self.done = 0               # Images fully processed so far
        self.phase = "Loading"      # Current pipeline phase
        self._t0 = time.monotonic() # Wall-clock start time for ETA
        self._phase_t0 = self._t0   # Per-phase start for phase timing log

    def tick(self, n: int = 1):
        """Increment completed image counter."""
        self.done += n

    def set_phase(self, phase: str):
        """Transition to a new pipeline phase."""
        elapsed = time.monotonic() - self._phase_t0
        logging.info(f"[BatchProgress] Phase '{self.phase}' took {elapsed:.1f}s")
        self.phase = phase
        self._phase_t0 = time.monotonic()

    @property
    def elapsed(self) -> float:
        return time.monotonic() - self._t0

    @property
    def throughput(self) -> float:
        """Images per second (0 until at least 1 image processed)."""
        return self.done / self.elapsed if self.elapsed > 0.5 and self.done > 0 else 0.0

    @property
    def eta_seconds(self) -> float:
        """Estimated seconds remaining (-1 if not enough data yet)."""
        if self.throughput <= 0 or self.done >= self.total:
            return -1.0
        remaining = self.total - self.done
        return remaining / self.throughput

    def label(self) -> str:
        """Human-readable status for the progress label widget."""
        pct = int(100 * self.done / self.total) if self.total > 0 else 0
        tp = self.throughput
        eta = self.eta_seconds
        tp_str = f"{tp:.1f} img/s" if tp > 0 else "—"
        if eta > 0:
            if eta >= 3600:
                eta_str = f"ETA {int(eta/3600)}h {int((eta%3600)/60)}m"
            elif eta >= 60:
                eta_str = f"ETA {int(eta/60)}m {int(eta%60)}s"
            else:
                eta_str = f"ETA {int(eta)}s"
        else:
            eta_str = "ETA —"
        return (f"[{self.phase}]  {self.done}/{self.total} ({pct}%)  "
                f"{tp_str}  {eta_str}")


class CSVWriteQueue:
    """
        TODO-001: Thread-safe CSV row accumulator for parallel post-processing.
        Usage:
        queue = CSVWriteQueue()
    """
    def __init__(self):
        self._q: queue.Queue = queue.Queue()

    def put(self, row: list):
        """Enqueue a CSV row (called from any thread)."""
        self._q.put(row)

    def drain_to(self, csv_writer) -> int:
        """Write all queued rows to csv_writer and return count written (main thread)."""
        count = 0
        while not self._q.empty():
            try:
                csv_writer.writerow(self._q.get_nowait())
                count += 1
            except queue.Empty:
                break
        return count


class _ThreadSafeCsvWriter:
    """as csv.writer but routes every row into a CSVWriteQueue instead."""
    def __init__(self, csv_queue: "CSVWriteQueue"):
        # Store reference to the shared queue; all threads share one instance.
        self._q = csv_queue

    def writerow(self, row: list) -> None:
        """Enqueue a row from any worker thread (thread-safe via queue.Queue)."""
        self._q.put(row)


