class MetadataCache:
    """ENHANCEMENT: Cache metadata to avoid re-processing same files."""
    def __init__(self, project_folder):
        self.project_folder = Path(project_folder)
        self.cache_file = self.project_folder / ".metadata_cache.json"
        self.cache = self._load_cache()
        self.hits = 0
        self.misses = 0
    
    def _load_cache(self):
        """Load cache from file."""
        if self.cache_file.exists():
            try:
                with open(self.cache_file, 'r', encoding='utf-8') as f:
                    return json.load(f)
            except Exception as e:
                logging.warning(f"Failed to load metadata cache: {e}")
        return {}
    
    def _save_cache(self):
        """Save cache to file — BUG-RT-04 FIX v3.30.17: atomic write (temp→rename)."""
        try:
            atomic_write_json(self.cache_file, self.cache, use_lock=False)
        except Exception as e:
            logging.error(f"Failed to save metadata cache: {e}")
    
    def get(self, file_path):
        """Get cached metadata if valid (checks file modification time)."""
        file_path = Path(file_path)
        filename = file_path.name
        
        if filename not in self.cache:
            self.misses += 1
            return None
        
        cached_entry = self.cache[filename]
        
        try:
            st = file_path.stat()
            # TODO-08 FIX v3.30.1.15: Use both mtime AND file-size as the
            # validity fingerprint.  mtime alone can miss a same-size replacement
            # written within the same filesystem timestamp resolution (1s on FAT32).
            cached_mtime = cached_entry.get("file_modified")
            cached_size  = cached_entry.get("file_size_bytes")
            if cached_mtime != st.st_mtime or cached_size != st.st_size:
                self.misses += 1
                return None

            self.hits += 1
            return cached_entry.get("metadata")
        except Exception as e:
            logging.debug(f"Cache stat error for {file_path.name}: {e}")
            self.misses += 1
            return None
    
    def set(self, file_path, metadata):
        """Cache metadata for a file with timestamp."""
        file_path = Path(file_path)
        filename = file_path.name
        
        try:
            st = file_path.stat()
            # TODO-08 FIX v3.30.1.15: Store size alongside mtime for double fingerprint.
            self.cache[filename] = {
                "metadata": metadata,
                "file_modified": st.st_mtime,
                "file_size_bytes": st.st_size,
                "cached_at": datetime.now().isoformat()
            }
            self._save_cache()
        except Exception as e:
            logging.error(f"Failed to cache metadata for {filename}: {e}")
    
    def get_stats(self):
        """Return cache statistics."""
        total = self.hits + self.misses
        hit_rate = (self.hits / total * 100) if total > 0 else 0
        return {
            'hits': self.hits,
            'misses': self.misses,
            'hit_rate': hit_rate,
            'cached_files': len(self.cache)
        }
    
    def clear(self):
        """Clear all cached metadata."""
        self.cache = {}
        if self.cache_file.exists():
            self.cache_file.unlink()
        logging.info("✓ Metadata cache cleared")
    
    def cleanup(self) -> None:
        """Cleanup method for cache (H-004)."""
        self.clear()
        self.hits = 0
        self.misses = 0
    
    def __del__(self):
        """Destructor ensures cleanup (H-004)."""
        # No action needed - cache persists across sessions


