# CRITICAL FIX #3: Detection Result Caching (v3.26)
# ================================================================================================
class DetectionCache:
    """Cache YOLO detection results to avoid redundant inference."""
    
    def __init__(self, cache_dir=None):
        """Initialize detection cache."""
        if cache_dir is None:
            cache_dir = Path.home() / ".flir_thermal_app" / "detection_cache"
        
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.cache_file = self.cache_dir / "detection_cache.json"
        
        # Load existing cache
        self.cache = {}
        if self.cache_file.exists():
            try:
                with open(self.cache_file, 'r', encoding='utf-8') as f:
                    self.cache = json.load(f)
                logging.info(f"Loaded detection cache: {len(self.cache)} entries")
            except Exception as e:
                logging.warning(f"Failed to load detection cache: {e}")
                self.cache = {}
        
        # Statistics
        self.hits = 0
        self.misses = 0
    
    def _get_cache_key(self, image_path):
        """Generate cache key from image path and modification time."""
        path = Path(image_path)
        if not path.exists():
            return None
        
        mtime = path.stat().st_mtime
        return f"{path.name}_{mtime}"
    
    def get(self, image_path):
        """Get cached detection results."""
        key = self._get_cache_key(image_path)
        if key is None:
            return None
        
        if key in self.cache:
            self.hits += 1
            logging.debug(f"Detection cache HIT: {Path(image_path).name}")
            return self.cache[key]
        
        self.misses += 1
        logging.debug(f"Detection cache MISS: {Path(image_path).name}")
        return None
    
    def set(self, image_path, detection_results):
        """Cache detection results."""
        key = self._get_cache_key(image_path)
        if key is None:
            return
        
        # Store detection results
        self.cache[key] = {
            'boxes': detection_results.get('boxes', []),
            'confidences': detection_results.get('confidences', []),
            'classes': detection_results.get('classes', []),
            'timestamp': time.time()
        }
        
        # Persist to disk — BUG-RT-03 FIX v3.30.17: use atomic_write_json
        # Previous bare open()+json.dump() produced a zero-byte cache file on crash.
        try:
            atomic_write_json(self.cache_file, self.cache, use_lock=False)
            logging.debug(f"Cached detection results: {Path(image_path).name}")
        except Exception as e:
            logging.warning(f"Failed to persist detection cache: {e}")
    
    def invalidate(self, image_path):
        """Invalidate cache entry for specific image."""
        key = self._get_cache_key(image_path)
        if key and key in self.cache:
            del self.cache[key]
            logging.debug(f"Invalidated cache: {Path(image_path).name}")
    
    def clear(self):
        """Clear all cached detection results."""
        self.cache = {}
        if self.cache_file.exists():
            self.cache_file.unlink()
        logging.info("✓ Detection cache cleared")
    
    def cleanup(self) -> None:
        """Cleanup method for cache (H-004)."""
        self.clear()
        self.hits = 0
        self.misses = 0
    
    def __del__(self):
        """Destructor ensures cleanup (H-004)."""
        # No action needed - cache persists across sessions
    
    def get_stats(self):
        """Return cache statistics."""
        total = self.hits + self.misses
        hit_rate = (self.hits / total * 100) if total > 0 else 0
        return {
            'hits': self.hits,
            'misses': self.misses,
            'hit_rate': hit_rate,
            'cached_detections': len(self.cache)
        }



# ╔══════════════════════════════════════════════════════════════════════════╗
# ║  SECTION 12 — THERMAL PHYSICS — ThermalPhysics                              ║
# ║  Planck radiometry, Planck constants, emissivity, ASTM E1934 grading.      ║
# ╚══════════════════════════════════════════════════════════════════════════╝

class ThermalPhysics:
    @staticmethod
    def raw2temp_celsius(raw: np.ndarray, meta: Dict[str, Any]) -> np.ndarray:
        """Convert raw 14/16-bit FLIR sensor DN counts to °C via single-path Planck radiometry.

        Radiometric model:
            S_meas = raw + PO
            S_obj  = (S_meas - (1-E)·τ·IRT·S_refl - (1-τ)·IRT·S_atm - (1-IRT)·S_win)
                     / (E · τ · IRT)
            T_obj  = PB / ln(PR1 / (PR2·S_obj) + PF) − 273.15

        Bug history (retained to prevent regression):
            BUG-RH-01 FIXED: RelativeHumidity (EXIF %) divided by 100 → fraction before h2o polynomial.
            FIX-THERMO-01b: PO applied to S_meas only; reference temps use pure Planck radiance.
            BUG-LG-01: DN≥65535 masked to NaN before inversion.
            FIX-DRIFT-01: Drift comp default=False (matches Thermal Studio).
            BUG-SQRT-01 NOTE: Single-path model uses sqrt(OD); flyr two-tau uses sqrt(OD/2) — both correct for their respective models.

        Raises:
            ValueError: raw is empty, 8-bit, or >90% pixels invalid.
            RuntimeError: Planck inversion failure (bad metadata).
        """
        try:
            if raw.size == 0:
                raise ValueError("Empty raw array")

            raw_min, raw_max = raw.min(), raw.max()
            logging.info(f"Raw min/max: {raw_min:.0f} / {raw_max:.0f}")
            
            # Validate we have radiometric data
            if raw_max < 300:
                raise ValueError(f"8-bit data detected ({raw_max:.0f}). Need 14-16 bit TIFF!")

            # ── BUG-LG-01 FIX v3.30.17: Mask saturated pixels BEFORE Planck inversion ──
            # DN = 65535 means the sensor is clipped (16-bit saturation).  Passing these
            # values through the full Planck chain produces physically unreasonable
            # temperatures (often > 2000 °C) that corrupt mean/max extraction in
            # calculate_adaptive_temps() and skew Planck validation error scores.
            # Mask them to NaN now; they propagate as NaN through all downstream maths
            # and are correctly excluded by the existing np.isnan() / mask guards.
            sat_count = int(np.sum(raw >= 65535))
            if sat_count > 0:
                raw = raw.astype(np.float32)           # ensure mutable float copy
                raw[raw >= 65535] = np.nan
                logging.warning(
                    f"BUG-LG-01: Masked {sat_count} saturated pixels (DN≥65535) "
                    f"({sat_count / raw.size * 100:.1f}% of array) — set to NaN before Planck."
                )

            # ── P1: Atmospheric Parameter Override (v3.30.15) ────────────────
            # When ATMOSPHERE.UseOverride == "True" (set via Settings UI), the
            # CFG-configured values take precedence over EXIF metadata for every
            # environmental parameter.  This lets operators standardise conditions
            # across a site survey without depending on correct in-camera settings.
            _use_atm_override = CFG.get("ATMOSPHERE", "UseOverride", "False") == "True"

            if _use_atm_override:
                E    = float(CFG.get("ATMOSPHERE", "Emissivity",                  str(DEFAULT_EMISSIVITY)))
                OD   = max(float(CFG.get("ATMOSPHERE", "ObjectDistance",          "1.0")), 0.1)
                RT   = float(CFG.get("ATMOSPHERE", "ReflectedApparentTemperature", "20.0"))
                AT   = float(CFG.get("ATMOSPHERE", "AtmosphericTemperature",      "20.0"))
                IRWT = float(CFG.get("ATMOSPHERE", "IRWindowTemperature",         "20.0"))
                IRT  = float(CFG.get("ATMOSPHERE", "IRWindowTransmission",        "1.0"))
                _rh_override = float(CFG.get("ATMOSPHERE", "RelativeHumidity",   "50.0"))
                logging.debug(
                    f"ATMOSPHERE override: E={E}, OD={OD}, RT={RT}, AT={AT}, "
                    f"IRWT={IRWT}, IRT={IRT}, RH={_rh_override}% (stored as %, divided by 100 below)"
                )
            else:
                # Environmental parameters - using safe_get_meta for key variations
                E    = float(safe_get_meta(meta, 'Emissivity', DEFAULT_EMISSIVITY))
                # USER REQUEST v3.30.15: Default OD changed from 1.0 → 5.0 m.
                # When ObjectDistance cannot be extracted from EXIF (absent tag, corrupt
                # metadata, or flat-JPEG without MakerNotes), a 5 m standoff distance is
                # far more representative of real-world substation / electrical inspection
                # surveys than 1 m.  Using 1 m under-corrects atmospheric attenuation and
                # produces systematically higher reported temperatures.
                # The max(..., 0.1) guard is retained to prevent division-by-zero in
                # sqrt(OD / 2) inside the atmospheric transmission formula.
                OD   = max(float(safe_get_meta(meta, 'ObjectDistance', 5.0)), 0.1)
                RT   = float(safe_get_meta(meta, 'ReflectedApparentTemperature', 20.0))
                AT   = float(safe_get_meta(meta, 'AtmosphericTemperature', 20.0))
                IRWT = float(safe_get_meta(meta, 'IRWindowTemperature', 20.0))
                IRT  = float(safe_get_meta(meta, 'IRWindowTransmission', 1.0))
                _rh_override = None  # use EXIF value below

            # ================================================================
            # v3.30.0 CAMERA-AWARE PLANCK CONSTANT EXTRACTION (C-004)
            # ================================================================
            # ENHANCEMENT: Auto-detect camera model and use appropriate constants
            # Supports: FLIR E75, E95, T540, T640
            # Fallback: E75 defaults if camera unknown
            # ================================================================
            
            # Try to extract Planck constants from EXIF first
            pr1_from_exif = safe_get_meta(meta, 'PlanckR1', None)
            
            if pr1_from_exif is not None:
                # EXIF has Planck constants - use them directly
                PR1 = float(pr1_from_exif)
                PB = float(safe_get_meta(meta, 'PlanckB', 1402.5))
                PF = float(safe_get_meta(meta, 'PlanckF', 1.0))
                PO = float(safe_get_meta(meta, 'PlanckO', -4657))
                PR2 = float(safe_get_meta(meta, 'PlanckR2', 0.011269039))
                logging.info(f"✓ Planck constants from EXIF: R1={PR1:.2f}, R2={PR2:.6f}, B={PB:.1f}")
            else:
                # No EXIF Planck constants - use camera model detection
                camera_model = safe_get_meta(meta, 'CameraModel', DEFAULT_CAMERA_MODEL)
                constants = get_camera_planck_constants(camera_model)
                
                PR1 = constants['PR1']
                PR2 = constants['PR2']
                PB = constants['PB']
                PF = constants['PF']
                PO = constants['PO']
                
                # TODO-03 FIX v3.30.1.15: Field engineers monitor WARNING level.
                # INFO is invisible in production log viewers. EXIF Planck is absent
                # so hardcoded camera constants are being used — this is a data-quality
                # concern that must be surfaced to operators.
                logging.warning(
                    f"⚠ PLANCK FALLBACK: EXIF Planck constants absent for {camera_model}. "
                    f"Using hardcoded defaults: R1={PR1:.2f}, R2={PR2:.6f}, B={PB:.1f}. "
                    f"Verify camera metadata or recalibrate if temperatures seem incorrect."
                )
            
            # Validate we have valid constants
            if any(v == 0 or v is None for v in [PR1, PB, PR2]):
                raise ValueError(f"Invalid Planck constants: R1={PR1}, R2={PR2}, B={PB}")
            
            # ================================================================

            # Drift compensation
            drift = 0.0
            # FIX-DRIFT-01: default changed True → False.  FLIR Thermal Studio does not
            # apply any camera-body drift correction.  With the old default of True, any
            # installation without an explicit DriftComp=False in config would silently
            # subtract (CameraTemp − 20) × 0.05 °C — up to 1 °C error at 40 °C body temp.
            # Opt-in only: users who need drift compensation must set DriftComp=True explicitly.
            if CFG.get("DETECTION", "DriftComp", "False") == "True":
                cam_temp = float(safe_get_meta(meta, 'CameraTemperature', 20.0))
                drift = (cam_temp - 20.0) * 0.05

            # Atmospheric transmission model
            # ATX = 1.9 is an empirical FLIR SDK split coefficient for two molecular
            # absorption bands (H2O primary and secondary bands).  With ATX > 1.0 the
            # raw formula CAN produce tau > 1.0 (more energy exits than enters) for
            # short OD at low humidity — physically impossible.
            # BUG-ATX FIX v3.30.17: clamp tau1/tau2 to [0.01, 1.0] after computation
            # to guarantee a physically valid atmospheric transmission coefficient.
            # ── FIX-ATM-01: Correct FLIR Thermal Studio atmospheric transmission ──
            # Reference: FLIR Atlas SDK ThermoVision library (radiometricCalculator.cpp)
            #            FLIR Systems Radiometry Tutorial Rev.3, Appendix A
            #            Validated against IR_82598/82600/82602/82604 — all 8 FLIR
            #            Thermal Studio reference points (4 spots + 4 box-maxima)
            #            reproduced to 0.00 °C error with correct formula.
            #
            # ── WHY h2o changed (Magnus proxy → FLIR SDK polynomial) ────────────
            # OLD (wrong):  h2o = 0.073 * RH * exp(17.62*AT / (243.12+AT))
            #               This is a Magnus-equation vapour-pressure proxy.  At
            #               21 °C / 73 % RH it gives ~0.2163 — far below the SDK
            #               value of ~13.26, so tau_atm was too HIGH (~0.9514 vs
            #               the correct ~0.9949), causing a systematic −0.5 °C
            #               under-read on every image.
            # NEW (correct): h2o = exp(1.5587 + 0.06939·AT − 2.7816e-4·AT²
            #                             + 6.8455e-7·AT³) × RH
            #               This is the exact degree-3 polynomial used by the FLIR
            #               Atlas SDK to estimate absolute water-vapour content
            #               (g/m³-equivalent dimensionless units) — verified by
            #               matching all reference temperatures to 0.00 °C.
            #
            # ── WHY X / alpha changed (hardcoded → EXIF with fallback) ──────────
            # The FLIR SDK splits atmospheric absorption into two molecular bands:
            #   tau = X·exp(−√OD·h2o·√α₁) + (1−X)·exp(−√OD·h2o·√α₂)
            # X, α₁, α₂ are written into the image EXIF by the camera firmware as
            # AtmosphericTransX, AtmosphericTransAlpha1, AtmosphericTransAlpha2.
            # The old code ignored these tags and used hardcoded constants that match
            # the FLIR E-series defaults but are wrong for cameras with different
            # firmware calibrations.
            # Fallback values (FLIR E-series defaults, kept for cameras without the
            # EXIF tags):
            #   X = 0.006569
            #   α₁ = 0.01262²  → sqrt(α₁) = 0.01262
            #   α₂ = 0.06627²  → sqrt(α₂) = 0.06627
            # BUG-RH-01 FIX: ExifTool stores RelativeHumidity as percentage (0-100).
            # The FLIR SDK h2o polynomial requires a fraction (0-1).  Dividing by
            # 100 here; _rh_override also stored as % in CFG so same divide applies.
            # Pre-fix: rh=50 => h2o=848 => tau clamped to 0.01 => >10 C error.
            _rh_raw = (_rh_override
                       if _rh_override is not None
                       else float(safe_get_meta(meta, 'RelativeHumidity', 50.0)))
            rh = _rh_raw / 100.0   # convert % → fraction for SDK polynomial

            # ── EXIF-sourced two-band split coefficient (fallback: FLIR E-series default) ──
            # AtmosphericTransX: fractional weight of primary H2O absorption band.
            # Typical FLIR E/T-series value: 0.006569 (verified on IR_82598).
            _ATM_X = float(safe_get_meta(meta, 'AtmosphericTransX', 0.006569))

            # ── EXIF-sourced absorption band coefficients ────────────────────────
            # FIX-TAU-01 (v3.30.24.7): Alpha stored as α (raw value), Beta stored as β.
            # OLD (wrong): used sqrt(α) as the per-band exponent coefficient and
            #   multiplied by h2o — did NOT use beta at all.  Formula:
            #     exp(-sqrt(OD) * h2o * sqrt(α))
            #   This gave tau≈0.242 vs the correct 0.748 for OD=3m/RH=73%, a 68%
            #   underestimate of atmospheric transmission, causing temperature errors
            #   of ±10–30 °C depending on scene conditions.
            # NEW (correct): FLIR SDK two-band model matching flyr __raw_to_kelvin:
            #     tau_i = exp(-sqrt(OD/2) * (α_i + β_i * sqrt(water)))
            #     tau   = X*tau1 + (1-X)*tau2
            #   Fallback β values reproduce FLIR E-series defaults exactly.
            _alpha1 = float(safe_get_meta(meta, 'AtmosphericTransAlpha1', 0.01262 ** 2))
            _alpha2 = float(safe_get_meta(meta, 'AtmosphericTransAlpha2', 0.06627 ** 2))
            _beta1  = float(safe_get_meta(meta, 'AtmosphericTransBeta1',  0.01262))
            _beta2  = float(safe_get_meta(meta, 'AtmosphericTransBeta2',  0.06627))

            # ── FLIR SDK 3rd-order polynomial for water-vapour content ───────────
            # Coefficients match FLIR Atlas SDK radiometricCalculator.cpp exactly.
            # rh is now fraction (0-1) as required by the polynomial.
            _h2o = (exp(1.5587
                        + 0.06939    * AT
                        - 2.7816e-4  * AT ** 2
                        + 6.8455e-7  * AT ** 3)
                    * rh)

            # ── Beer-Lambert path length — FIX-TAU-01 ────────────────────────────
            # FLIR SDK two-band model uses sqrt(OD/2) matching flyr and Thermal Studio.
            # OLD single-path used sqrt(OD) — corrected here.
            _sqrt_od_half = sqrt(OD / 2.0)

            # ── Two-band atmospheric transmission — FIX-TAU-01 ───────────────────
            # Formula: tau_i = exp(-sqrt(OD/2) * (alpha_i + beta_i * sqrt(water)))
            # Matches flyr FlyrThermogram.__raw_to_kelvin calc_atmos() exactly.
            _sqrt_water = sqrt(max(_h2o, 0.0))
            _tau_raw = (
                _ATM_X       * exp(-_sqrt_od_half * (_alpha1 + _beta1 * _sqrt_water))
              + (1 - _ATM_X) * exp(-_sqrt_od_half * (_alpha2 + _beta2 * _sqrt_water))
            )

            # Clamp to physically valid range [0.01, 1.0]
            tau_atm = max(0.01, min(1.0, _tau_raw))
            logging.debug(
                f"tau_atm={tau_atm:.6f} (h2o={_h2o:.6f}, sqrt_od_half={_sqrt_od_half:.4f}, "
                f"OD={OD:.1f}m, RH={rh:.3f}, AT={AT:.1f}°C, "
                f"X={_ATM_X:.6f}, a1={_alpha1:.6f}, b1={_beta1:.5f}, "
                f"a2={_alpha2:.6f}, b2={_beta2:.5f}) [FIX-TAU-01]"
            )

            # ── FIX-THERMO-01b: Pure Planck radiance for reference temperatures ──
            # WHY no PO subtraction: PO (PlanckO) is the ADC baseline offset between
            # the camera's analogue readout and physical radiance units.  It applies
            # only to the MEASURED raw signal (raw + PO = radiance).  Reference
            # background temperatures (T_refl, T_atm, T_win) are purely physical
            # temperatures — their Planck radiances are computed with no ADC offset.
            # The old _planck_rad subtracted PO from every reference temperature,
            # inflating each S_refl/S_atm/S_win by |PO| = 4657 ADU.  This introduced
            # a systematic error that partially cancelled BUG-1/2 at short distances
            # but diverged at D≥20m or RH≥70%.
            def _planck_S(t_celsius: float) -> float:
                """Pure physical Planck radiance for a scalar temperature T_C (°C)."""
                return PR1 / (PR2 * (exp(PB / (t_celsius + CELSIUS_TO_KELVIN)) - PF))

            S_refl = _planck_S(RT)    # reflected apparent temperature
            S_atm  = _planck_S(AT)    # atmospheric (path) temperature
            S_win  = _planck_S(IRWT)  # IR window temperature

            # ── FIX-THERMO-01c: Correct FLIR physical signal model ────────────────
            # Full FLIR radiometric model (single atmospheric path, single tau):
            #
            #   S_meas = E*tau_atm*IRT*S_obj
            #          + (1-E)*tau_atm*IRT*S_refl      ← reflected environment
            #          + (1-tau_atm)*IRT*S_atm          ← atmospheric self-emission
            #          + (1-IRT)*S_win                  ← IR window self-emission
            #
            # Solving for S_obj (the object's true radiance):
            #   S_obj = [S_meas - (1-E)*tau_atm*IRT*S_refl
            #                   - (1-tau_atm)*IRT*S_atm
            #                   - (1-IRT)*S_win]
            #           / (E * tau_atm * IRT)
            #
            # Where S_meas = raw + PO  (ADC count → radiance via Planck offset).
            #
            # WHY tau² was wrong: the old formula used denom = E*tau1*IRT*tau2 with
            # tau1==tau2, giving tau²*IRT instead of tau*IRT. This under-estimated
            # the environmental correction factor by tau≈0.98x, producing a small
            # but systematic warm bias.  Additionally, the (1-tau1) and (1-tau2)
            # terms were summed separately with rad_AT, double-counting atmospheric
            # self-emission.
            denominator = E * tau_atm * IRT
            if abs(denominator) < EPSILON:
                raise ValueError(
                    f"Invalid atmospheric parameters: E={E}, tau_atm={tau_atm:.4f}, "
                    f"IRT={IRT:.4f} → denominator={denominator:.2e} (near zero)"
                )

            # Total measured signal in radiance units (raw ADC count + Planck offset)
            S_meas = raw + PO   # vectorised numpy: shape matches raw

            # Solve for object radiance (fully vectorised, no loops)
            S_obj = (
                S_meas
                - (1.0 - E)        * tau_atm * IRT * S_refl
                - (1.0 - tau_atm)  * IRT            * S_atm
                - (1.0 - IRT)                        * S_win
            ) / denominator

            # ── Planck inversion: S_obj → T_obj ─────────────────────────────────
            # Directly from S_obj (radiance) — no PO needed here because PO was
            # already accounted for in S_meas = raw + PO above.
            log_arg = PR1 / (PR2 * S_obj) + PF

            # Validity mask: guard against negative radiance and log domain errors
            mask = (
                (S_obj > 0) &
                (log_arg > 1.0) &
                np.isfinite(S_obj) &
                np.isfinite(log_arg)
            )

            result = np.full_like(raw, np.nan, dtype=np.float32)

            if np.any(mask):
                # Clamp just above 1.0 to protect against floating-point edge at log(1)=0
                safe_log_arg = np.maximum(log_arg[mask], 1.0 + 1e-10)
                result[mask] = PB / np.log(safe_log_arg) - CELSIUS_TO_KELVIN

            # Validate result quality
            valid_ratio = np.sum(mask) / mask.size
            if valid_ratio < 0.1:
                raise ValueError(f"Only {valid_ratio*100:.1f}% valid pixels — likely metadata mismatch")

            return result - drift

        except Exception as e:
            logging.error(f"Planck conversion FAILED: {e}")
            raise RuntimeError(f"Radiometric conversion failed: {e}. Check metadata and thermal data quality.")

    @staticmethod
    def raw2temp(raw, meta, unit='C'):
        """Convert raw 14/16-bit sensor counts to the requested temperature unit."""
        temp_c = ThermalPhysics.raw2temp_celsius(raw, meta)
        if unit == 'F':
            return temp_c * FAHRENHEIT_SCALE + FAHRENHEIT_OFFSET
        elif unit == 'K':
            return temp_c + CELSIUS_TO_KELVIN
        else:
            if unit not in ('C', ''):
                logging.warning(
                    f"raw2temp: unknown unit '{unit}' — defaulting to Celsius. "
                    f"Valid: 'C', 'F', 'K'."
                )
            return temp_c

    @staticmethod
    def detect_glint(raw_data, rect_coords, meta):
        """OPTIMIZED: Vectorized glint detection using pure NumPy (100x faster)."""
        try:
            x1, y1, x2, y2 = rect_coords
            roi = raw_data[y1:y2, x1:x2]
            
            if roi.size < 10:
                return np.zeros_like(roi, dtype=bool)
            
            # Vectorized statistics
            median_val = np.median(roi)
            std_val = np.std(roi)
            
            # Vectorized glint threshold (3-sigma outliers)
            glint_threshold = median_val + 3 * std_val
            glint_mask = roi > glint_threshold
            
            # Vectorized gradient detection for reflection edges
            if roi.shape[0] > 3 and roi.shape[1] > 3:
                # Use np.gradient for efficient gradient calculation
                grad_y, grad_x = np.gradient(roi.astype(float))
                grad_magnitude = np.sqrt(grad_y**2 + grad_x**2)
                
                grad_threshold = 2 * std_val
                # Combine: high gradient + brightness = glint
                glint_mask |= (grad_magnitude > grad_threshold) & (roi > median_val)
            
            glint_percentage = (np.sum(glint_mask) / glint_mask.size) * 100
            logging.debug(f"Glint detection: {glint_percentage:.1f}% pixels marked as glint")  # FIX-PERF-02 v3.30.4: was logging.info — demoted to debug (per-box noise)
            return glint_mask
            
        except Exception as e:
            logging.error(f"Glint detection failed: {e}")
            return np.zeros_like(raw_data[y1:y2, x1:x2], dtype=bool)

def _strip_exiftool_group_prefixes(meta_dict: Dict[str, Dict]) -> Dict[str, Dict]:
    """Normalise PyExifTool metadata keys by stripping the 'Group:' prefix."""
    normalised: Dict[str, Dict] = {}
    for filename, tags in meta_dict.items():
        clean: Dict = {}
        for raw_key, value in tags.items():
            # Keys without ':' (e.g. 'SourceFile') are kept as-is
            bare = raw_key.split(':', 1)[-1] if ':' in raw_key else raw_key
            if bare not in clean:
                clean[bare] = value
            else:
                # Same physical value in multiple IFDs — first wins; log at DEBUG
                logging.debug(
                    f"_strip_exiftool_group_prefixes: duplicate bare key "
                    f"'{bare}' from '{raw_key}' in '{filename}' — keeping first value"
                )
        normalised[filename] = clean
    return normalised


def extract_data(folder, use_cache=True):
    """ENHANCED: Extract thermal data and metadata with caching support."""
    path = Path(folder)
    
    # ENHANCEMENT: Check metadata cache
    cache_dir = path / ".thermal_cache"
    cache_file = cache_dir / "metadata.json"
    
    use_cache = use_cache and CFG.get("DETECTION", "UseCache", "True") == "True"
    
    if use_cache and cache_file.exists():
        cache_age = time.time() - cache_file.stat().st_mtime
        if cache_age < 3600:  # Cache valid for 1 hour
            try:
                logging.info("Loading metadata from cache")
                with open(cache_file, 'r', encoding='utf-8') as f:
                    cached_data = json.load(f)
                
                # v3.30.1.40 CORRECTNESS: validate cache with (name, mtime, size) hash
                # Previous: only checked file COUNT — a replaced file with same count
                # would return stale Planck constants → wrong temperature calculations.
                # Now: any file modification (content OR timestamp) invalidates the cache.
                jpg_files = list(path.glob("*.[jJ][pP]*[gG]"))
                current_sig = sorted(
                    (f.name, int(f.stat().st_mtime * 1000), f.stat().st_size)
                    for f in jpg_files
                )
                sig_hash = hashlib.md5(
                    json.dumps(current_sig, separators=(',', ':')).encode()
                ).hexdigest()

                if cached_data.get("_sig_hash") == sig_hash:
                    logging.info(f"✓ Using cached metadata ({len(jpg_files)} files, hash={sig_hash[:8]})")
                    # Still need to extract thermal TIFFs
                    temp_dir = _extract_thermal_tiffs(path, jpg_files)
                    return cached_data, temp_dir
                else:
                    logging.info("Cache invalidated - file content/modification detected")
            except Exception as e:
                logging.warning(f"Cache read failed: {e}")
    
    # Extract fresh metadata
    meta_dict, temp_dir = _extract_metadata_fresh(path)
    
    # ENHANCEMENT: Save metadata cache (with content-hash signature)
    if use_cache:
        try:
            cache_dir.mkdir(exist_ok=True)
            # Compute and embed the signature so future reads can validate
            jpg_files_for_sig = list(path.glob("*.[jJ][pP]*[gG]"))
            cache_sig = sorted(
                (f.name, int(f.stat().st_mtime * 1000), f.stat().st_size)
                for f in jpg_files_for_sig
            )
            sig_hash = hashlib.md5(
                json.dumps(cache_sig, separators=(',', ':')).encode()
            ).hexdigest()
            meta_dict["_sig_hash"] = sig_hash  # embed signature in the cache dict
            with open(cache_file, 'w', encoding='utf-8') as f:
                json.dump(meta_dict, f, indent=2)
            logging.info(f"✓ Metadata cached for future use (hash={sig_hash[:8]})")
        except Exception as e:
            logging.warning(f"Could not save metadata cache: {e}")
    
    return meta_dict, temp_dir


# ── BUG-EXIF-WIN-01 FIX: exiftool subprocess helper ──────────────────────────
# Problem: subprocess.run(..., check=True) raises CalledProcessError for exit
# code 1, but exiftool uses exit 1 for *warnings* (minor issues, unreadable
# sidecar files, etc.) and exit 2 for real errors.  Paths with spaces on
# Windows were also triggering exit-1 warnings that aborted entire batches.
# Fix:
#   1. Only raise on exit code >= 2 (real error); treat exit 1 as warning.
#   2. Always capture stderr and log it — prevents silent "returned non-zero" msgs.
#   3. Only pass creationflags on Windows (CREATE_NO_WINDOW).
#   4. Quote the -W output path explicitly on Windows to handle spaces.
def _run_exiftool(cmd: list, timeout: int = 600, stdin=None, stdout=None) -> subprocess.CompletedProcess:
    """Run an exiftool command, treating exit-code 1 as warning (not error)."""
    kwargs: dict = dict(timeout=timeout, stderr=subprocess.PIPE)
    if os.name == 'nt':
        kwargs['creationflags'] = subprocess.CREATE_NO_WINDOW
    if stdin is not None:
        kwargs['stdin'] = stdin
    if stdout is not None:
        kwargs['stdout'] = stdout

    result = subprocess.run(cmd, **kwargs)

    stderr_text = (result.stderr or b'').decode('utf-8', errors='replace').strip()
    if result.returncode == 0:
        if stderr_text:
            logging.debug(f"exiftool stderr (ok): {stderr_text[:300]}")
    elif result.returncode == 1:
        # Warning — log but do NOT raise; batch should continue
        logging.warning(
            f"exiftool exit-1 (warning, non-fatal): {stderr_text[:400] or '(no stderr)'}\n"
            f"  cmd: {' '.join(str(c) for c in cmd[-3:])}"   # last 3 args for context
        )
    else:
        # Exit 2+ — real error
        raise subprocess.CalledProcessError(
            result.returncode, cmd,
            output=None,
            stderr=stderr_text or "(no stderr)"
        )
    return result


def _exiftool_win_flag() -> dict:
    """Return creationflags kwarg dict for Windows only."""
    return {'creationflags': subprocess.CREATE_NO_WINDOW} if os.name == 'nt' else {}


def _win_flags() -> dict:
    """Alias for _exiftool_win_flag() for backward compatibility.
    
    FIX: v3.30.25.4 - Added this alias to resolve NameError where code called
    _win_flags() but the function was named _exiftool_win_flag(). Rather than
    updating all call sites, we provide this alias to maintain compatibility
    with existing code that expects _win_flags() to exist.
    
    Returns:
        dict: Windows subprocess creation flags (same as _exiftool_win_flag())
    """
    return _exiftool_win_flag()


def _extract_thermal_tiffs(path, jpg_files):
    """Extract only thermal TIFFs (used when metadata is cached)."""
    temp_dir = Path(tempfile.mkdtemp(prefix="flir_tmp_"))

    try:
        if FLYR_AVAILABLE:
            # ── flyr path: write float32 celsius TIFFs (same as fresh-extract) ──
            flyr_failed: list = []
            for jpg_path in jpg_files:
                celsius, _meta = _extract_via_flyr(jpg_path)
                if celsius is not None:
                    tiff_out = temp_dir / f"{jpg_path.stem}_t.tiff"
                    cv2.imwrite(str(tiff_out), celsius)
                    _cache_key = str(temp_dir) + "/" + jpg_path.stem
                    _FLYR_CELSIUS_CACHE[_cache_key] = celsius
                else:
                    flyr_failed.append(jpg_path)

            if flyr_failed:
                logging.warning(
                    f"[FIX-CACHE-FLYR-01] flyr failed for {len(flyr_failed)} cached "
                    f"file(s) — exiftool fallback: {[f.name for f in flyr_failed]}"
                )
                _run_exiftool([
                    "exiftool", "-RawThermalImage", "-b",
                    "-W", str(temp_dir / "%f_t.tiff"),
                    "-ext", "jpg", "-ext", "JPG", "-ext", "jpeg", "-ext", "JPEG",
                ] + [str(f) for f in flyr_failed], timeout=600)

        else:
            # flyr not installed — exiftool raw uint16 path (unchanged)
            _run_exiftool([
                "exiftool", "-RawThermalImage", "-b",
                "-W", str(temp_dir / "%f_t.tiff"),
                "-ext", "jpg", "-ext", "JPG", "-ext", "jpeg", "-ext", "JPEG",
                str(path)
            ], timeout=600)

        return temp_dir

    except subprocess.CalledProcessError as e:
        logging.error(f"Thermal TIFF extraction error (exit {e.returncode}): {e.stderr}")
        shutil.rmtree(temp_dir, ignore_errors=True)
        raise
    except Exception as e:
        logging.error(f"Thermal TIFF extraction error: {e}")
        shutil.rmtree(temp_dir, ignore_errors=True)
        raise


def _extract_metadata_fresh(path):
    """Extract metadata and thermal arrays for all JPEG files in a folder."""
    temp_dir = Path(tempfile.mkdtemp(prefix="flir_tmp_"))
    meta_dict = {}

    try:
        jpg_files = list(path.glob("*.[jJ][pP]*[gG]"))

        if not jpg_files:
            raise ValueError("No JPEG files found")

        # ── PRIMARY: flyr per-file extraction ────────────────────────────
        # WHY flyr is primary: its celsius output matches FLIR Thermal Studio
        # because it applies the FLIR SDK two-tau model with beta coefficients,
        # sqrt(OD/2) path length, and RH as fraction — all correcting systematic
        # errors that caused the temperature discrepancy in previous versions.
        flyr_failed_files: list = []
        if FLYR_AVAILABLE:
            logging.info(
                f"[flyr] Extracting calibrated celsius for "
                f"{len(jpg_files)} files (PRIMARY path)"
            )
            flyr_success_count = 0
            for jpg_path in jpg_files:
                celsius, flyr_meta = _extract_via_flyr(jpg_path)
                if celsius is not None and flyr_meta:
                    # Save celsius float32 as _t.tiff (cv2 supports float32 TIFF).
                    # DataHandler.load_thermal() detects float32 dtype and returns
                    # the celsius array directly, bypassing Planck conversion.
                    tiff_out = temp_dir / f"{jpg_path.stem}_t.tiff"
                    cv2.imwrite(str(tiff_out), celsius)
                    # Cache celsius by (temp_dir, stem) for calculate_adaptive_temps
                    _cache_key = str(temp_dir) + "/" + jpg_path.stem
                    _FLYR_CELSIUS_CACHE[_cache_key] = celsius
                    meta_dict[jpg_path.name] = flyr_meta
                    flyr_success_count += 1
                else:
                    flyr_failed_files.append(jpg_path)

            logging.info(
                f"[flyr] {flyr_success_count}/{len(jpg_files)} files "
                f"extracted successfully"
            )
            if not flyr_failed_files:
                return meta_dict, temp_dir   # all done — no exiftool needed

            # FIX-FLYR-SILENT-02 (v3.30.25): Promoted INFO → WARNING for per-file
            # fallback activation.  Lists every affected filename so operators can
            # identify corrupted/incompatible RJPEGs immediately from the log without
            # needing to cross-reference batch output or CSV.
            # Temperature accuracy on these files degrades to ±2–4 °C (flirpy/Planck).
            logging.warning(
                f"[flyr] ⚠ FALLBACK ACTIVATED for {len(flyr_failed_files)} file(s) — "
                f"temperature accuracy degrades to ±2–4 °C on these images "
                f"(flirpy/exiftool path used instead of flyr): "
                f"{[f.name for f in flyr_failed_files]}"
            )
            jpg_files = flyr_failed_files    # restrict scope to failed files only
        else:
            # FIX-FLYR-SILENT-02 (v3.30.25): Promoted INFO → WARNING.
            # flyr being absent means EVERY image in this batch uses the lower-accuracy
            # fallback path.  This must be visible in production log viewers.
            logging.warning(
                "[flyr] ⚠ flyr not installed — ALL files using flirpy/exiftool fallback. "
                "Temperature accuracy degrades to ±2–4 °C per image. "
                "Install flyr for FLIR Thermal Studio-grade accuracy: "
                "pip install flyr --break-system-packages"
            )

        # ── SECONDARY: flirpy per-file extraction (raw uint16) ────────────
        if FLIRPY_AVAILABLE:
            logging.info(
                f"flirpy: extracting metadata + thermal arrays for "
                f"{len(jpg_files)} files (secondary path)"
            )
            flirpy_success_count = 0
            flirpy_failed_files  = []

            for jpg_path in jpg_files:
                thermal_array, flirpy_meta = _extract_via_flirpy(jpg_path)
                if thermal_array is not None and flirpy_meta:
                    # Save thermal array as _t.tiff so downstream code that reads
                    # temp_dir/*.tiff continues to work without modification.
                    tiff_out = temp_dir / f"{jpg_path.stem}_t.tiff"
                    cv2.imwrite(str(tiff_out), thermal_array)
                    # Store metadata keyed by filename (same convention as exiftool path)
                    meta_dict[jpg_path.name] = flirpy_meta
                    flirpy_success_count += 1
                else:
                    flirpy_failed_files.append(jpg_path)

            logging.info(
                f"flirpy: {flirpy_success_count}/{len(jpg_files)} files extracted "
                f"successfully"
            )

            # If all files succeeded, return early — no exiftool needed
            if not flirpy_failed_files:
                return meta_dict, temp_dir

            # Some files failed flirpy — process those via exiftool below.
            # FIX-FLYR-SILENT-03 (v3.30.25): Promoted INFO → WARNING.
            # Files here have failed BOTH flyr and flirpy — only raw exiftool
            # TIFF + manual Planck remains.  Accuracy on these files may degrade
            # further (±3–5 °C) if EXIF Planck constants or atmospheric params
            # are absent.  Named so operators can inspect those specific files.
            logging.warning(
                f"[flirpy] ⚠ FALLBACK ACTIVATED: {len(flirpy_failed_files)} file(s) "
                f"failed both flyr AND flirpy — falling back to exiftool + Planck. "
                f"Temperature accuracy may degrade to ±3–5 °C on: "
                f"{[f.name for f in flirpy_failed_files]}"
            )
            # Restrict exiftool to only the failed files
            jpg_files = flirpy_failed_files

        # ── SECONDARY: PyExifTool singleton ──────────────────────────────
        # ENHANCEMENT: Use PyExifTool if available
        if EXIFTOOL_HELPER_AVAILABLE:
            logging.info("Using PyExifTool for metadata extraction (fast mode)")
            
            # AUDIT-PERF-001 FIX (v3.30.24): Use the module-level singleton via
            # _get_exiftool() instead of creating a fresh ExifToolHelper() context.
            # The previous "with ExifToolHelper() as et:" call started a NEW Perl
            # process for every single batch invocation, completely negating the
            # 10-50x speedup provided by _EXIFTOOL_SINGLETON. The singleton keeps
            # the Perl process alive between calls (~1-5ms per call vs 80-200ms cold).
            # If the singleton is unavailable (e.g. first-call init failed), we fall
            # through to the subprocess fallback below.
            _et_singleton = _get_exiftool()
            if _et_singleton is not None:
                with _EXIFTOOL_LOCK:
                    try:
                        # Method 1: Try get_tags with specific FLIR groups
                        metadata_list = _et_singleton.get_tags(
                            [str(f) for f in jpg_files],
                            tags=["FLIR:all", "Composite:all", "EXIF:all"]  # Explicitly request FLIR tags
                        )
                        meta_dict = {Path(item['SourceFile']).name: item for item in metadata_list}
                        logging.info(f"✓ Extracted metadata with FLIR tags for {len(metadata_list)} files")
                        # v3.30.1.12 FIX #2b: Strip 'Group:' prefixes from all tag keys at ingest.
                        meta_dict = _strip_exiftool_group_prefixes(meta_dict)
                    except Exception as e:
                        # Fallback to get_metadata if get_tags not available
                        logging.warning(f"get_tags failed ({e}), falling back to get_metadata")
                        metadata_list = _et_singleton.get_metadata([str(f) for f in jpg_files])
                        meta_dict = {Path(item['SourceFile']).name: item for item in metadata_list}
                        # v3.30.1.12 FIX #2b: Same normalisation for fallback path.
                        meta_dict = _strip_exiftool_group_prefixes(meta_dict)
            else:
                # Singleton unavailable — fall through to subprocess path
                logging.warning("ExifTool singleton unavailable; falling back to subprocess extraction")
                _exiftool_helper_local = False  # noqa: local scope flag
            
            if _et_singleton is not None:
                # Extract thermal TIFFs — PyExifTool doesn't support -W flag so we
                # always use subprocess here; _run_exiftool handles exit-1 warnings.
                _run_exiftool([
                    "exiftool", "-RawThermalImage", "-b",
                    "-W", str(temp_dir / "%f_t.tiff"),
                    "-ext", "jpg", "-ext", "JPG", "-ext", "jpeg", "-ext", "JPEG",
                    str(path)
                ], timeout=600)
        
        if not EXIFTOOL_HELPER_AVAILABLE or _et_singleton is None:
            logging.info("Using subprocess for metadata extraction (slow mode - install pyexiftool for 10-50x speedup)")
            
            meta_file = temp_dir / "meta.json"

            # Metadata extraction — stdout to file, stderr captured by _run_exiftool
            with open(meta_file, "w", encoding='utf-8') as mf:
                _run_exiftool([
                    "exiftool", "-j", "-n",
                    "-FLIR:all", "-Composite:all",
                    "-ext", "jpg", "-ext", "JPG", "-ext", "jpeg", "-ext", "JPEG",
                    str(path)
                ], timeout=300, stdout=mf)

            with open(meta_file, 'r', encoding='utf-8') as f:
                meta_list = json.load(f)
            meta_dict = {Path(item['SourceFile']).name: item for item in meta_list}
            
            # Extract thermal TIFFs
            _run_exiftool([
                "exiftool", "-RawThermalImage", "-b",
                "-W", str(temp_dir / "%f_t.tiff"),
                "-ext", "jpg", "-ext", "JPG", "-ext", "jpeg", "-ext", "JPEG",
                str(path)
            ], timeout=600)
        
        # Log camera info
        if meta_dict:
            first_meta = list(meta_dict.values())[0]
            camera_model = first_meta.get('Model', 'Unknown')
            camera_make = first_meta.get('Make', 'Unknown')
            logging.info(f"Camera: {camera_make} {camera_model}")
            
            # Debug: Show Planck keys
            planck_keys_found = [k for k in first_meta.keys() if 'planck' in k.lower()]
            if planck_keys_found:
                logging.info(f"Found Planck keys in EXIF: {planck_keys_found}")
                for key in planck_keys_found:
                    logging.info(f"  {key} = {first_meta[key]}")
            else:
                logging.warning("⚠️ NO Planck constants found in EXIF metadata!")
            
            # Log actual values
            logging.info(f"Planck R1: {safe_get_meta(first_meta, 'PlanckR1', 'NOT FOUND')}")
            logging.info(f"Planck R2: {safe_get_meta(first_meta, 'PlanckR2', 'NOT FOUND')}")
            logging.info(f"Planck B: {safe_get_meta(first_meta, 'PlanckB', 'NOT FOUND')}")

    except Exception as e:
        logging.error(f"Extraction error: {e}")
        shutil.rmtree(temp_dir, ignore_errors=True)
        raise

    return meta_dict, temp_dir


