# CRITICAL FIX #2: ThermalFrame Architecture (v3.26)
# ================================================================================================

# ╔══════════════════════════════════════════════════════════════════════════╗
# ║  SECTION 13 — THERMAL FRAME                                                 ║
# ║  Strict separation: raw thermal / ML preprocessing / display output.       ║
# ╚══════════════════════════════════════════════════════════════════════════╝

class ThermalFrame:
    """USAGE:"""
    
    def __init__(self, raw_thermal, metadata, image_path=None):
        """Initialize ThermalFrame with raw thermal data."""
        self.raw = raw_thermal.astype(np.float32)  # Raw radiometric data
        self.metadata = metadata
        self.image_path = image_path
        
        # Lazy-loaded processed versions (computed once, cached)
        self._gray_ml = None      # CLAHE-enhanced grayscale for YOLO
        self._display = None      # Display-ready image (palette applied)
        self._display_cache_key = None  # v3.30.1.40: (palette,apply_clahe,clip,auto,min,max) tuple
        self._temps_celsius = None  # Temperature map (computed once)
        
        # Validation
        if self.raw.ndim != 2:
            raise ValueError(f"Raw thermal must be 2D, got shape {self.raw.shape}")
        
        # Validate radiometric range (14-16 bit expected)
        raw_max = np.max(self.raw)
        if raw_max < 300:
            logging.warning(f"Suspicious thermal data: max={raw_max:.0f} (expected 14-16 bit range)")
    
    @classmethod
    def from_rjpeg(cls, rjpeg_path, metadata=None):
        """Create ThermalFrame from FLIR R-JPEG file."""
        rjpeg_path = Path(rjpeg_path)
        
        # Extract thermal data (this handles MSX removal automatically)
        thermal_array = extract_thermal_from_rjpeg(rjpeg_path)
        if thermal_array is None:
            raise RuntimeError(f"Failed to extract thermal from {rjpeg_path}")
        
        # Extract metadata if not provided
        if metadata is None:
            # v3.30.1.40 EFFICIENCY: use persistent ExifTool singleton when available
            # (was: raw subprocess.run without FLIR:all flag — missed FLIR-specific tags)
            et = _get_exiftool()
            if et is not None:
                try:
                    with _EXIFTOOL_LOCK:
                        meta_list = et.get_tags(
                            [str(rjpeg_path)],
                            tags=["FLIR:all", "Composite:all", "EXIF:all"]
                        )
                    raw_meta = meta_list[0] if meta_list else {}
                    # Strip group prefixes for downstream compatibility
                    metadata = _strip_exiftool_group_prefixes({rjpeg_path.name: raw_meta}).get(rjpeg_path.name, {})
                except Exception as exc:
                    logging.warning(f"ExifTool singleton metadata failed ({exc}); falling back to subprocess")
                    metadata = None
            if metadata is None:
                # Subprocess fallback — includes FLIR:all for correct Planck constants
                # FIX-EXIF-RANGE-005 (v3.30.25.8): Added -EXIF:all to extract
                # Make, Model, LensModel, ImageWidth, ImageHeight from EXIF group.
                flag = subprocess.CREATE_NO_WINDOW if os.name == 'nt' else 0
                try:
                    result = subprocess.run(
                        ["exiftool", "-j", "-n", "-FLIR:all", "-Composite:all", "-EXIF:all", str(rjpeg_path)],
                        capture_output=True, text=True, check=True,
                        creationflags=flag, timeout=30
                    )
                    raw_meta = json.loads(result.stdout)[0]
                    metadata = _strip_exiftool_group_prefixes({rjpeg_path.name: raw_meta}).get(rjpeg_path.name, {})
                except Exception as exc:
                    logging.warning(f"Failed to extract metadata: {exc}, using defaults")
                    metadata = {}
        
        return cls(thermal_array, metadata, rjpeg_path)
    
    def get_temperatures(self, box_coords=None, unit='C'):
        """Get temperature values from raw thermal data."""
        if self._temps_celsius is None:
            # Detect flyr celsius array by dtype + realistic temperature range.
            # Same sentinel logic as DataHandler.load_thermal and
            # calculate_adaptive_temps so all three functions agree.
            _is_celsius = (
                self.raw.dtype == np.float32
                and self.raw.min() >= -80.0
                and self.raw.max() <= 650.0
            )
            if _is_celsius:
                # Already calibrated °C — cache as-is (no copy needed; read-only use)
                self._temps_celsius = self.raw
                logging.debug(
                    "[flyr] ThermalFrame.get_temperatures: celsius array detected — "
                    "raw2temp_celsius skipped"
                )
            else:
                self._temps_celsius = ThermalPhysics.raw2temp_celsius(
                    self.raw, self.metadata
                )

        temps = self._temps_celsius

        # Extract ROI if requested
        if box_coords is not None:
            x1, y1, x2, y2 = box_coords
            temps = temps[y1:y2, x1:x2]

        # Unit conversion
        if unit == 'F':
            temps = temps * FAHRENHEIT_SCALE + FAHRENHEIT_OFFSET
        elif unit == 'K':
            temps = temps + CELSIUS_TO_KELVIN

        return temps
    
    def get_ml_input(self):
        """Get YOLO-ready input (3-channel CLAHE-enhanced grayscale)."""
        if self._gray_ml is None:
            # Apply CLAHE preprocessing ONCE (same as prepare_single_image_parallel)
            self._gray_ml = self._apply_ml_preprocessing()
        
        return self._gray_ml
    
    def _apply_ml_preprocessing(self):
        """Internal: Apply YOLO preprocessing pipeline."""
        # Per-image normalization
        thermal_float = self.raw.astype(np.float32)
        min_val = np.min(thermal_float)
        max_val = np.max(thermal_float)
        
        if max_val - min_val < 1e-6:
            normalized = np.full_like(thermal_float, 0.5)
        else:
            normalized = (thermal_float - min_val) / (max_val - min_val + 1e-6)
        
        normalized_8bit = (normalized * 255.0).astype(np.uint8)
        
        # ML-003: Bilateral filter REMOVED (30-40% speed improvement)
        # Reason: CLAHE already handles local contrast, bilateral filter is redundant
        # This significantly speeds up preprocessing for training and detection
        
        # ML-004: Thermal-optimized CLAHE parameters
        # Variance threshold changed from 100 (RGB default) to 200 (thermal-specific)
        # Tile sizes optimized for thermal image characteristics
        image_variance = np.var(normalized_8bit)
        # BUG-RT-02 FIX v3.30.17: cv2 CLAHE objects are NOT thread-safe.
        # The module-level _CLAHE_LOW/_CLAHE_HIGH globals are safe for ProcessPool
        # (each worker gets its own memory copy) but NOT for ThreadPoolExecutor
        # (all threads share the same object, causing data races in the C++ layer).
        # Fix: always create a fresh, thread-local CLAHE object here.
        # cv2.createCLAHE() is lightweight — the object is just a parameter container
        # with negligible allocation cost compared to the .apply() operation itself.
        if image_variance < THERMAL_VARIANCE_THRESHOLD:  # Low contrast thermal
            clahe = cv2.createCLAHE(clipLimit=CLAHE_CLIP_LIMIT_LOW_VARIANCE,
                                    tileGridSize=CLAHE_TILE_SIZE_LOW)
        else:                                            # High contrast thermal
            clahe = cv2.createCLAHE(clipLimit=CLAHE_CLIP_LIMIT_HIGH_VARIANCE,
                                    tileGridSize=CLAHE_TILE_SIZE_HIGH)
        
        enhanced = clahe.apply(normalized_8bit)  # Apply directly to normalized, no bilateral
        
        # Expand to 3 channels (YOLO compatibility)
        three_channel = cv2.merge([enhanced, enhanced, enhanced])
        
        return three_channel
    
    def get_display(self, palette="INFERNO", apply_clahe=False, clahe_clip=2.0, 
                    auto_window=True, manual_min=None, manual_max=None):
        """
            Get display-ready image for viewers/reports.
            This is SEPARATE from ML preprocessing and must NEVER be used for training.
        """
        # v3.30.1.40 EFFICIENCY: cache display result keyed by all rendering parameters.
        # QCViewer redraws the same image repeatedly as the user navigates — without this
        # cache every navigation event called apply_thermal_window() (expensive NumPy +
        # colormap operation). Cache is invalidated when any display parameter changes.
        cache_key = (palette, apply_clahe, clahe_clip, auto_window, manual_min, manual_max)
        if self._display_cache_key == cache_key and self._display is not None:
            return self._display

        display = apply_thermal_window(
            self.raw,
            auto_window=auto_window,
            manual_min=manual_min,
            manual_max=manual_max,
            palette=palette,
            apply_clahe_display=apply_clahe,
            clahe_clip=clahe_clip
        )
        self._display = display
        self._display_cache_key = cache_key
        return display
    
    def save_ml_image(self, output_path):
        """Save ML-ready image for training dataset."""
        ml_input = self.get_ml_input()
        if not cv2.imwrite(str(output_path), ml_input):
            raise IOError(f"save_ml_image: cv2.imwrite failed for {output_path}")
        logging.info(f"Saved ML-ready image: {output_path}")
    
    def save_display_image(self, output_path, **display_kwargs):
        """Save display image for viewers/reports."""
        display = self.get_display(**display_kwargs)
        if not cv2.imwrite(str(output_path), display):
            raise IOError(f"save_display_image: cv2.imwrite failed for {output_path}")
        logging.info(f"Saved display image: {output_path}")



# ╔══════════════════════════════════════════════════════════════════════════╗
# ║  SECTION 14 — DATA HANDLER                                                  ║
# ║  RJPEG extraction, FLIR metadata, exiftool bridge.                         ║
# ╚══════════════════════════════════════════════════════════════════════════╝

class DataHandler:
    @staticmethod
    def load_thermal(stem, temp_dir):
        """Load thermal data for *stem* from temp_dir."""
        # ── Locate TIFF file ─────────────────────────────────────────────────
        thermal_path = temp_dir / f"{stem}_t.tiff"
        if not thermal_path.exists():
            thermal_path = temp_dir / f"{stem}_t.tif"
            if not thermal_path.exists():
                logging.error(f"Thermal file not found: {stem}_t.tiff")
                return None, None

        raw = cv2.imread(str(thermal_path), cv2.IMREAD_UNCHANGED)
        if raw is None or raw.size == 0:
            logging.error(f"Failed to read thermal file: {thermal_path}")
            return None, None

        # Collapse unexpected multi-channel TIFF (defensive; should not occur)
        if raw.ndim == 3:
            raw = raw[:, :, 0]

        # ── PATH A: flyr celsius TIFF ─────────────────────────────────────────
        # flyr writes float32 TIFFs.  A legitimate raw uint16 TIFF can never
        # have dtype float32.  We add a value-range sanity check (−80…+650 °C)
        # to guard against any edge-case float32 TIFF that is NOT a celsius map.
        _is_flyr_celsius = (
            raw.dtype == np.float32
            and raw.min() >= -80.0    # below FLIR camera min range
            and raw.max() <= 650.0    # above FLIR camera max range
        )
        if _is_flyr_celsius:
            logging.debug(
                f"[flyr] load_thermal [{stem}]: celsius TIFF detected "
                f"min={raw.min():.2f}°C  max={raw.max():.2f}°C — "
                f"skipping byte-swap and Planck conversion"
            )
            # raw is already float32 celsius — return as-is
        else:
            # ── PATH B: uint16 raw DN (flirpy / exiftool) ─────────────────
            logging.debug(
                f"RAW THERMAL DATA DEBUG [{stem}]: "
                f"min={raw.min():.0f} max={raw.max():.0f} "
                f"mean={raw.mean():.0f} dtype={raw.dtype}"
            )

            # ── Byte-order correction (two complementary guards) ─────────
            # Guard 1 (max < 7000): big-endian TIFF read by cv2 as LE
            #   → anomalously LOW values.
            # Guard 2 (mean > 32000): FLIR T5xx/Exx big-endian PNG inside
            #   FFF APP1 block → values 44..65355, mean ~33347 instead of
            #   correct 11000..22000 mean ~17000.
            _needs_swap = raw.dtype == np.uint16 and (
                raw.max() < 7000        # guard 1: BE TIFF misread as LE
                or raw.mean() > 32000   # guard 2: BE PNG misread as LE
            )
            if _needs_swap:
                logging.warning(
                    f"BYTE ORDER BUG DETECTED [{stem}]: "
                    f"max={raw.max():.0f} mean={raw.mean():.0f} — applying byteswap."
                )
                raw = raw.byteswap()
                if raw.max() > 7000:
                    logging.info(f"Byte swap successful: {raw.min():.0f}–{raw.max():.0f}")
                else:
                    logging.warning(f"Byte swap incomplete — max still < 7000: {raw.max():.0f}")
            elif raw.dtype != np.uint16 and raw.max() < 7000:
                logging.error(f"Data type {raw.dtype} cannot be byte-swapped")
            else:
                logging.debug(f"Byte order correct: max={raw.max():.0f} mean={raw.mean():.0f}")

            # Cast to float32 for downstream Planck conversion
            raw = raw.astype(np.float32)

        # ── Generate display image (both paths) ──────────────────────────────
        # apply_thermal_window() normalises whatever float32 range it receives
        # so it works correctly whether raw contains DN values or °C values.
        auto_window     = CFG.get("DISPLAY", "AutoThermalWindow",  "True")  == "True"
        palette         = CFG.get("DISPLAY", "ThermalPalette",     "INFERNO")
        manual_enabled  = CFG.get("DISPLAY", "EnableManualWindow", "False") == "True"

        if manual_enabled and not auto_window:
            manual_min = CFG.get("DISPLAY", "ManualTempMin", 20.0, float)
            manual_max = CFG.get("DISPLAY", "ManualTempMax", 100.0, float)
            display = apply_thermal_window(
                raw, auto_window=False,
                manual_min=manual_min, manual_max=manual_max,
                palette=palette
            )
        else:
            display = apply_thermal_window(raw, auto_window=True, palette=palette)

        return display, raw

def prepare_single_image_parallel(raw_thermal):
    """ENHANCEMENT v3.19: Module-level function for parallel CLAHE preprocessing."""
    # Import locally since this runs in separate process
    import cv2
    import numpy as np
    
    # Simplified preprocessing (same logic as _prepare_yolo_input)
    thermal_float = raw_thermal.astype(np.float32)
    min_val = np.min(thermal_float)
    max_val = np.max(thermal_float)
    
    # Per-image normalization
    if max_val - min_val < 1e-6:
        normalized = np.full_like(thermal_float, 0.5)
    else:
        normalized = (thermal_float - min_val) / (max_val - min_val + 1e-6)
    
    normalized_8bit = (normalized * 255.0).astype(np.uint8)
    
    # ML-003: Bilateral filter REMOVED for 30-40% speed improvement
    
    # ML-004: Thermal-optimized CLAHE
    image_variance = np.var(normalized_8bit)
    if image_variance < THERMAL_VARIANCE_THRESHOLD:
        clip_limit = CLAHE_CLIP_LIMIT_LOW_VARIANCE
        tile_size = CLAHE_TILE_SIZE_LOW
    else:
        clip_limit = CLAHE_CLIP_LIMIT_HIGH_VARIANCE
        tile_size = CLAHE_TILE_SIZE_HIGH
    
    clahe = cv2.createCLAHE(clipLimit=clip_limit, tileGridSize=tile_size)
    enhanced = clahe.apply(normalized_8bit)
    
    # v3.30.1.17 FIX D-003: Added conservative sharpening for low-variance images.
    # This step was present in _prepare_yolo_input() but missing here, causing a
    # preprocessing mismatch between training (which used _prepare_yolo_input via
    # annotation export) and detection (which uses this parallel function for batches
    # > 10 images). Low-contrast thermal images got weaker preprocessing at inference
    # than at training, reducing model confidence on exactly those images.
    # Logic is identical to _prepare_yolo_input() lines 11967-11973.
    if image_variance < 100:
        kernel = np.array([[-0.5, -0.5, -0.5],
                         [-0.5,  5.0, -0.5],
                         [-0.5, -0.5, -0.5]])
        sharpened = cv2.filter2D(enhanced, -1, kernel)
        # Blend 50/50: subtle effect, avoids over-sharpening thermal noise
        enhanced = cv2.addWeighted(enhanced, 0.5, sharpened, 0.5, 0)
    
    # Expand to 3 channels (YOLO expects 3-channel input)
    three_channel = cv2.merge([enhanced, enhanced, enhanced])
    return three_channel


# REMOVED: add_temperature_scale (v3.30.1.21 — user requested complete removal of temperature scale bar)

def apply_thermal_window(raw_thermal, auto_window=True, manual_min=None, manual_max=None, palette="INFERNO",
                        apply_clahe_display=False, clahe_clip=2.0):
    """Convert raw thermal pixel values to a BGR display image. DISPLAY ONLY — never use for ML."""
    raw = raw_thermal.astype(np.float32)
    
    # Step 1: Determine temperature window
    if auto_window:
        # Auto-contrast: Use actual min/max from this specific image
        temp_min = np.min(raw)
        temp_max = np.max(raw)
    else:
        # Manual window: Use user-specified range
        temp_min = manual_min if manual_min is not None else np.min(raw)
        temp_max = manual_max if manual_max is not None else np.max(raw)
    
    # Step 2: Clip and scale to temperature window
    if temp_max > temp_min:
        # Clip values to window
        clipped = np.clip(raw, temp_min, temp_max)
        # Scale to 0-255
        normalized = ((clipped - temp_min) / (temp_max - temp_min) * 255).astype(np.uint8)
    else:
        # Degenerate case: all same temperature
        normalized = np.full(raw.shape, 128, dtype=np.uint8)
    
    # Step 2.5: OPTIONAL CLAHE enhancement for display (NEW v3.18.0)
    # ❌ DISPLAY ONLY - NOT FOR TRAINING/DETECTION
    if apply_clahe_display:
        logging.debug(f"Applying CLAHE to display image (clip_limit={clahe_clip:.1f}) - DISPLAY ONLY, NOT ML")
        clahe = cv2.createCLAHE(clipLimit=clahe_clip, tileGridSize=(8, 8))
        normalized = clahe.apply(normalized)
        logging.debug("✓ CLAHE applied to display (NOT used for training/detection)")
    
    # Step 3: Apply color palette
    palette_map = {
        "INFERNO": cv2.COLORMAP_INFERNO,
        "JET": cv2.COLORMAP_JET,
        "HOT": cv2.COLORMAP_HOT,
        "RAINBOW": cv2.COLORMAP_RAINBOW,
        "BONE": cv2.COLORMAP_BONE,
        "TURBO": cv2.COLORMAP_TURBO,
        "VIRIDIS": cv2.COLORMAP_VIRIDIS,
        "GRAYSCALE": None,  # NEW v3.18.0: Pure grayscale (no colormap)
    }
    
    # Apply palette
    if palette == "GRAYSCALE":
        # Pure grayscale: Convert single channel to 3-channel BGR
        display = cv2.cvtColor(normalized, cv2.COLOR_GRAY2BGR)
    else:
        colormap = palette_map.get(palette, cv2.COLORMAP_INFERNO)
        display = cv2.applyColorMap(normalized, colormap)
    
    return display

# ENHANCEMENT: Parallel thermal loading helper
def load_thermal_parallel(args):
    """Helper function for parallel thermal loading."""
    stem, temp_dir = args
    return DataHandler.load_thermal(stem, temp_dir)

def calculate_adaptive_temps(boxes, raw, meta, unit='C'):
    """Extract per-box spot-meter temperatures from YOLO detection boxes."""
    # ── Configuration ─────────────────────────────────────────────────────────
    base_percentile = CFG.get("DETECTION", "Percentile", 95, int)
    max_delta       = CFG.get("DETECTION", "MaxDelta", 15.0, float)
    adaptive        = CFG.get("DETECTION", "AdaptiveDelta", "True") == "True"

    # ── Input validation ──────────────────────────────────────────────────────
    # BUG-ASSERT-001 FIX (v3.30.24): bare assert statements are stripped by
    # Python's -O / -OO optimisation flags, silently bypassing all validation
    # in production builds. Replaced with explicit if-raise guards that are
    # always enforced regardless of the interpreter optimisation level.
    if not isinstance(raw, np.ndarray):
        raise TypeError("Raw thermal data must be numpy array")
    if raw.ndim != 2:
        raise ValueError(f"Raw thermal must be 2D, got shape {raw.shape}")

    # ── Detect whether raw is already calibrated celsius (flyr path) ──────────
    # flyr writes float32 TIFFs whose values are °C in the range −80…+650.
    # Raw DN arrays are uint16 or float32 with values in the range 300…65535.
    # Using BOTH dtype and value range makes the check robust against edge cases
    # (e.g. a float32 TIFF produced by some other tool).
    _is_celsius_array = (
        raw.dtype == np.float32
        and raw.min() >= -80.0
        and raw.max() <= 650.0
    )
    if _is_celsius_array:
        logging.debug(
            f"[flyr] calculate_adaptive_temps: celsius array detected "
            f"({raw.min():.1f}°C … {raw.max():.1f}°C) — Planck conversion skipped"
        )
    else:
        logging.debug(
            f"calculate_adaptive_temps: raw DN array "
            f"(min={raw.min():.0f} max={raw.max():.0f}) — Planck conversion active"
        )

    th, tw = raw.shape
    logging.debug(f"Temperature calculation for {len(boxes)} boxes on {th}x{tw} thermal image")

    spots = []

    for box_idx, box in enumerate(boxes):
        # Step 1: Validate and clip box coordinates
        x1, y1, x2, y2 = map(int, box)
        x1, x2 = max(0, x1), min(tw, x2)
        y1, y2 = max(0, y1), min(th, y2)

        logging.debug(f"Box {box_idx+1}: coords=({x1},{y1})-({x2},{y2}), size={x2-x1}x{y2-y1}px")

        # Check for degenerate box (zero area)
        if x2 <= x1 or y2 <= y1:
            logging.warning(f"Box {box_idx+1} has zero area: ({x1},{y1})-({x2},{y2})")
            spots.append({
                'pixels': [],
                'box_origin': (x1, y1),
                'box_coords': (x1, y1, x2, y2),
                'percentile': base_percentile,
                'temp': -999.0,
                'x': int((x1 + x2) / 2),
                'y': int((y1 + y2) / 2)
            })
            continue

        # Step 2: Extract box region from raw thermal data
        # CRITICAL: This ensures temperature comes from EXACT detection position
        box_raw = raw[y1:y2, x1:x2]

        # Validate extraction
        expected_h, expected_w = y2 - y1, x2 - x1
        actual_h, actual_w = box_raw.shape
        # BUG-ASSERT-001 FIX: explicit raise instead of bare assert
        if (actual_h, actual_w) != (expected_h, expected_w):
            raise ValueError(
                f"Box extraction mismatch: expected {expected_h}x{expected_w}, "
                f"got {actual_h}x{actual_w}"
            )

        # Step 3: Apply glint detection mask (opt-in only — FIX-GLINT-01)
        # WHY disabled by default: the 3-sigma threshold flags any hotspot occupying
        # <14% of the box as glint, masking the genuine hot pixels and returning the
        # background temperature instead.  Errors range from −5°C to −100°C depending
        # on ΔT.  FLIR Thermal Studio applies no glint mask on spot meters.
        # Enable via DETECTION.EnableGlintDetection=True in settings.ini for close-range
        # images with confirmed metallic specular reflections.
        _glint_enabled = CFG.get("DETECTION", "EnableGlintDetection", "False") == "True"
        if _glint_enabled:
            glint_mask = ThermalPhysics.detect_glint(raw, (x1, y1, x2, y2), meta)
        else:
            glint_mask = np.zeros(box_raw.shape, dtype=bool)   # no pixels masked
        glint_pixels = np.sum(glint_mask)
        total_pixels = box_raw.size

        if glint_pixels > 0:
            glint_pct = 100.0 * glint_pixels / total_pixels
            logging.debug(
                f"Box {box_idx+1}: {glint_pixels}/{total_pixels} pixels "
                f"masked as glint ({glint_pct:.1f}%)"
            )

        # Step 4: Obtain per-pixel temperatures for this box
        try:
            if _is_celsius_array:
                # ── MODE A: flyr celsius — direct read ───────────────────────
                # box_raw values are already °C courtesy of flyr.  Apply unit
                # conversion if the caller requested Fahrenheit or Kelvin.
                box_temps = box_raw.copy().astype(np.float32)
                if unit == 'F':
                    box_temps = box_temps * 1.8 + 32.0
                elif unit == 'K':
                    box_temps = box_temps + CELSIUS_TO_KELVIN
                # NaN-mask any physically impossible pixels (should be rare)
                box_temps[~np.isfinite(box_temps)] = np.nan
            else:
                # ── MODE B: raw DN — Planck conversion ───────────────────────
                box_temps = ThermalPhysics.raw2temp(box_raw, meta, unit)

            # Apply glint mask to exclude specular-reflection pixels
            box_temps[glint_mask] = np.nan

            # Validate: at least one finite temperature must survive
            valid_temps = box_temps[~np.isnan(box_temps)]
            if len(valid_temps) == 0:
                logging.error(f"Box {box_idx+1}: No valid temperatures after conversion")
                spots.append({
                    'pixels': [],
                    'box_origin': (x1, y1),
                    'box_coords': (x1, y1, x2, y2),
                    'percentile': base_percentile,
                    'temp': -999.0,
                    'x': int((x1 + x2) / 2),
                    'y': int((y1 + y2) / 2)
                })
                continue

            # Log temperature statistics for validation
            logging.debug(
                f"Box {box_idx+1} temps: min={valid_temps.min():.1f}°, "
                f"max={valid_temps.max():.1f}°, mean={valid_temps.mean():.1f}°, "
                f"valid_pixels={len(valid_temps)}"
                f"{' [flyr]' if _is_celsius_array else ' [Planck]'}"
            )
            
        except RuntimeError as e:
            logging.error(f"Box {box_idx+1} temperature conversion failed: {e}")
            spots.append({
                'pixels': [],
                'box_origin': (x1, y1),
                'box_coords': (x1, y1, x2, y2),  # FIXED v3.25: Store for center shift calculation
                'percentile': base_percentile,
                'temp': -999.0,
                'x': int((x1 + x2) / 2),
                'y': int((y1 + y2) / 2)
            })
            continue

        # Step 5: Vectorized pixel extraction (100x faster than loops)
        # Creates meshgrid of local (x,y) coordinates within box
        yy, xx = np.meshgrid(
            range(box_temps.shape[0]), 
            range(box_temps.shape[1]), 
            indexing='ij'
        )
        
        # Mask for valid temperatures (non-NaN, above error threshold)
        valid_mask = (~np.isnan(box_temps)) & (box_temps > -500)
        
        # Extract valid pixels as flat arrays
        temps_flat = box_temps[valid_mask]
        x_flat = xx[valid_mask]
        y_flat = yy[valid_mask]
        
        # Create list of (temp, local_x, local_y) tuples
        # This preserves temperature-position pairing for percentile selection
        valid_pixels = list(zip(temps_flat, x_flat, y_flat))

        spots.append({
            'pixels': valid_pixels,
            'box_origin': (x1, y1),
            'box_coords': (x1, y1, x2, y2),  # FIXED v3.25: Store for center shift calculation
            'percentile': base_percentile,
            'temp': -999.0,
            'x': int((x1 + x2) / 2),
            'y': int((y1 + y2) / 2)
        })

    # Step 6: Adaptive convergence loop
    # Iteratively adjusts percentiles to satisfy delta constraints.
    #
    # FIX-PERF-01 v3.30.4: Pre-sort each spot's pixel list ONCE here, before the
    # iteration loop.  The pixels list is immutable during convergence — only
    # spot['percentile'] changes.  Previously sorted() was called on every iteration
    # for every spot (up to 50 × n_spots re-sorts of ~256 items each per image).
    # Pre-sorting reduces sort calls from O(50 × n_spots) → O(n_spots) total.
    for spot in spots:
        if spot['pixels']:
            spot['sorted_pixels'] = sorted(spot['pixels'], key=lambda p: p[0])
        else:
            spot['sorted_pixels'] = []

    logging.debug("Starting adaptive convergence (max 50 iterations)")

    for iteration in range(50):
        for spot_idx, spot in enumerate(spots):
            if not spot['sorted_pixels']:
                spot['temp'] = -999.0
                continue

            # Use pre-sorted list — no re-sort needed; only percentile index changes
            sorted_pixels = spot['sorted_pixels']
            
            # Select percentile index
            percentile_idx = int(len(sorted_pixels) * spot['percentile'] / 100.0)
            percentile_idx = min(percentile_idx, len(sorted_pixels) - 1)
            
            # Extract percentile pixel (temp, local_x, local_y)
            percentile_pixel = sorted_pixels[percentile_idx]
            temp, local_x, local_y = percentile_pixel
            
            # Convert local coordinates to image coordinates
            # CRITICAL: This is the exact pixel position used for temperature
            image_x = spot['box_origin'][0] + local_x
            image_y = spot['box_origin'][1] + local_y
            
            # FIXED v3.25: Shift spot meter slightly towards center of component (detection box)
            # Limited to 3-4 pixels maximum for subtle visual improvement
            # The temperature is still read from the original percentile position
            
            # Get detection box coordinates
            x1, y1, x2, y2 = spot['box_coords']
            
            # Calculate detection box center
            box_center_x = (x1 + x2) / 2.0
            box_center_y = (y1 + y2) / 2.0
            
            # Calculate vector from current position to box center
            dx_to_center = box_center_x - image_x
            dy_to_center = box_center_y - image_y
            
            # Calculate distance to center
            distance_to_center = (dx_to_center**2 + dy_to_center**2)**0.5
            
            # Apply a small shift towards center (max 3-4 pixels)
            # This keeps the spot close to the hottest point while centering it slightly
            max_shift_pixels = 4  # Maximum shift in pixels
            if distance_to_center > 0:
                # Normalize direction vector
                shift_x = (dx_to_center / distance_to_center) * min(max_shift_pixels, distance_to_center)
                shift_y = (dy_to_center / distance_to_center) * min(max_shift_pixels, distance_to_center)
                image_x = int(image_x + shift_x)
                image_y = int(image_y + shift_y)
            
            # Ensure we stay within the detection box bounds
            image_x = max(x1, min(x2 - 1, image_x))
            image_y = max(y1, min(y2 - 1, image_y))

            # NOTE (FIX-BUG-01 v3.30.4): The LEGACY "edge margin" block that
            # previously followed this clamp has been removed.  It used inverted
            # min/max operators that could displace the coordinate back outside the
            # detection box after the correct clamp above, causing the spot to report
            # a pixel that was NOT the selected percentile temperature.
            # Safety is provided by: (a) the clamp above, (b) the inner-box
            # construction in _process_single_image (max(0,...)/min(shape,...)),
            # and (c) the assert below.
            
            # Validate coordinates are within image bounds.
            # BUG-ASSERT-001 FIX: explicit raises instead of bare asserts.
            if not (0 <= image_x < tw):
                raise ValueError(f"X coordinate {image_x} out of bounds (width={tw})")
            if not (0 <= image_y < th):
                raise ValueError(f"Y coordinate {image_y} out of bounds (height={th})")
            
            # Update spot with selected temperature and position
            spot['temp'] = temp
            spot['x'] = image_x
            spot['y'] = image_y
            
            # Log for position accuracy verification
            if iteration == 0:  # Log initial selection
                logging.debug(
                    f"Spot {spot_idx+1}: percentile={spot['percentile']}%, "
                    f"temp={temp:.2f}°, pos=({image_x},{image_y}), "
                    f"rank={percentile_idx+1}/{len(sorted_pixels)}"
                )

        if len(spots) < 2:
            break

        # Check for delta violations (adaptive percentile adjustment)
        violation_found = False
        for i in range(len(spots)):
            for j in range(i + 1, len(spots)):
                t1, t2 = spots[i]['temp'], spots[j]['temp']
                if t1 <= -500 or t2 <= -500:
                    continue
                
                if abs(t1 - t2) > max_delta:
                    if not adaptive:
                        break
                    
                    violation_found = True
                    hotter = i if t1 > t2 else j
                    
                    # Reduce percentile of hotter spot
                    if spots[hotter]['percentile'] > 70:
                        spots[hotter]['percentile'] = 70
                    elif spots[hotter]['percentile'] > 50:
                        spots[hotter]['percentile'] -= 1
                    
                    logging.debug(
                        f"Iteration {iteration}: Delta violation {abs(t1-t2):.1f}° > {max_delta}°, "
                        f"reducing spot {hotter+1} percentile to {spots[hotter]['percentile']}%"
                    )
                    break
            
            if violation_found:
                break

        if not violation_found:
            logging.debug(f"Convergence reached in {iteration} iterations")
            break
    
    # Final validation: Log all spot temperatures and positions
    final_temps = [(s['temp'], s['x'], s['y']) for s in spots]

    # TODO-04 FIX v3.30.1.15: Guard empty result before any caller accesses
    # final_temps[0].  If no boxes were provided or all conversions failed,
    # returning an empty list is correct — callers must handle [] gracefully.
    if not final_temps:
        logging.warning(
            "calculate_adaptive_temps: no valid spots computed "
            f"(boxes_in={len(boxes)}, spots_built={len(spots)}) — returning []"
        )
        return []

    for i, (t, x, y) in enumerate(final_temps):
        if t > -500:
            logging.info(f"✓ Spot {i+1}: {t:.2f}° at pixel ({x},{y})")
        else:
            logging.warning(f"✗ Spot {i+1}: Measurement error")

    return final_temps

def check_delta_guard(spot_temps, threshold=15.0):
    """DELTA GUARD FUNCTION - Pairwise Temperature Difference Check v3.20.1 P2.2: Added"""
    # v3.20.1 P2.2: Unit-aware delta checking
    # Get current temperature unit from config
    temp_unit = CFG.get("GENERAL", "TempUnit", "C")
    
    # If temperatures are in Fahrenheit, convert to Celsius for comparison
    # Threshold is always in Celsius (15°C = 27°F difference)
    if temp_unit == "F":
        # Convert Fahrenheit temperatures to Celsius for delta calculation
        # This prevents double conversion issues
        temps_celsius = []
        for t in spot_temps:
            if t > -500:  # Valid temperature
                t_celsius = (t - 32) * 5/9
                temps_celsius.append(t_celsius)
            else:
                temps_celsius.append(t)  # Keep error values
        
        # Use Celsius temps for comparison
        comparison_temps = temps_celsius
        logging.debug(f"v3.20.1: Converted {len(temps_celsius)} Fahrenheit temps to Celsius for delta check")
    else:
        # Already in Celsius, use as-is
        comparison_temps = spot_temps
    
    # Step 1: Filter out error values (-999 indicates measurement failure)
    # Why -500 threshold: Gives margin for very cold temps while filtering errors
    valid_temps_with_idx = [(i, t) for i, t in enumerate(comparison_temps) if t > -500]
    valid_temps = [t for _, t in valid_temps_with_idx]
    
    logging.debug(
        f"Delta guard input: {len(spot_temps)} temps, {len(valid_temps)} valid after filtering (unit: {temp_unit})"
    )
    
    if len(valid_temps) < 2:
        # Cannot compute pairwise differences with <2 valid temperatures
        logging.warning(f"Insufficient valid temperatures for pairwise check: {len(valid_temps)}/4")
        return False, 0.0, []
    
    # Step 2: Check ALL pairwise differences
    # This is O(n²) but with n=4, only 6 comparisons total
    max_delta = 0.0
    violation_pairs = []
    all_deltas = []
    
    for i in range(len(valid_temps_with_idx)):
        for j in range(i + 1, len(valid_temps_with_idx)):
            idx_i, temp_i = valid_temps_with_idx[i]
            idx_j, temp_j = valid_temps_with_idx[j]
            
            # Calculate absolute difference
            delta = abs(temp_i - temp_j)
            all_deltas.append(delta)
            
            # Track maximum delta for CSV reporting
            if delta > max_delta:
                max_delta = delta
            
            # Log each pairwise comparison
            logging.debug(
                f"  Pairwise: Sp{idx_i+1}={temp_i:.2f}° vs Sp{idx_j+1}={temp_j:.2f}° "
                f"→ Δ={delta:.2f}° {'✗ VIOLATION' if delta > threshold else '✓'}"
            )
            
            # Check if this pair violates threshold
            if delta > threshold:
                violation_pairs.append((idx_i, idx_j, delta))
    
    # Step 3: Determine if high delta based on ANY violation
    is_high_delta = len(violation_pairs) > 0
    
    # Step 4: Collect all flagged spot indices
    flagged = set()
    if is_high_delta:
        for idx_i, idx_j, delta in violation_pairs:
            flagged.add(idx_i)
            flagged.add(idx_j)
            logging.warning(
                f"  ⚠️  VIOLATION: Sp{idx_i+1} vs Sp{idx_j+1} = {delta:.2f}° > {threshold}°"
            )
    
    flagged = sorted(list(flagged))
    
    # Step 5: Summary logging for QC audit trail
    if is_high_delta:
        logging.warning(
            f"⚠️  HIGH DELTA DETECTED: {len(violation_pairs)} pairwise violation(s), "
            f"max_delta={max_delta:.2f}° (threshold={threshold}°), "
            f"flagged_spots={[i+1 for i in flagged]}"
        )
    else:
        avg_delta = sum(all_deltas) / len(all_deltas) if all_deltas else 0.0
        logging.debug(
            f"✓ Pairwise delta check PASSED: max={max_delta:.2f}°, avg={avg_delta:.2f}°, "
            f"all {len(all_deltas)} pairs < {threshold}°"
        )
    
    # v3.20.1 P2.2: Convert max_delta back to original unit
    # If input was Fahrenheit, convert delta back to Fahrenheit for display/CSV
    if temp_unit == "F":
        # Delta conversion: Celsius delta to Fahrenheit delta
        max_delta_original_unit = max_delta * 9/5  # 1°C difference = 1.8°F difference
        logging.debug(f"v3.20.1: Converted delta from {max_delta:.2f}°C to {max_delta_original_unit:.2f}°F")
    else:
        max_delta_original_unit = max_delta
    
    return is_high_delta, max_delta_original_unit, flagged


def validate_spot_geometry(spot_data: List[Dict], class_id: int,
                           bbox: Optional[Tuple] = None
                           ) -> Tuple[bool, float, str, List[str]]:
    """
        v3.30.1.10 FIX #12: Added missing validate_spot_geometry function.
        Validates spatial distribution and count of detected spot meters against the
    """
    warnings_out: List[str] = []
    expected = get_expected_spot_count(class_id)
    detected = len(spot_data)

    # Hard fail: nothing detected at all
    if detected == 0:
        return False, 0.0, f"No spots detected (expected={expected})", []

    # Count mismatch – log but treat as soft warning for partial results
    count_ok = (detected >= expected)
    if not count_ok:
        warnings_out.append(
            f"Spot count mismatch: detected={detected}, expected={expected}"
        )

    # Spatial spread check – require at least some separation between spots
    spread_ok = True
    if detected >= 2:
        xs = [s.get("x", 0) for s in spot_data]
        ys = [s.get("y", 0) for s in spot_data]
        x_spread = max(xs) - min(xs)
        y_spread = max(ys) - min(ys)
        if x_spread < 2 and y_spread < 2:
            spread_ok = False
            warnings_out.append("All spots are nearly co-located (spread < 2px)")

    is_valid = count_ok and spread_ok
    confidence = 1.0 if is_valid else max(0.1, detected / max(expected, 1))
    report = (
        f"Geometry {'VALID' if is_valid else 'INVALID'}: "
        f"detected={detected}/{expected}, spread_ok={spread_ok}"
    )
    return is_valid, confidence, report, warnings_out


class Rectangle:
    """ENHANCED: Draggable rectangle with corner handles and body movement."""
    def __init__(self, center_x, center_y, width=15, height=20):
        self.center_x = center_x
        self.center_y = center_y
        self.width = width
        self.height = height
        self.selected_handle = None  # None or 'tl', 'tr', 'bl', 'br'
        
    def get_bbox(self):
        """Return bounding box coordinates (x1, y1, x2, y2)."""
        x1 = int(self.center_x - self.width / 2)
        y1 = int(self.center_y - self.height / 2)
        x2 = int(self.center_x + self.width / 2)
        y2 = int(self.center_y + self.height / 2)
        return x1, y1, x2, y2
    
    def get_handles(self):
        """Return corner handle positions."""
        x1, y1, x2, y2 = self.get_bbox()
        return {
            'tl': (x1, y1),
            'tr': (x2, y1),
            'bl': (x1, y2),
            'br': (x2, y2)
        }
    
    def hit_test_handle(self, x, y, threshold=8):
        """Check if click is near a corner handle."""
        handles = self.get_handles()
        for name, (hx, hy) in handles.items():
            if abs(x - hx) <= threshold and abs(y - hy) <= threshold:
                return name
        return None
    
    def hit_test_body(self, x, y):
        """ENHANCEMENT: Check if click is inside rectangle body (for dragging)."""
        x1, y1, x2, y2 = self.get_bbox()
        margin = 8  # Corner handle size
        
        # Inside box but not on corner
        if x1 + margin < x < x2 - margin and y1 + margin < y < y2 - margin:
            return True
        return False
    
    def update_handle(self, handle_name, new_x, new_y):
        """Update rectangle by dragging a corner handle."""
        x1, y1, x2, y2 = self.get_bbox()
        
        if handle_name == 'tl':
            x1, y1 = new_x, new_y
        elif handle_name == 'tr':
            x2, y1 = new_x, new_y
        elif handle_name == 'bl':
            x1, y2 = new_x, new_y
        elif handle_name == 'br':
            x2, y2 = new_x, new_y
        
        # Ensure minimum size
        if x2 - x1 < 10:
            if handle_name in ['tl', 'bl']:
                x1 = x2 - 10
            else:
                x2 = x1 + 10
        if y2 - y1 < 10:
            if handle_name in ['tl', 'tr']:
                y1 = y2 - 10
            else:
                y2 = y1 + 10
        
        # Update center and size
        self.center_x = (x1 + x2) / 2
        self.center_y = (y1 + y2) / 2
        self.width = x2 - x1
        self.height = y2 - y1
    
    def move(self, dx, dy):
        """ENHANCEMENT: Move rectangle by offset."""
        self.center_x += dx
        self.center_y += dy
    
    def duplicate(self, offset_x=20, offset_y=20):
        """Create a duplicate rectangle with offset."""
        return Rectangle(
            self.center_x + offset_x,
            self.center_y + offset_y,
            self.width,
            self.height
        )


