class ThermalEditor(tk.Toplevel):
    """ENHANCED: Thermal annotation editor with improved UI."""
    def __init__(self, master, img_path, temp_dir, callback, meta=None):
        super().__init__(master)
        
        self.img_path = img_path  # ENHANCEMENT: Store for window title updates
        self.callback = callback
        self.meta = meta or {}
        self.points = []
        self.rectangles = []
        self.current_rect = None
        self.dragging_handle = False
        self.dragging_body = False  # ENHANCEMENT: Track body dragging
        self.drag_start_x = None  # ENHANCEMENT: For body dragging
        self.drag_start_y = None
        self.scale = 1.0
        self.pan_x = self.pan_y = 0
        self.annotation_mode = 'rectangle'
        self.rect_start = None
        self.rect_current = None
        
        # v3.25.1 FIX #5: Dynamic spot limits based on class and filename
        # Detect class from filename to set appropriate spot limit
        self.detected_class_id = get_class_from_filename(Path(img_path).name)
        self.max_spots = self._get_max_spots_for_image(img_path)
        logging.info(f"Annotation editor: class_id={self.detected_class_id}, max_spots={self.max_spots}")
        
        # ENHANCEMENT: Default preset sizes
        self.rect_width_default = 15
        self.rect_height_default = 20
        
        # ENHANCEMENT: Improved window title
        self.title(f"Thermal Annotation Editor - Rectangle Mode: {Path(img_path).name}")
        self.geometry("1024x850")  # ENHANCEMENT: Taller for new controls
        self.configure(bg="#1e1e1e")

        # ================================================================
        # CRITICAL PIPELINE SEPARATION v3.19.0 (TODO-001)
        # ================================================================
        # Load TWO versions of the thermal data:
        # 
        # 1. self.raw (AUTHORITATIVE SOURCE):
        #    - Raw thermal pixel values from FLIR file
        #    - This is the GROUND TRUTH for all temperature measurements
        #    - Annotations are saved relative to THIS (not display)
        #    - ✓ Used for: Temperature extraction, training coordinates
        # 
        # 2. self.display (VISUAL UI ONLY):
        #    - Colored/contrasted thermal image for human viewing
        #    - Used ONLY for annotation UI visualization
        #    - ❌ NEVER used for training, detection, or measurement
        #    - This is a throw-away display buffer
        # 
        # CRITICAL RULE: Annotations are stored as (x,y) coordinates
        # relative to self.raw dimensions, NOT self.display
        # ================================================================
        self.display, self.raw = DataHandler.load_thermal(img_path.stem, temp_dir)
        if self.raw is None:
            messagebox.showerror("Error", f"Failed to load thermal data for {img_path.name}")
            self.destroy()
            return

        # ENHANCED v3.19.0: Log image properties for annotation validation
        # Confirms image dimensions and data integrity between annotation and export
        logging.info(f"Annotation editor loaded: {img_path.name}")
        logging.info(f"  - DISPLAY (UI only): shape={self.display.shape}, dtype={self.display.dtype}, mean={np.mean(self.display):.2f}")
        logging.info(f"  - RAW (authoritative): shape={self.raw.shape}, dtype={self.raw.dtype}, mean={np.mean(self.raw):.2f}")
        logging.info(f"  - Annotations will be saved relative to RAW dimensions: {self.raw.shape[:2]}")
        
        self.img_disp = Image.fromarray(cv2.cvtColor(self.display, cv2.COLOR_BGR2RGB))
        self.im_w, self.im_h = self.img_disp.size

        # TODO-20 FIX v3.30.1.15: Load existing annotations BEFORE building UI.
        # Previously self.points and self.rectangles were always [] on open,
        # forcing the reviewer to re-place all spots from scratch even when a
        # valid JSON sidecar already existed for the image.
        #
        # Load strategy (priority order):
        #   1. Same directory as img_path (<stem>.json)
        #   2. detection_jsons/ subdirectory one level up (canonical v3.30.19+)
        #   3. jsons/ subdirectory one level up (legacy fallback)
        #   4. sidecar written by batch detection (<stem>_visual.json → spotmeters key)
        self._load_existing_annotations()

        self._create_ui()
        self._setup_bindings()
        self.scale = min(1000 / self.im_w, 700 / self.im_h)
        self.redraw()

    def _get_max_spots_for_image(self, img_path):
        """
            v3.25.1: Determine maximum allowed spots based on image class and filename.
            Returns:
        """
        filename_lower = str(img_path).lower()
        
        # Special case: HV/Inverter images (future feature - allow more spots)
        # TODO: When multiclass system is fully implemented, make this configurable
        if any(keyword in filename_lower for keyword in ['hv', 'inverter', 'inv']):
            # For now, set to 10 (expandable in future)
            # NOTE: This is a placeholder for future multiclass implementation
            logging.info(f"HV/Inverter image detected: {Path(img_path).name} - allowing up to 10 spots")
            return 10  # Future: make this configurable or unlimited
        
        # Class-based limits
        if self.detected_class_id == 2:  # TBX (Terminal Box)
            return 2  # Only 2 spots for Terminal Box
        elif self.detected_class_id == 1:  # LBD_Type_2 (Midpoint/Gaia)
            return 6  # 6 spots for 3x2 grid
        else:  # LBD_Type_1 or LBD_Type_3
            return 4  # Default 4 spots for 2x2 grid


    def _load_existing_annotations(self) -> None:
        """sidecar so the editor opens with current spots visible and editable rather than blank."""
        img_path = Path(self.img_path)
        stem = img_path.stem

        # Candidate sidecar paths in priority order.
        # qc_jsons/ checked first — QC edits open with the corrected spot positions.
        candidates = [
            img_path.parent.parent / "qc_jsons"         / f"{stem}.json",  # QC edit wins
            img_path.parent        / "qc_jsons"          / f"{stem}.json",  # QC edit sibling
            img_path.parent / f"{stem}.json",
            img_path.parent.parent / "detection_jsons"  / f"{stem}.json",  # canonical v3.30.19+
            img_path.parent.parent / "jsons"            / f"{stem}.json",  # legacy fallback
            img_path.parent / f"{stem}_visual.json",
        ]

        for sidecar in candidates:
            if not sidecar.exists():
                continue
            try:
                with open(sidecar, "r", encoding="utf-8") as fh:
                    data = json.load(fh)

                # --- spotmeter-format sidecar (written by batch detection) ---
                if "spotmeters" in data:
                    for sp in data["spotmeters"]:
                        x, y = sp.get("x"), sp.get("y")
                        if x is not None and y is not None:
                            self.points.append((int(x), int(y)))
                    logging.info(
                        f"ThermalEditor pre-loaded {len(self.points)} spots "
                        f"from spotmeter sidecar: {sidecar.name}"
                    )
                    return  # Done — use first valid sidecar found

                # --- annotation-format sidecar (written by SpotMeterManager) ---
                spot_list = data.get("spot_meters", [])
                rect_list = data.get("rectangles", [])

                # Rebuild point list
                for sp in spot_list:
                    x = sp.get("x", sp.get("coordinates", {}).get("x"))
                    y = sp.get("y", sp.get("coordinates", {}).get("y"))
                    if x is not None and y is not None:
                        self.points.append((int(x), int(y)))

                # Rebuild rectangle list — AnnotationRect compatible
                for rd in rect_list:
                    x1 = rd.get("x1", rd.get("coordinates", {}).get("x1"))
                    y1 = rd.get("y1", rd.get("coordinates", {}).get("y1"))
                    x2 = rd.get("x2", rd.get("coordinates", {}).get("x2"))
                    y2 = rd.get("y2", rd.get("coordinates", {}).get("y2"))
                    if all(v is not None for v in [x1, y1, x2, y2]):
                        try:
                            # Use Rectangle class (the actual ThermalEditor rect class).
                            # Rectangle(center_x, center_y, width, height)
                            cx = (int(x1) + int(x2)) / 2
                            cy = (int(y1) + int(y2)) / 2
                            w  = abs(int(x2) - int(x1))
                            h  = abs(int(y2) - int(y1))
                            new_rect = Rectangle(cx, cy, w, h)
                            self.rectangles.append(new_rect)
                        except Exception as re_err:
                            logging.debug(f"Could not rebuild rect from JSON: {re_err}")

                if self.points or self.rectangles:
                    logging.info(
                        f"ThermalEditor pre-loaded {len(self.points)} spots, "
                        f"{len(self.rectangles)} rects from: {sidecar.name}"
                    )
                    return  # Done — use first valid sidecar found

            except Exception as load_err:
                logging.debug(
                    f"Could not pre-load annotations from {sidecar.name}: {load_err}"
                )

        logging.debug(f"ThermalEditor: no existing annotations found for {img_path.name}")

