    def _get_active_theme(self) -> dict:
        """Return the currently active theme dict based on CFG["UI"]["Theme"]."""
        saved = CFG.get("UI", "Theme", "dark").strip().lower()
        return self._LIGHT_THEME if saved == "light" else self._DARK_THEME

    def toggle_theme(self) -> None:
        """TODO-029: Toggle between dark and light themes."""
        current = CFG.get("UI", "Theme", "dark").strip().lower()
        new_name = "light" if current == "dark" else "dark"
        CFG.set("UI", "Theme", new_name)
        theme = self._LIGHT_THEME if new_name == "light" else self._DARK_THEME
        self._apply_theme_dict(theme)
        logging.info(f"TODO-029: theme switched to '{new_name}'")

    def _apply_theme_dict(self, theme: dict) -> None:
        """Apply a theme dict to ttk.Style and walk all tk widgets."""
        try:
            style = ttk.Style()
            style.configure("TNotebook",
                            background=theme["bg_primary"], borderwidth=0)
            style.configure("TNotebook.Tab",
                            background=theme["notebook_tab"],
                            foreground=theme["fg_primary"],
                            padding=[12, 8])
            style.map("TNotebook.Tab",
                      background=[("selected", theme["notebook_sel"])],
                      foreground=[("selected", theme["accent"])])
            style.configure("TProgressbar",
                            background=theme["accent"],
                            troughcolor=theme["progress_bg"],
                            borderwidth=0)
            self.configure(bg=theme["bg_primary"])
            self._walk_theme(self, theme)
        except Exception as e:
            logging.warning(f"Theme apply error: {e}")

    def _walk_theme(self, widget, theme: dict) -> None:
        """Recursively walk all child widgets and apply bg/fg where supported."""
        try:
            cls = widget.__class__.__name__
            if cls in ("Label", "Frame", "Canvas"):
                widget.configure(bg=theme["bg_secondary"])
            elif cls == "Button":
                widget.configure(bg=theme["btn_bg"], fg=theme["fg_primary"],
                                 activebackground=theme["accent"],
                                 activeforeground=theme["bg_primary"])
            elif cls in ("Entry", "Text"):
                widget.configure(bg=theme["entry_bg"], fg=theme["fg_primary"],
                                 insertbackground=theme["fg_primary"])
            elif cls == "Checkbutton":
                widget.configure(bg=theme["bg_secondary"], fg=theme["fg_primary"],
                                 selectcolor=theme["bg_card"],
                                 activebackground=theme["bg_secondary"],
                                 activeforeground=theme["fg_primary"])
            elif cls == "Radiobutton":
                widget.configure(bg=theme["bg_secondary"], fg=theme["fg_primary"],
                                 selectcolor=theme["bg_card"],
                                 activebackground=theme["bg_secondary"],
                                 activeforeground=theme["fg_primary"])
        except Exception as _cfg_err:
            # Intentional: ttk widgets or read-only widgets reject configure() — silently skip
            logging.debug(f"apply_theme widget configure: {type(widget).__name__} — {_cfg_err}")
        for child in widget.winfo_children():
            # Skip Toplevel children — they own their own theme
            if child.__class__.__name__ == "Toplevel":
                continue
            self._walk_theme(child, theme)

    def _apply_ui_colors(self):
        """v3.30.0 / TODO-028: Apply UI colors."""
        try:
            # Step 1: apply the theme palette (dark/light)
            self._apply_theme_dict(self._get_active_theme())

            # Step 2: layer the per-key color overrides from the Settings radio buttons
            tab_color = CFG.get("UI", "TabColor", "").strip()
            bg_color  = CFG.get("UI", "BGColor",  "").strip()
            if bg_color:
                self.configure(bg=bg_color)
            if tab_color or bg_color:
                style = ttk.Style()
                if tab_color:
                    style.configure("TNotebook.Tab", background=tab_color)
                if bg_color:
                    style.configure("TNotebook", background=bg_color)
            logging.info(
                f"UI theme='{CFG.get('UI','Theme','dark')}' "
                f"tab='{tab_color or '(theme)'}' bg='{bg_color or '(theme)'}'"
            )
        except Exception as e:
            logging.warning(f"Could not apply UI colors: {e}")

