        # ── [USER REQUEST v3.30.5] CRITICAL: stored as self.train_model_path_var ─
        # Must be a self attribute (not a local closure var) so that _train_thread
        # can refresh the Combobox display after training completes and overwrites
        # CFG["GENERAL"]["ModelPath"] with the output trained_model.pt path.
        # Without self.*, the UI StringVar is frozen at the pre-training value even
        # though CFG (and thus the actual model used next time) has changed → "false
        # cut": user sees old model name but the real selection has silently moved.
        self.train_model_path_var = tk.StringVar(
            value=CFG.get("GENERAL", "ModelPath", "yolo11n.pt")
        )
        # Alias for the closures in this method (browse + trace reference this name)
        model_path_var = self.train_model_path_var

