        # ─────────────────────────────────────────────────────────────────────────
        # Previous layout: one monolithic 3-column grid with 16 bare rows, plus
        # separate LabelFrames below — visually congested, no logical grouping.
        #
        # New layout (7 sections, all sharing consistent design tokens):
        #   Row A ── side-by-side: 🎯 Detection Thresholds | ⚙️ Detection Options
        #   Row B ── full-width:   📐 Temperature Unit & Spot Dimensions
        #   Row C ── full-width:   🌡 Atmospheric & Emissivity Overrides
        #   Row D ── side-by-side: 🎨 Spot Meter Appearance | 📊 Detection Performance
        #   Row E ── full-width:   📁 Folder Paths
        #   Row F ── 3-col:        🎨 UI Appearance | ⚙️ Training (→) | 📋 Report
        #
        # Design principles:
        #   • Every section is a LabelFrame with a coloured accent title.
        #   • Compact 3-col grid inside each section: [label] [control] [inline hint]
        #   • pady=3 (was 5), Entry width=8 for integers (was 20) — saves ~40% height.
        #   • Checkboxes embed the brief hint in their own text — no extra label row.
        #   • Side-by-side pairs halve vertical height for complementary settings.
        #   • All variable names, CFG keys, and callbacks are 100% unchanged.
        # ─────────────────────────────────────────────────────────────────────────
        tab_settings = tk.Frame(notebook, bg="#34495e")
        notebook.add(tab_settings, text="Settings")

        # ── Scrollable canvas container (infrastructure unchanged) ─────────────
        settings_canvas = tk.Canvas(tab_settings, bg="#34495e", highlightthickness=0)
        settings_scrollbar = tk.Scrollbar(tab_settings, orient=tk.VERTICAL,
                                          command=settings_canvas.yview)
        settings_canvas.configure(yscrollcommand=settings_scrollbar.set)
        settings_scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        settings_canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        settings_inner = tk.Frame(settings_canvas, bg="#34495e")
        settings_inner_id = settings_canvas.create_window((0, 0), window=settings_inner,
                                                           anchor="nw")

        def _on_settings_frame_configure(event):
            settings_canvas.configure(scrollregion=settings_canvas.bbox("all"))

        def _on_settings_canvas_configure(event):
            # Stretch inner frame to canvas width so it doesn't feel narrow
            settings_canvas.itemconfig(settings_inner_id, width=event.width)

        settings_inner.bind("<Configure>", _on_settings_frame_configure)
        settings_canvas.bind("<Configure>", _on_settings_canvas_configure)

        # FIX-06 v3.30.1.39: Widget-local bind — prevents triple scroll with params_canvas
        def _on_settings_mousewheel(event):
            settings_canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")

        settings_canvas.bind("<MouseWheel>", _on_settings_mousewheel)
        settings_canvas.bind("<Button-4>", lambda e: settings_canvas.yview_scroll(-1, "units"))
        settings_canvas.bind("<Button-5>", lambda e: settings_canvas.yview_scroll(1, "units"))

        # ── Design tokens ──────────────────────────────────────────────────────
        _S_BG   = "#2c3e50"            # LabelFrame interior background
        _S_TAB  = "#34495e"            # Tab / row-frame background
        _S_FG   = "white"              # Primary label foreground
        _S_HINT = "#95a5a6"            # Muted help / hint text
        _S_DARK = "#1a252f"            # Entry input background
        _S_HEAD = ("Arial", 10, "bold")   # LabelFrame title font
        _S_LBL  = ("Arial", 9)            # Row label font
        _S_HELP = ("Arial", 8)            # Inline hint font
        _S_SAVE = "#27ae60"            # Save button green
        _S_WARN = "#f39c12"            # "takes effect at…" amber hint

        def _lf(parent, title, accent, **kw):
            """Return a consistently-styled LabelFrame."""
            return tk.LabelFrame(parent, text=title, bg=_S_BG, fg=accent,
                                 font=_S_HEAD, padx=8, pady=6, **kw)

        def _hrow(frame, lbl_text, ctrl_widget, hint_text, row):
            """Add a compact label | control | inline-hint row to a LabelFrame grid."""
            tk.Label(frame, text=lbl_text, bg=_S_BG, fg=_S_FG,
                     font=_S_LBL, anchor="e"
                     ).grid(row=row, column=0, sticky="e", padx=(8, 4), pady=3)
            ctrl_widget.grid(row=row, column=1, sticky="w", padx=4, pady=3)
            tk.Label(frame, text=hint_text, bg=_S_BG, fg=_S_HINT,
                     font=_S_HELP, anchor="w"
                     ).grid(row=row, column=2, sticky="w", padx=(2, 8), pady=3)

        def _entry(parent, var, w=8):
            """Return a dark-themed Entry bound to var."""
            return tk.Entry(parent, textvariable=var, width=w,
                            bg=_S_DARK, fg=_S_FG, insertbackground=_S_FG,
                            relief=tk.FLAT, highlightthickness=1,
                            highlightbackground="#3d566e", highlightcolor="#3498db")

        def _cb(parent, text, var, on_cmd):
            """Return a styled Checkbutton with hint embedded in label text."""
            return tk.Checkbutton(parent, text=text, variable=var,
                                  onvalue="True", offvalue="False",
                                  bg=_S_BG, fg=_S_FG, selectcolor=_S_DARK,
                                  activebackground=_S_BG, activeforeground=_S_FG,
                                  font=_S_LBL, command=on_cmd)

        # ── Shared save-feedback helpers ───────────────────────────────────────
        # CFG.set() writes to settings.ini atomically on every call, so settings
        # are always persisted.  These helpers give the user visible confirmation
        # and explain when each group of settings will take effect.

        # _saved_label_var: StringVar that drives the top-of-settings status strip.
        _saved_label_var = tk.StringVar(value="")

        def _flash_saved(msg: str = "✅  Saved") -> None:
            """Flash a confirmation message in the header strip for 3 s."""
            _saved_label_var.set(msg)
            settings_inner.after(3000, lambda: _saved_label_var.set(""))

        def _effect_popup(title: str, body: str) -> None:
            """Show a dark-themed, non-blocking Toplevel describing when changes"""
            win = tk.Toplevel(settings_inner)
            win.title(title)
            win.configure(bg="#1a252f")
            win.resizable(False, False)
            win.grab_set()
            # Title bar
            tk.Label(win, text=title, bg="#0f3460", fg="#3498db",
                     font=("Arial", 11, "bold"), anchor="w",
                     padx=12, pady=8
                     ).pack(fill=tk.X)
            # Body
            tk.Label(win, text=body, bg="#1a252f", fg="#ecf0f1",
                     font=("Arial", 9), justify=tk.LEFT,
                     padx=16, pady=12, wraplength=460
                     ).pack(fill=tk.X)
            tk.Button(win, text="  OK  ", command=win.destroy,
                      bg=_S_SAVE, fg="white",
                      font=("Arial", 9, "bold"), padx=12, pady=4,
                      relief=tk.FLAT
                      ).pack(pady=(0, 14))
            win.update_idletasks()
            pw = win.winfo_reqwidth()
            ph = win.winfo_reqheight()
            px = self.winfo_rootx() + (self.winfo_width()  - pw) // 2
            py = self.winfo_rooty() + (self.winfo_height() - ph) // 2
            win.geometry(f"+{max(0, px)}+{max(0, py)}")

        def _save_section_btn(parent, label: str, on_save,
                              info_title: str, info_body: str,
                              pack_kw: dict | None = None,
                              grid_kw: dict | None = None,
                              effect_text: str = "") -> tk.Button:
            """
            Return a green  💾 Save  button that:
              1. Calls on_save() to re-persist the section values
              2. Flashes the header strip confirmation
              3. Opens the themed effect-info popup
            Caller grids or packs the returned button.
            """
            def _click():
                on_save()
                _flash_saved(f"✅  {label} saved")
                _effect_popup(info_title, info_body)

            btn = tk.Button(parent, text=f"💾  Save {label}",
                            command=_click,
                            bg=_S_SAVE, fg="white",
                            font=("Arial", 9, "bold"),
                            padx=10, pady=4, relief=tk.FLAT, cursor="hand2")
            if grid_kw is not None:
                btn.grid(**grid_kw)
            elif pack_kw is not None:
                btn.pack(**pack_kw)
            if effect_text:
                eff_lbl_parent = parent
                eff_lbl = tk.Label(eff_lbl_parent, text=effect_text,
                                   bg=_S_BG, fg=_S_WARN, font=_S_HELP)
                if grid_kw is not None:
                    gk2 = dict(grid_kw)
                    gk2["row"] = gk2.get("row", 0) + 1
                    eff_lbl.grid(**gk2)
                else:
                    eff_lbl.pack(anchor="w", padx=8, pady=(0, 4))
            return btn

        # ── Auto-save indicator strip (top of settings panel) ─────────────────
        # Shows "All settings auto-save" info plus the _flash_saved() output.
        _hdr = tk.Frame(settings_inner, bg="#0f3460", height=26)
        _hdr.pack(fill=tk.X, padx=0, pady=(0, 6))
        _hdr.pack_propagate(False)
        tk.Label(_hdr,
                 text="🔒  Settings auto-save on change.  "
                      "Use  💾 Save  buttons to see exactly when each group takes effect.",
                 bg="#0f3460", fg="#3498db", font=("Arial", 8), anchor="w"
                 ).pack(side=tk.LEFT, padx=10, fill=tk.Y)
        tk.Label(_hdr, textvariable=_saved_label_var,
                 bg="#0f3460", fg=_S_SAVE,
                 font=("Arial", 8, "bold"), anchor="e"
                 ).pack(side=tk.RIGHT, padx=10, fill=tk.Y)

        # ══════════════════════════════════════════════════════════════════════
        # ROW A — Side-by-side: Detection Thresholds  |  Detection Options
        # ══════════════════════════════════════════════════════════════════════
        _row_a = tk.Frame(settings_inner, bg=_S_TAB)
        _row_a.pack(fill=tk.X, padx=10, pady=(10, 4))
        _row_a.columnconfigure(0, weight=1)
        _row_a.columnconfigure(1, weight=1)

        # ── Left: Detection Thresholds ─────────────────────────────────────
        _thresh = _lf(_row_a, "🎯 Detection Thresholds", "#3498db")
        _thresh.grid(row=0, column=0, sticky="nsew", padx=(0, 4))
        _thresh.columnconfigure(2, weight=1)

        _thresh_rows = [
            ("Conf High:",   "DETECTION", "ConfHigh",   "0.6", "0.0–1.0  upper acceptance gate"),
            ("Conf Low:",    "DETECTION", "ConfLow",    "0.3", "0.0–1.0  low-confidence retry gate"),
            ("Percentile:",  "DETECTION", "Percentile", "95",  "80–99  hot-spot temperature percentile"),
            ("Max Delta:",   "DETECTION", "MaxDelta",   "30",  "°C max temperature spread between spots"),
        ]
        # Collect vars so the Save button can re-persist them all at once.
        # FIX-SETTINGS-01: bind FocusOut+Return instead of trace_add("write").
        # trace_add fires on every keystroke — it saves partial values like "0."
        # or "" (during clear) to settings.ini.  Binding to FocusOut and Return
        # means only complete, validated values are written.
        _thresh_entry_vars: list[tuple] = []   # (section, key, StringVar)
        for _tr, (_lbl, _sec, _key, _def, _hint) in enumerate(_thresh_rows):
            _v = tk.StringVar(value=CFG.get(_sec, _key, _def))
            _thresh_entry_vars.append((_sec, _key, _v))
            def _make_thresh_commit(s=_sec, k=_key, v=_v):
                def _commit(event=None):
                    try:
                        float(v.get().strip())   # validate — must be a number
                        CFG.set(s, k, v.get().strip())
                    except ValueError:
                        pass   # ignore mid-type fragments (e.g. "0.", "-")
                return _commit
            _tc = _make_thresh_commit()
            _te = _entry(_thresh, _v)
            _te.bind("<FocusOut>", _tc)
            _te.bind("<Return>",   _tc)
            _hrow(_thresh, _lbl, _te, _hint, _tr)

        # Adaptive Delta: checkbox on its own row (spans all columns)
        _adap_var = tk.StringVar(value=CFG.get("DETECTION", "AdaptiveDelta", "True"))
        _cb(_thresh,
            "Adaptive Delta  — auto-adjusts threshold to per-image statistics",
            _adap_var,
            lambda: CFG.set("DETECTION", "AdaptiveDelta", _adap_var.get())
            ).grid(row=4, column=0, columnspan=3, sticky="w", padx=8, pady=(4, 2))

        # ── Right: Detection Options ───────────────────────────────────────
        _opts = _lf(_row_a, "⚙️ Detection Options", "#3498db")
        _opts.grid(row=0, column=1, sticky="nsew", padx=(4, 0))
        _opts.columnconfigure(2, weight=1)

        cache_var = tk.StringVar(value=CFG.get("DETECTION", "UseCache", "True"))
        _cb(_opts,
            "Use Metadata Cache  (speeds up re-runs on the same image set)",
            cache_var,
            lambda: CFG.set("DETECTION", "UseCache", cache_var.get())
            ).grid(row=0, column=0, columnspan=3, sticky="w", padx=8, pady=3)

        filter_var = tk.StringVar(value=CFG.get("DETECTION", "EnableInferenceFilter", "True"))
        _cb(_opts,
            "Inference Filtering  (geometry-based false-positive suppression)",
            filter_var,
            lambda: CFG.set("DETECTION", "EnableInferenceFilter", filter_var.get())
            ).grid(row=1, column=0, columnspan=3, sticky="w", padx=8, pady=3)

        multiclass_var = tk.StringVar(value=CFG.get("DETECTION", "EnableMultiClass", "False"))
        multiclass_check = _cb(
            _opts,
            "Multi-Class System  (Spot / Midpoint / Breaker / TBX detection)",
            multiclass_var,
            None  # command wired below after combo is created
        )
        multiclass_check.grid(row=2, column=0, columnspan=3, sticky="w", padx=8, pady=3)

        # Multi-Class Mode combobox — indented, disabled when multi-class is off
        tk.Label(_opts, text="Mode:", bg=_S_BG, fg=_S_FG, font=_S_LBL
                 ).grid(row=3, column=0, sticky="e", padx=(24, 4), pady=3)
        _MC_MODE_OPTIONS = [
            "LBD_and_TBX", "LBD_only", "TBX_only",
            "Inverters_HV", "Inverters_Fuse", "Inverters_Contactor", "Inverters_All",
        ]
        mc_mode_var = tk.StringVar(value=CFG.get("DETECTION", "MultiClassMode", "LBD_and_TBX"))
        mc_mode_combo = ttk.Combobox(_opts, textvariable=mc_mode_var,
                                     values=_MC_MODE_OPTIONS, state="readonly", width=18)
        mc_mode_combo.grid(row=3, column=1, sticky="w", padx=4, pady=3)
        mc_mode_combo.bind("<<ComboboxSelected>>",
                           lambda _e: CFG.set("DETECTION", "MultiClassMode", mc_mode_var.get()))
        tk.Label(_opts, text="LBD=4 spots  TBX=2 spots  Inverter=coming soon",
                 bg=_S_BG, fg=_S_HINT, font=_S_HELP
                 ).grid(row=3, column=2, sticky="w", padx=(2, 8), pady=3)

        def _on_multiclass_toggle(_var=multiclass_var, _combo=mc_mode_combo):
            """Toggle MultiClassMode combobox alongside the checkbox."""
            enabled = _var.get() == "True"
            CFG.set("DETECTION", "EnableMultiClass", _var.get())
            _combo.configure(state="readonly" if enabled else "disabled")

        multiclass_check.configure(command=_on_multiclass_toggle)
        # Set initial combo state
        if CFG.get("DETECTION", "EnableMultiClass", "False") != "True":
            mc_mode_combo.configure(state="disabled")

        save_detection_var = tk.StringVar(value=CFG.get("DETECTION", "SaveDetectionInput", "False"))
        _cb(_opts,
            "Save Detection Input  (write CLAHE grayscale YOLO inputs to disk)",
            save_detection_var,
            lambda: CFG.set("DETECTION", "SaveDetectionInput", save_detection_var.get())
            ).grid(row=4, column=0, columnspan=3, sticky="w", padx=8, pady=3)

        # ── Glint Detection toggle (FIX-GLINT-UI-01 v3.30.24.7) ─────────────────
        # Disabled by default — see FIX-GLINT-01 comment at DETECTION defaults.
        # Enable only when close-range metallic specular reflections are present
        # and confirmed NOT to be the measurement target.
        glint_var = tk.StringVar(value=CFG.get("DETECTION", "EnableGlintDetection", "False"))
        _cb(_opts,
            "Enable Glint Detection  (mask specular reflections on metal surfaces)",
            glint_var,
            lambda: CFG.set("DETECTION", "EnableGlintDetection", glint_var.get())
            ).grid(row=5, column=0, columnspan=3, sticky="w", padx=8, pady=3)
        tk.Label(
            _opts,
            text="⚠  Off by default — can mask genuine hot-spots and cause −5…−100 °C errors",
            bg=_S_BG, fg=_S_HINT, font=_S_HELP,
        ).grid(row=5, column=0, columnspan=3, sticky="w", padx=(28, 8), pady=(0, 3))

        # FIX-SETTINGS-01: NMS and MaxWorkers — FocusOut/Return binding only.
        # FIX v3.30.1.21: correct default 0.55 (was stale 0.45 in earlier builds)
        nms_var = tk.StringVar(value=CFG.get("DETECTION", "NMS_IOU_Threshold", "0.55"))
        nms_entry = _entry(_opts, nms_var)
        def _nms_commit(event=None):
            try:
                v = float(nms_var.get().strip())
                if 0.0 < v <= 1.0:
                    CFG.set("DETECTION", "NMS_IOU_Threshold", f"{v:.4f}")
            except ValueError:
                pass
        nms_entry.bind("<FocusOut>", _nms_commit)
        nms_entry.bind("<Return>",   _nms_commit)
        _hrow(_opts, "NMS IOU:", nms_entry, "0.3–0.7  non-maximum suppression overlap threshold", 6)

        _mw_default = str(max(1, min((cpu_count() or 1) - 1, 8)))
        _mw_var = tk.StringVar(value=CFG.get("DETECTION", "MaxWorkers", _mw_default))
        _mw_entry = _entry(_opts, _mw_var)
        def _mw_commit(event=None):
            try:
                v = int(_mw_var.get().strip())
                if v >= 1:
                    CFG.set("DETECTION", "MaxWorkers", str(v))
            except ValueError:
                pass
        _mw_entry.bind("<FocusOut>", _mw_commit)
        _mw_entry.bind("<Return>",   _mw_commit)
        _hrow(_opts, "Max Workers:", _mw_entry, "CPU workers for parallel preprocessing (CPUs−1, max 8)", 7)

        # ── ROW A — Combined Save button (Detection Thresholds + Options) ──────
        # Both cards share the same effect boundary: the NEXT batch detection run.
        _row_a_foot = tk.Frame(_row_a, bg=_S_TAB)
        _row_a_foot.grid(row=1, column=0, columnspan=2, sticky="w",
                         padx=4, pady=(2, 6))

        def _save_detection_all():
            """Re-persist all Detection Threshold + Option values (belt-and-suspenders)."""
            for _s, _k, _v in _thresh_entry_vars:
                try:
                    float(_v.get().strip())
                    CFG.set(_s, _k, _v.get().strip())
                except ValueError:
                    pass
            CFG.set("DETECTION", "AdaptiveDelta",         _adap_var.get())
            CFG.set("DETECTION", "UseCache",              cache_var.get())
            CFG.set("DETECTION", "EnableInferenceFilter", filter_var.get())
            CFG.set("DETECTION", "EnableMultiClass",      multiclass_var.get())
            CFG.set("DETECTION", "MultiClassMode",        mc_mode_var.get())
            CFG.set("DETECTION", "SaveDetectionInput",    save_detection_var.get())
            CFG.set("DETECTION", "EnableGlintDetection",  glint_var.get())
            _nms_commit()
            _mw_commit()

        tk.Button(
            _row_a_foot,
            text="💾  Save Detection Settings",
            command=lambda: [
                _save_detection_all(),
                _flash_saved("✅  Detection settings saved"),
                _effect_popup(
                    "Detection Settings — When do these take effect?",
                    "✅  Saved to settings.ini.\n\n"
                    "📋  WHEN DOES THIS TAKE EFFECT?\n\n"
                    "• ALL changes apply to the NEXT batch detection run.\n"
                    "  Already-processed images in visual_annotated/ are NOT affected.\n\n"
                    "• ConfHigh / ConfLow  →  tighten or loosen the acceptance gate.\n"
                    "  Higher ConfHigh = fewer false positives.\n"
                    "  Lower ConfLow = fewer borderline retries.\n\n"
                    "• MaxDelta  →  detections flagged High-Delta in the report when\n"
                    "  the hottest and coolest spot differ by more than this.\n\n"
                    "• NMS IOU / MaxWorkers  →  no restart needed.\n\n"
                    "• Multi-Class Mode  →  changes which YOLO model weights are used;\n"
                    "  make sure the matching model is loaded in the Model panel."
                ),
            ],
            bg=_S_SAVE, fg="white", font=("Arial", 9, "bold"),
            padx=10, pady=4, relief=tk.FLAT, cursor="hand2"
        ).pack(side=tk.LEFT, padx=(0, 10))

        tk.Label(_row_a_foot,
                 text="Takes effect on the NEXT detection run  —  no restart needed",
                 bg=_S_TAB, fg=_S_WARN, font=_S_HELP
                 ).pack(side=tk.LEFT)

        # ══════════════════════════════════════════════════════════════════════
        # ROW B — Temperature Unit & Spot Dimensions (full width)
        # ══════════════════════════════════════════════════════════════════════
        _dims = _lf(settings_inner, "📐 Temperature Unit & Spot Dimensions", "#1abc9c")
        _dims.pack(fill=tk.X, padx=10, pady=4)
        _dims.columnconfigure(2, weight=1)

        # Temperature unit (row 0) — radio buttons inline
        tk.Label(_dims, text="Temperature Unit:", bg=_S_BG, fg=_S_FG,
                 font=_S_LBL, anchor="e"
                 ).grid(row=0, column=0, sticky="e", padx=(8, 4), pady=3)
        unit_var = tk.StringVar(value=CFG.get("GENERAL", "TempUnit", "C"))
        _unit_row = tk.Frame(_dims, bg=_S_BG)
        _unit_row.grid(row=0, column=1, sticky="w", padx=4, pady=3)
        tk.Radiobutton(_unit_row, text="°C  Celsius", variable=unit_var, value="C",
                       bg=_S_BG, fg=_S_FG, selectcolor=_S_DARK, font=_S_LBL,
                       activebackground=_S_BG, activeforeground=_S_FG,
                       command=lambda: CFG.set("GENERAL", "TempUnit", "C")
                       ).pack(side=tk.LEFT, padx=(0, 10))
        tk.Radiobutton(_unit_row, text="°F  Fahrenheit", variable=unit_var, value="F",
                       bg=_S_BG, fg=_S_FG, selectcolor=_S_DARK, font=_S_LBL,
                       activebackground=_S_BG, activeforeground=_S_FG,
                       command=lambda: CFG.set("GENERAL", "TempUnit", "F")
                       ).pack(side=tk.LEFT)
        tk.Label(_dims, text="Note: MaxDelta in °F ≈ 1.8× the °C value",
                 bg=_S_BG, fg=_S_HINT, font=_S_HELP, anchor="w"
                 ).grid(row=0, column=2, sticky="w", padx=(2, 8), pady=3)

        # Spot Box Size — temperature-sampling window (row 1)
        # v3.30.1.37: square box centred on each spot; side = SpotBoxSize px.
        # FIX-SETTINGS-01: FocusOut/Return instead of trace_add (avoids mid-type saves).
        sbs_var = tk.StringVar(value=CFG.get("DETECTION", "SpotBoxSize", "16"))
        sbs_entry = _entry(_dims, sbs_var)
        def _sbs_commit(event=None):
            try:
                v = int(sbs_var.get().strip())
                if v > 0:
                    CFG.set("DETECTION", "SpotBoxSize", str(v))
            except ValueError:
                pass
        sbs_entry.bind("<FocusOut>", _sbs_commit)
        sbs_entry.bind("<Return>",   _sbs_commit)
        _hrow(_dims, "Spot Box Size (px):", sbs_entry,
              "16×16 px temp-sampling window per spot (increase for noisy sensors)", 1)

        # Detection Box Width (YOLO label width — must match training) (row 2)
        # v3.30.1.41: BoxWidth = what YOLO learns; SpotBoxSize = inner crop for temp only.
        bw_var = tk.StringVar(value=CFG.get("DETECTION", "BoxWidth", "15"))
        bw_entry = _entry(_dims, bw_var)
        def _bw_commit(event=None):
            try:
                v = int(bw_var.get().strip())
                if v > 0:
                    CFG.set("DETECTION", "BoxWidth", str(v))
            except ValueError:
                pass
        bw_entry.bind("<FocusOut>", _bw_commit)
        bw_entry.bind("<Return>",   _bw_commit)
        _hrow(_dims, "Box Width (px):", bw_entry,
              "YOLO label width — must match training (default 15; upgrade to 40 = re-export)", 2)

        # Detection Box Height (YOLO label height — must match training) (row 3)
        bh_var = tk.StringVar(value=CFG.get("DETECTION", "BoxHeight", "25"))
