    def preview_detection_input(self):
        """Show side-by-side comparison of:"""
        # Select folder with thermal images
        folder = filedialog.askdirectory(title="Select Folder with Thermal Images")
        if not folder:
            return
        
        folder_path = Path(folder)
        jpg_files = list(folder_path.glob("*.[jJ][pP]*[gG]"))
        
        if not jpg_files:
            messagebox.showinfo("No Images", "No JPG images found in folder.")
            return
        
        # Select a random image for preview
        # FIX v3.30.9 BUG-2: Removed redundant inline 'import random' — already at module level
        img_path = random.choice(jpg_files)
        
        try:
            self.status_var.set(f"Generating preview for {img_path.name}...")
            self.update()
            
            # Extract thermal data
            meta_dict, temp_dir = extract_data(folder_path, use_cache=False)
            
            if img_path.stem not in meta_dict:
                messagebox.showerror("Error", f"Could not extract thermal data from {img_path.name}")
                return
            
            meta = meta_dict[img_path.stem]
            
            # Load raw thermal
            raw = cv2.imread(str(temp_dir / f"{img_path.stem}_t.tiff"), cv2.IMREAD_UNCHANGED)
            if raw is None:
                messagebox.showerror("Error", f"Could not load thermal TIFF for {img_path.name}")
                return
            
            # Byte-order correction: guard 1 (max<7000) + guard 2 (mean>32000).
            # Guard 2 catches FLIR cameras whose RawThermalImage is a big-endian PNG
            # blob — exiftool writes it verbatim with .tiff extension, cv2 reads it
            # as uint16 big-endian (44..65355 mean~33347) instead of correct LE values.
            if raw.dtype == np.uint16 and (raw.max() < 7000 or raw.mean() > 32000):
                raw = raw.byteswap()  # byteswap() only — .view(newbyteorder) would cancel the swap
            
            raw = raw.astype(np.float32)
            
            # Generate display version (colored, auto-contrast)
            display_img = apply_thermal_window(raw, auto_window=True, palette="INFERNO")
            
            # Generate model input (CLAHE grayscale)
            model_input = self._prepare_yolo_input(raw)
            
            # Create comparison window
            preview_window = tk.Toplevel(self)
            preview_window.title(f"Preview: Display vs Model Input - {img_path.name}")
            preview_window.geometry("1400x700")
            preview_window.configure(bg="#1e1e1e")
            
            # Title
            title_label = tk.Label(
                preview_window,
                text=f"Preprocessing Comparison: {img_path.name}",
                bg="#1e1e1e", fg="white", font=("Arial", 14, "bold")
            )
            title_label.pack(pady=10)
            
            # Create frame for side-by-side display
            comparison_frame = tk.Frame(preview_window, bg="#1e1e1e")
            comparison_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
            
            # Left side: Display version
            left_frame = tk.Frame(comparison_frame, bg="#2c3e50", relief=tk.RAISED, borderwidth=2)
            left_frame.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=5)
            
            tk.Label(
                left_frame,
                text="Display Version (What You See)",
                bg="#2c3e50", fg="#27ae60", font=("Arial", 12, "bold")
            ).pack(pady=5)
            
            tk.Label(
                left_frame,
                text="• Auto-contrast per-image\n• INFERNO color palette\n• For human viewing",
                bg="#2c3e50", fg="#95a5a6", font=("Arial", 9),
                justify=tk.LEFT
            ).pack(pady=5)
            
            # Convert display image for tkinter
            display_rgb = cv2.cvtColor(display_img, cv2.COLOR_BGR2RGB)
            display_pil = Image.fromarray(display_rgb)
            display_pil = display_pil.resize((600, 450), Image.Resampling.LANCZOS)
            display_photo = ImageTk.PhotoImage(display_pil)
            
            display_label = tk.Label(left_frame, image=display_photo, bg="#2c3e50")
            display_label.image = display_photo  # Keep reference
            display_label.pack(pady=10)
            
            # Right side: Model input
            right_frame = tk.Frame(comparison_frame, bg="#2c3e50", relief=tk.RAISED, borderwidth=2)
            right_frame.pack(side=tk.RIGHT, fill=tk.BOTH, expand=True, padx=5)
            
            tk.Label(
                right_frame,
                text="Model Input (What YOLO Sees)",
                bg="#2c3e50", fg="#e74c3c", font=("Arial", 12, "bold")
            ).pack(pady=5)
            
            tk.Label(
                right_frame,
                text="• CLAHE enhancement\n• Bilateral filtering\n• Grayscale (replicated 3x)",
                bg="#2c3e50", fg="#95a5a6", font=("Arial", 9),
                justify=tk.LEFT
            ).pack(pady=5)
            
            # Convert model input for tkinter
            model_rgb = cv2.cvtColor(model_input, cv2.COLOR_BGR2RGB)
            model_pil = Image.fromarray(model_rgb)
            model_pil = model_pil.resize((600, 450), Image.Resampling.LANCZOS)
            model_photo = ImageTk.PhotoImage(model_pil)
            
            model_label = tk.Label(right_frame, image=model_photo, bg="#2c3e50")
            model_label.image = model_photo  # Keep reference
            model_label.pack(pady=10)
            
            # Bottom info panel
            info_frame = tk.Frame(preview_window, bg="#34495e", relief=tk.SUNKEN, borderwidth=2)
            info_frame.pack(fill=tk.X, padx=10, pady=10)
            
            info_text = (
                f"Raw Thermal Range: {np.min(raw):.1f} to {np.max(raw):.1f}\n"
                f"Image Shape: {raw.shape[1]}x{raw.shape[0]} pixels\n"
                f"Camera Model: {safe_get_meta(meta, 'Model', 'Unknown')}\n\n"
                f"ℹ️ Training images MUST match model input preprocessing!\n"
                f"✓ Fixed in v3.19.0: Training now uses CLAHE-processed images"
            )
            
            tk.Label(
                info_frame,
                text=info_text,
                bg="#34495e", fg="white", font=("Arial", 10),
                justify=tk.LEFT
            ).pack(pady=10, padx=10)
            
            # Save button
            def save_preview():
                """Save preview images with error handling - FIXED v3.20.5.1"""
                try:
                    save_dir = filedialog.askdirectory(title="Select Folder to Save Preview Images")
                    if not save_dir:
                        return
                    
                    save_path = Path(save_dir)
                    save_path.mkdir(exist_ok=True)
                    
                    display_file = save_path / f"{img_path.stem}_display.jpg"
                    model_file = save_path / f"{img_path.stem}_model_input.jpg"
                    
                    # cv2.imwrite returns False on failure
                    success1 = cv2.imwrite(str(display_file), display_img)
                    success2 = cv2.imwrite(str(model_file), model_input)
                    
                    if not success1 or not success2:
                        raise IOError("cv2.imwrite() failed - could not write image file(s)")
                    
                    messagebox.showinfo("Saved", f"Preview images saved to {save_dir}")
                    logging.info(f"Preview images saved: {display_file.name}, {model_file.name}")
                    
                except Exception as e:
                    logging.error(f"Failed to save preview images: {e}")
                    messagebox.showerror(
                        "Save Error", 
                        f"Failed to save preview images:\n\n{str(e)}\n\n"
                        f"Check folder permissions and available disk space."
                    )
            
            tk.Button(
                preview_window,
                text="💾 Save Both Images",
                command=save_preview,
                bg="#16a085", fg="white", font=("Arial", 11)
            ).pack(pady=10)
            
            self.status_var.set("Preview ready")
            
            # Cleanup
            shutil.rmtree(temp_dir, ignore_errors=True)
            
        except Exception as e:
            logging.error(f"Preview error: {e}")
            messagebox.showerror("Preview Error", f"Failed to generate preview:\n{e}")
            self.status_var.set("Preview failed")

    def load_model(self):
        """Fully independent of Training Parameters model (ModelPath key)."""
        try:
            path = filedialog.askopenfilename(
                title="Select YOLO Detection Model",
                filetypes=[("PyTorch Model", "*.pt")]
            )

            if path:
                # ENHANCEMENT: Auto-detect and use GPU if available
                if TORCH_AVAILABLE:
                    device = 'cuda' if torch.cuda.is_available() else 'cpu'

                    # C-005/ML-001: Use ModelManager for caching
                    model = ModelManager.get_model(path)
                    model.to(device)

                    # v3.30.1.10: Write to DETECTION-specific config key
                    CFG.set("GENERAL", "DetectionModelPath", path)
                    CFG.set("GENERAL", "Device", device)

                    # Update display label (instance attr created in _create_ui)
                    self.detect_model_path_var.set(Path(path).name)

                    device_info = (f"GPU: {torch.cuda.get_device_name(0)}"
                                   if device == 'cuda' else "CPU")
                    messagebox.showinfo(
                        "Detection Model Loaded",
                        f"Model: {Path(path).name}\n"
                        f"Device: {device_info}\n\n"
                        f"Ready for detection!\n(Cached for performance)"
                    )
                    logging.info(f"Detection YOLO model loaded (cached) on {device}: {Path(path).name}")
                else:
                    CFG.set("GENERAL", "DetectionModelPath", path)
                    self.detect_model_path_var.set(Path(path).name)
                    messagebox.showinfo("Detection Model Loaded", f"Model: {Path(path).name}")

        except Exception as e:
            logging.error(f"Model load error: {e}")
            messagebox.showerror("Error", f"Failed to load model:\n{str(e)}")

    def browse_model(self):
        """Writes to CFG "GENERAL"/"DetectionModelPath" (separate from training)."""
        try:
            path = filedialog.askopenfilename(
                title="Select YOLO Detection Model",
                filetypes=[("PyTorch Model", "*.pt"), ("All Files", "*.*")]
            )

            if path:
                model_path = Path(path)
                if not model_path.exists():
                    messagebox.showerror("Error", "Selected model file does not exist")
                    return

                # v3.30.1.10: Write to DETECTION-specific config key (not shared ModelPath)
                CFG.set("GENERAL", "DetectionModelPath", str(model_path))

                # Update the entry widget in Detection tab
                self.detect_model_path_var.set(model_path.name)

                logging.info(f"Detection model path updated: {model_path.name}")

                messagebox.showinfo(
                    "Detection Model Selected",
                    f"Detection model set to:\n{model_path.name}\n\n"
                    f"Click 'Load' to activate it for batch processing."
                )

        except Exception as e:
            logging.error(f"Model browse error: {e}")
            messagebox.showerror("Error", f"Failed to browse model:\n{str(e)}")

