    def open_qc_viewer(self):
        """Open QC viewer for detected folder."""
        last_folder = CFG.get("QC", "LastQCFolder", "")
        initial_dir = last_folder if last_folder and Path(last_folder).exists() else str(SCRIPT_DIR)

        folder = filedialog.askdirectory(title="Select Detected Images Folder (annotated/)", initialdir=initial_dir)
        if not folder:
            return

        CFG.set("QC", "LastQCFolder", folder)
        detected_path = Path(folder)

        # Infer primary_folder: typically parent or grandparent of detected folder
        # Standard structure: input_folder/ → output/annotated/
        # So: annotated.parent.parent → input_folder
        primary_folder = None
        if detected_path.name == "annotated":
            primary_folder = detected_path.parent.parent
        elif (detected_path.parent.name == "output"
              or "detect" in detected_path.parent.name.lower()):
            primary_folder = detected_path.parent.parent
        else:
            primary_folder = detected_path.parent

        # ── v3.30.1.26: Read QC output folder from Settings (PATHS.QCOutputFolder) ──
        # The user sets this once via Settings → Folder Paths → "QC Output Folder: Browse..."
        # FEAT-QCDIR-001 (v3.30.26.1): If the path is configured but the directory does not
        # yet exist, create it automatically so the first QC save lands in the right place
        # rather than silently falling back to visual_annotated/annotated/.
        qc_out_raw = CFG.get("PATHS", "QCOutputFolder", "").strip()
        qc_output_folder: Optional[str] = None
        if qc_out_raw:
            _qc_path = Path(qc_out_raw)
            if not _qc_path.exists():
                # FEAT-QCDIR-001: Auto-create the configured folder
                try:
                    _qc_path.mkdir(parents=True, exist_ok=True)
                    write_folder_manifest(_qc_path, "visual_annotated")  # closest schema
                    logging.info(
                        f"QCViewer: created QCOutputFolder (did not exist): {_qc_path}"
                    )
                except OSError as _qcdir_err:
                    logging.warning(
                        f"QCViewer: could not create QCOutputFolder {_qc_path}: {_qcdir_err} "
                        "— falling back to detected_folder/visual_annotated/annotated/"
                    )
                    _qc_path = None   # fall back
            if _qc_path is not None:
                qc_output_folder = str(_qc_path)

        if qc_output_folder:
            logging.info(f"QCViewer: qc_output_folder from Settings → {qc_output_folder}")
        else:
            logging.info(
                "QCViewer: PATHS.QCOutputFolder not set — "
                "annotated images will be saved to detected_folder/visual_annotated/annotated/ "
                "(configure in Settings → Folder Paths to override)"
            )

        logging.info(f"QCViewer: detected_folder={detected_path}")
        logging.info(f"QCViewer: inferred primary_folder={primary_folder}")

        QCViewer(self, folder,
                 primary_folder=str(primary_folder) if primary_folder else None,
                 qc_output_folder=qc_output_folder)
    
