# ── Web UI HTML ───────────────────────────────────────────────────────────────
# Loaded from flir_web_ui.html alongside this script (if present).
# Falls back to a minimal redirect to /api/docs when the file is absent.
_WEB_UI_HTML: str = ""
try:
    _ui_path = Path(__file__).parent / "flir_web_ui.html"
    if _ui_path.exists():
        _WEB_UI_HTML = _ui_path.read_text(encoding="utf-8")
        logging.info(f"[UI] Web UI loaded from {_ui_path} ({len(_WEB_UI_HTML):,} chars)")
    else:
        logging.warning("[UI] flir_web_ui.html not found — root route serves redirect to /api/docs")
except Exception as _ui_err:
    logging.warning(f"[UI] Could not load flir_web_ui.html: {_ui_err}")

_WEB_UI_FALLBACK = """<!DOCTYPE html><html><head><meta charset="UTF-8">
<title>FLIR Thermal</title>
<meta http-equiv="refresh" content="2;url=/api/docs">
<style>body{font-family:monospace;background:#0d1117;color:#8b949e;display:flex;
  align-items:center;justify-content:center;height:100vh;flex-direction:column;gap:12px}
a{color:#00e5cc}</style></head>
<body><div style="font-size:24px">🌡</div>
<div>FLIR Thermal Analysis</div>
<div style="font-size:12px">Web UI not found — redirecting to <a href="/api/docs">API docs</a>…</div>
</body></html>"""


def _build_fastapi_app():
    """Build and return the FastAPI application with all registered routes."""
    if not WEB_AVAILABLE:
        return None

    from fastapi import FastAPI, BackgroundTasks, HTTPException, Request  # type: ignore[import]
    from fastapi.middleware.cors import CORSMiddleware                      # type: ignore[import]
    from fastapi.responses import HTMLResponse                              # type: ignore[import]
    import contextlib as _ctx

    # ── Pydantic request/response models ────────────────────────────────
    if PYDANTIC_AVAILABLE:
        from pydantic import BaseModel, Field                      # type: ignore[import]

        class BatchDetectRequest(BaseModel):
            folder:     str  = Field(..., description="Source image folder (absolute path)")
            model_path: str  = Field("",  description="Override model path (optional)")
            config:     dict = Field(default_factory=dict,
                                     description="CFG override dict e.g. {'DETECTION.ConfHigh':'0.7'}")

        class QCSaveRequest(BaseModel):
            folder:         str  = Field(..., description="annotated/ folder (absolute path)")
            stem:           str  = Field(..., description="Image stem without extension")
            spots:          list = Field(..., description="List of spot dicts")
            is_not_marked:  bool = Field(False, description="Mark/unmark image for manual review")

        class ReportRequest(BaseModel):
            folder:         str  = Field(..., description="Project root folder")
            regenerate_all: bool = Field(True, description="Regenerate existing reports")

        class PerfReportRequest(BaseModel):
            csv_path: str = Field(..., description="Absolute path to Report_*.csv")

    else:
        # Fallback plain classes when pydantic is absent
        class BatchDetectRequest:          # type: ignore[no-redef]
            def __init__(self, **kw):
                self.folder = kw.get("folder",""); self.model_path = kw.get("model_path","")
                self.config = kw.get("config",{})

        class QCSaveRequest:               # type: ignore[no-redef]
            def __init__(self, **kw):
                self.folder         = kw.get("folder",""); self.stem = kw.get("stem","")
                self.spots          = kw.get("spots",[])
                self.is_not_marked  = kw.get("is_not_marked", False)

        class ReportRequest:               # type: ignore[no-redef]
            def __init__(self, **kw):
                self.folder = kw.get("folder",""); self.regenerate_all = kw.get("regenerate_all",True)

        class PerfReportRequest:           # type: ignore[no-redef]
            def __init__(self, **kw):
                self.csv_path = kw.get("csv_path","")

    # ── Input validation helpers ─────────────────────────────────────────
    def _is_path_under_root(p: Path, root: Path) -> bool:
        """Return True if *p* is the same as or a descendant of *root*."""
        # AUDIT-SEC-010 FIX (v3.30.24): Use proper parent-chain check instead of
        # relative_to(p.anchor) which accepts any absolute path (passes for /etc etc).
        try:
            p.relative_to(root)
            return True
        except ValueError:
            return False

    def _validate_folder(folder_str: str, label: str = "folder") -> Path:
        """Validate folder path: non-empty, exists, is a directory, not a traversal attempt."""
        if not folder_str or not folder_str.strip():
            raise HTTPException(status_code=400, detail=f"{label} is required")
        p = Path(folder_str.strip()).resolve()
        # AUDIT-SEC-010 FIX (v3.30.24): The previous relative_to(p.anchor) check was
        # ineffective — every absolute path passes it (e.g. Path("/etc").resolve()
        # .relative_to("/") succeeds). Replaced with a check that the path must exist
        # and be a directory (already present), plus a null-byte injection guard.
        # Path traversal to valid existing directories is intentionally allowed by design
        # (the user must be able to navigate to any project folder); the real protection
        # is the API token and the per-user job scoping. The check below prevents only
        # null-byte and invalid path injection.
        if "\x00" in folder_str:
            raise HTTPException(status_code=400, detail=f"Invalid {label} path")
        if not p.exists():
            raise HTTPException(status_code=404, detail=f"{label} not found")
        if not p.is_dir():
            raise HTTPException(status_code=400, detail=f"{label} must be a directory")
        return p

    def _extract_user_token(request: Request) -> str:
        """Extract X-FLIR-Token for per-user job tracking; falls back to client IP."""
        return request.headers.get("X-FLIR-Token", "") or \
               (request.client.host if request.client else "anon")

    # ── BUG5-FIX: lifespan replaces deprecated on_event("startup") ──────
    @_ctx.asynccontextmanager
    async def _lifespan(app_instance):
        # Startup
        _FASTAPI_READY_EVENT.set()
        logging.info(f"[SECTION 17] FastAPI v{APP_VERSION} ready — "
                     f"RUNTIME_MODE={RUNTIME_MODE}")
        AUDIT.log("APP_START", {"app_version": APP_VERSION, "mode": "web",
                                 "runtime": RUNTIME_MODE})
        yield
        # Shutdown
        logging.info("[SECTION 17] FastAPI lifespan shutdown.")

    # ── Application ─────────────────────────────────────────────────────
    app = FastAPI(
        title="FLIR Thermal Analysis API",
        version=APP_VERSION,
        description=(
            "Hybrid web+desktop API for FLIR RJPEG thermal inspection. "
            "Localhost-only by default. Set FLIR_HOST=0.0.0.0 for LAN/WFH access."
        ),
        docs_url="/api/docs",
        redoc_url="/api/redoc",
        openapi_url="/api/openapi.json",
        lifespan=_lifespan,   # BUG5-FIX: replaces deprecated on_event
    )

    # AUDIT-SEC-001 FIX (v3.30.24): allow_origins=["*"] + allow_credentials=True is
    # forbidden by the CORS spec (browsers reject it). Use allow_credentials=False when
    # wildcard origins are needed. Credentials (cookies/auth headers) are managed via the
    # explicit X-FLIR-Token request header, NOT via the browser credential mechanism, so
    # allow_credentials=False is correct and sufficient.
    app.add_middleware(
        CORSMiddleware,
        allow_origins=["*"],      # WFH multi-user: any browser origin allowed
        allow_credentials=False,  # AUDIT-SEC-001: wildcard + credentials=True is spec-invalid
        allow_methods=["*"],
        allow_headers=["*"],
    )

    # AUDIT-SEC-009 FIX (v3.30.24): Add hardening security response headers.
    # Without these, browsers allow clickjacking (X-Frame-Options), MIME sniffing
    # (X-Content-Type-Options), and there is no Content-Security-Policy to block
    # inline script injection. These headers cost nothing and meaningfully reduce
    # the attack surface when the UI is served from the API server.
    from starlette.middleware.base import BaseHTTPMiddleware as _BHM_sec  # type: ignore[import]

    class _SecurityHeadersMiddleware(_BHM_sec):
        async def dispatch(self, request, call_next):
            response = await call_next(request)
            response.headers["X-Frame-Options"] = "SAMEORIGIN"
            response.headers["X-Content-Type-Options"] = "nosniff"
            response.headers["Referrer-Policy"] = "strict-origin-when-cross-origin"
            # Permissive CSP: allows inline scripts/styles (needed by the bundled UI),
            # API fetch to same origin, and base64 image data. Tighten if you add a
            # build step that externalises scripts.
            response.headers["Content-Security-Policy"] = (
                "default-src 'self'; "
                "script-src 'self' 'unsafe-inline'; "
                "style-src 'self' 'unsafe-inline'; "
                "img-src 'self' data: blob:; "
                "connect-src 'self'; "
                "frame-ancestors 'self';"
            )
            return response

    app.add_middleware(_SecurityHeadersMiddleware)

    # v3.30.23 FIX-AUTH: Optional static API-token middleware.
    # Set FLIR_API_TOKEN=<secret> in the environment to enable.
    # When set, every non-health/non-docs request must carry:
    #   Header:  X-FLIR-Token: <secret>
    # When unset (default), auth is disabled — safe for single-user localhost.
    import secrets as _secrets  # AUDIT-SEC-002: timing-safe compare
    _API_TOKEN = os.environ.get("FLIR_API_TOKEN", "").strip()
    _AUTH_EXEMPT = {"/", "/api/v1/health", "/api/v1/version", "/api/v1/help",
                    "/api/docs", "/api/redoc", "/api/openapi.json"}

    if _API_TOKEN:
        from starlette.middleware.base import BaseHTTPMiddleware  # type: ignore[import]
        from starlette.responses import JSONResponse              # type: ignore[import]

        class _TokenAuthMiddleware(BaseHTTPMiddleware):
            async def dispatch(self, request, call_next):
                if request.url.path not in _AUTH_EXEMPT:
                    token = request.headers.get("X-FLIR-Token", "")
                    # AUDIT-SEC-002 FIX (v3.30.24): use secrets.compare_digest() instead of
                    # != string comparison. Direct string comparison leaks timing information
                    # that an attacker can use to brute-force the token one character at a
                    # time via a timing side-channel attack. compare_digest() runs in
                    # constant time regardless of how many characters match.
                    if not _secrets.compare_digest(token, _API_TOKEN):
                        logging.warning(
                            f"[AUTH] Rejected {request.method} {request.url.path} "
                            f"from {request.client.host} — bad/missing token"
                        )
                        return JSONResponse(
                            {"detail": "Unauthorized — X-FLIR-Token required"},
                            status_code=401,
                        )
                return await call_next(request)

        app.add_middleware(_TokenAuthMiddleware)
        logging.info("[SECTION 17] API token auth ENABLED (FLIR_API_TOKEN is set).")
    else:
        logging.info("[SECTION 17] API token auth DISABLED — set FLIR_API_TOKEN to enable.")

    # ╔══════════════════════════════════════════════════════════════════════════╗
    # ║  !! DELIVERY RULE — ALWAYS PRESENT BOTH FILES TOGETHER !!              ║
    # ║  Any change touching drawSpots, SPOT_LABEL_STYLE, or this route        ║
    # ║  MUST result in BOTH files being delivered to the user:                ║
    # ║    1. flir_thermal_app_v3_30_24.py                                     ║
    # ║    2. flir_web_ui.html                                                  ║
    # ║  Never present only one. No exceptions.                                ║
    # ╚══════════════════════════════════════════════════════════════════════════╝
    # ── / (Web UI) ────────────────────────────────────────────────────
    @app.get("/", tags=["meta"], response_class=HTMLResponse,
             include_in_schema=False)
    async def web_ui():
        """Serve the full web UI (flir_web_ui.html) at the root path."""
        content = _WEB_UI_HTML if _WEB_UI_HTML else _WEB_UI_FALLBACK

        # ── Auto-sync: inject SPOT_LABEL_STYLE → JS constants ────────────
        # Replace /* __SPOT_LABEL_STYLE__ */ sentinel in drawSpots() with
        # the current SPOT_LABEL_STYLE values.  Change only the Python dict
        # and both the cv2/PIL backend AND the web canvas update together.
        _sls = SPOT_LABEL_STYLE
        _bg  = f'"{_sls["label_bg_hex"]}"' if _sls["label_bg_hex"] else "null"
        _bd  = f'"{_sls["label_bd_hex"]}"' if _sls["label_bd_hex"] else "null"
        _shadow_c = f'"{_sls["label_shadow_c"]}"' if _sls.get("label_shadow") else "null"
        _shadow_b = _sls.get("label_shadow_b", 0) if _sls.get("label_shadow") else 0
        # Use single-quoted JS string for LABEL_FONT — the value contains double quotes
        # (e.g. "JetBrains Mono") which json.dumps would escape as \" producing invalid JS.
        _font_js = _sls["label_font_js"].replace("'", "\\'")   # escape any single quotes
        _inject = (
            "  // __SPOT_LABEL_STYLE_START__\n"
            "  // auto-injected from SPOT_LABEL_STYLE in flir_thermal_app_v3_30_24.py\n"
            f"  const SPOT_R        = {_sls['spot_r']};\n"
            f"  const ARM_GAP       = {_sls['arm_gap']};\n"
            f"  const ARM_OUT       = SPOT_R + {_sls['arm_ext']};\n"
            f"  const LABEL_PAD     = {_sls['label_pad']};\n"
            f"  const LABEL_GAP     = {_sls['label_gap']};\n"
            f"  const LABEL_BG      = {_bg};\n"
            f"  const LABEL_FG      = '{_sls['label_fg_hex']}';\n"
            f"  const LABEL_BD      = {_bd};\n"
            f"  const SPOT_C        = '{_sls['spot_c_hex']}';\n"
            f"  const LABEL_FONT    = '{_font_js}';\n"
            f"  const LABEL_SHADOW_C = {_shadow_c};\n"
            f"  const LABEL_SHADOW_B = {_shadow_b};\n"
            "  // __SPOT_LABEL_STYLE_END__"
        )
        import re as _re
        # Replace the entire delimited block (including its delimiters)
        content = _re.sub(
            r"  // __SPOT_LABEL_STYLE_START__.*?// __SPOT_LABEL_STYLE_END__",
            _inject,
            content,
            flags=_re.DOTALL,
        )
        return HTMLResponse(content=content, status_code=200)

