    @app.get("/api/v1/settings", tags=["settings"])
    async def settings_get():
        """WEB-019: Return all user-facing CFG values as {section.key: value} dict."""
        result = {}
        for sec, key, default, _ in _SETTINGS_SCHEMA:
            result[f"{sec}.{key}"] = CFG.get(sec, key, default)
        return {"ok": True, "settings": result}

    class SettingsPayload(BaseModel):  # type: ignore[misc]
        settings: dict  # {section.key: value}

    @app.post("/api/v1/settings", tags=["settings"])
    async def settings_post(payload: SettingsPayload):  # type: ignore[valid-type]
        """
            WEB-019: Persist settings dict to CFG and to the .ini file on disk.
            Accepts {section.key: value} pairs; unknown keys are silently ignored
        """
        # Build allowed-key set from schema
        allowed = {f"{sec}.{key}" for sec, key, *_ in _SETTINGS_SCHEMA}
        applied: list = []
        rejected: list = []
        for compound_key, value in (payload.settings or {}).items():
            if compound_key not in allowed:
                rejected.append(compound_key)
                continue
            sec, key = compound_key.split(".", 1)
            CFG.set(sec, key, str(value))
            applied.append(compound_key)
        # Persist to disk
        try:
            CFG.save()
        except Exception as _se:
            logging.warning(f"[settings_post] CFG.save failed: {_se}")
        AUDIT.log("SETTINGS_SAVE", {"applied": len(applied), "rejected": rejected})
        return {"ok": True, "applied": applied, "rejected": rejected}

    # ── /shutdown ────────────────────────────────────────────────────────
    @app.post("/api/v1/shutdown", tags=["meta"])
    async def shutdown():
        """Refuses if any batch job is currently running to prevent data corruption."""
        # BUG2-FIX: check for active jobs before signalling shutdown
        with CoreEngine._jobs_lock:
            active = [jid for jid, j in CoreEngine._jobs.items()
                      if j.get("status") == "running"]
        if active:
            raise HTTPException(
                status_code=409,
                detail=f"Cannot shut down: {len(active)} active job(s) running — "
                       f"wait for completion or cancel: {active}"
            )

        logging.info("[SECTION 17] /shutdown called — signalling StartupController.")
        _FASTAPI_SHUTDOWN_EVENT.set()

        def _stop():
            import time as _t, signal as _sig, os as _oe
            _t.sleep(0.3)
            try:
                _sig.raise_signal(_sig.SIGTERM)
            except AttributeError:
                _oe.kill(_oe.getpid(), _sig.SIGTERM)

        threading.Thread(target=_stop, daemon=True, name="uvicorn-shutdown").start()
        return {"status": "shutting_down",
                "message": "Server will stop. Desktop mode dialog will appear shortly."}

    # ── /jobs/list ────────────────────────────────────────────────────────
    @app.get("/api/v1/jobs/list", tags=["detection"])
    async def jobs_list(request: Request):
        """List all jobs for the calling user token (or all if admin token)."""
        user_token = _extract_user_token(request)
        with CoreEngine._jobs_lock:
            # Admin sees all; regular user sees own jobs only.
            # AUDIT-SEC-002 FIX: use secrets.compare_digest() for constant-time compare.
            _is_admin = bool(_API_TOKEN) and _secrets.compare_digest(user_token, _API_TOKEN)
            if _is_admin:
                result = {jid: {k: v for k, v in j.items() if k != "user_token"}
                          for jid, j in CoreEngine._jobs.items()}
            else:
                result = {jid: {k: v for k, v in j.items() if k != "user_token"}
                          for jid, j in CoreEngine._jobs.items()
                          if j.get("user_token") == user_token}
        return {"ok": True, "jobs": result}

