    @app.post("/api/v1/detect/batch", tags=["detection"])
    async def detect_batch(request_data: BatchDetectRequest,       # type: ignore[valid-type]
                           request: Request,
                           background_tasks: BackgroundTasks):
        """
        Start a batch detection job (non-blocking).
        Poll /detect/status/{job_id} for progress.
        """
        _validate_folder(request_data.folder, "folder")
        cfg = dict(request_data.config or {})
        if request_data.model_path:
            cfg["GENERAL.DetectionModelPath"] = request_data.model_path
        user_token = _extract_user_token(request)
        try:
            job_id = CoreEngine.start_batch_job(request_data.folder, cfg,
                                                 user_token=user_token)
        except RuntimeError as _rte:
            raise HTTPException(status_code=429, detail=str(_rte))
        logging.info(f"[SECTION 17] /detect/batch job_id={job_id[:8]} "
                     f"folder={request_data.folder} user={user_token}")
        return {"status": "started", "job_id": job_id}

    # ── /detect/status ───────────────────────────────────────────────────
    @app.get("/api/v1/detect/status/{job_id}", tags=["detection"])
    async def detect_status(job_id: str, request: Request):
        """Poll status of a running batch detection job."""
        # AUDIT-SEC-008 FIX (v3.30.24): verify the requesting user owns this job.
        # Previously any authenticated user could poll any job_id. Now we check
        # user_token matches; admins (token == _API_TOKEN) can see any job.
        user_token = _extract_user_token(request)
        s = CoreEngine.get_job_status(job_id)
        if not s.get("ok"):
            raise HTTPException(status_code=404, detail=s.get("error"))
        _job_owner = s.get("user_token", "")
        _is_admin = bool(_API_TOKEN) and _secrets.compare_digest(user_token, _API_TOKEN)
        if not _is_admin and _job_owner and _job_owner != user_token:
            raise HTTPException(status_code=403, detail="Not authorized to view this job")
        return s

