    # ══════════════════════════════════════════════════════════════════════
    # SYNC-TRAIN — WEB ↔ TKINTER TRAINING PARITY MAINTENANCE CONTRACT
    # ══════════════════════════════════════════════════════════════════════
    # ANY change to training parameters in EITHER file MUST be reflected
    # in the OTHER file.  Checklist:
    #
    #  Python (this file) — CoreEngine.start_train_job():
    #    • train_kwargs dict must include every param the Tkinter _train_thread
    #      passes to model.train().  If you add a param in Tkinter, add it here.
    #    • Safety guards (worker cap, multi_scale/imgsz, rect/mosaic) must match.
    #    • _log() calls must cover new params so web log stream is informative.
    #
    #  HTML  (flir_web_ui.html) — Training Parameters panel:
    #    • Every data-key value must match a TRAINING.* CFG key (case-sensitive).
    #    • Toggle IDs must appear in saveTrainingParams() toggleMap.
    #    • If a new CFG key is added in Python, add a matching input in HTML.
    #    • If a CFG key is renamed, update BOTH the Python default AND the HTML.
    #
    #  Key mapping (HTML data-key  →  Python CFG key  →  YOLO kwarg):
    #    Device       → TRAINING.TrainDevice → device   (NOT TRAINING.Device)
    #    LR_Final     → TRAINING.LR_Final    → lrf
    #    NBS          → TRAINING.NBS         → nbs
    #    Cos_LR       → TRAINING.Cos_LR      → cos_lr   (toggle, not data-key)
    #    Close_Mosaic → TRAINING.Close_Mosaic→ close_mosaic
    #    CopyPasteMode→ TRAINING.CopyPasteMode→copy_paste_mode
    #    TimeLimit    → TRAINING.TimeLimit   → time (0.0 → None)
    #    SavePlots    → TRAINING.SavePlots   → plots    (toggle)
    # ══════════════════════════════════════════════════════════════════════
    # ── /train/params ─────────────────────────────────────────────────────
    @app.post("/api/v1/train/params", tags=["training"])
    async def train_params_save(request: Request):
        """Persist training parameters to settings.ini via CFG.set()."""
        # AUDIT-SEC-003 FIX (v3.30.24): Validate incoming keys against an explicit
        # TRAINING-section whitelist. Previously, this endpoint accepted ANY "section.key"
        # pair, allowing a malicious client to overwrite arbitrary config values (e.g.
        # "GENERAL.DetectionModelPath" pointing to a shell script). Now only recognised
        # TRAINING keys (those present in AppConfig._load_defaults under ["TRAINING"])
        # and the specific GENERAL/DETECTION keys the UI legitimately sends are accepted.
        # Unknown keys are silently rejected and returned in the response for debugging.
        _TRAIN_ALLOWED: set = {
            # TRAINING section — all keys from AppConfig._load_defaults["TRAINING"]
            "TRAINING.Epochs", "TRAINING.Batch", "TRAINING.ImgSz", "TRAINING.LR0",
            "TRAINING.Patience", "TRAINING.Optimizer", "TRAINING.Momentum",
            "TRAINING.Weight_Decay", "TRAINING.LR_Final", "TRAINING.Workers",
            "TRAINING.NBS", "TRAINING.Cos_LR", "TRAINING.Mosaic", "TRAINING.MixUp",
            "TRAINING.CopyPaste", "TRAINING.Perspective", "TRAINING.Erasing",
            "TRAINING.CutMix", "TRAINING.HSV_H", "TRAINING.HSV_S", "TRAINING.HSV_V",
            "TRAINING.Degrees", "TRAINING.Translate", "TRAINING.Scale", "TRAINING.Shear",
            "TRAINING.FlipLR", "TRAINING.FlipUD", "TRAINING.BGR", "TRAINING.AutoAugment",
            "TRAINING.Dropout", "TRAINING.Fraction", "TRAINING.Multi_Scale",
            "TRAINING.Freeze", "TRAINING.Label_Smoothing", "TRAINING.SavePeriod",
            "TRAINING.Seed", "TRAINING.Deterministic", "TRAINING.Box", "TRAINING.Cls",
            "TRAINING.DFL", "TRAINING.Rect", "TRAINING.SingleCls", "TRAINING.TimeLimit",
            "TRAINING.CopyPasteMode", "TRAINING.AMP", "TRAINING.Cache",
            "TRAINING.Name", "TRAINING.FineTune", "TRAINING.Resume",
            "TRAINING.WarmupEpochs", "TRAINING.WarmupMomentum", "TRAINING.WarmupBiasLr",
            "TRAINING.CloseEnhanceMosaic", "TRAINING.SavePlots",
            # GENERAL keys legitimately sent from training UI
            "GENERAL.ModelPath", "GENERAL.DetectionModelPath",
        }
        body = await request.json()
        config: dict = body.get("config", {})
        saved: list = []
        rejected: list = []
        for cfg_key, val in config.items():
            if cfg_key not in _TRAIN_ALLOWED:
                rejected.append(cfg_key)
                continue
            if "." in cfg_key:
                sec, key = cfg_key.split(".", 1)
                CFG.set(sec, key, str(val))
                saved.append(cfg_key)
        if rejected:
            logging.warning(f"[train_params_save] Rejected unknown keys: {rejected}")
        AUDIT.log("TRAIN_PARAMS_SAVED", {"keys": saved, "rejected": rejected})
        return {"ok": True, "saved": len(saved), "keys": saved, "rejected": rejected}

