    # ── /train/start ───────────────────────────────────────────────────────
    @app.post("/api/v1/train/start", tags=["training"])
    async def train_start(request: Request):
        """Start a YOLO training job in a background thread."""
        body = await request.json()
        dataset_dir = body.get("dataset_dir", "")
        if not dataset_dir:
            raise HTTPException(status_code=400, detail="dataset_dir is required")
        # AUDIT-SEC-005 FIX (v3.30.24): run_name is used in Path construction as
        # SCRIPT_DIR/runs/<run_name>/weights/best.pt. An unsanitized run_name like
        # "../../etc" would escape the runs/ directory. Restrict to alphanumerics,
        # hyphens, and underscores only; reject anything else. Also cap length to
        # prevent filesystem path length overflows.
        _raw_run = body.get("run_name", "flir_training") or "flir_training"
        import re as _re_rn
        run_name = _re_rn.sub(r"[^A-Za-z0-9_\-]", "_", _raw_run)[:64]
        if not run_name:
            run_name = "flir_training"
        finetune   = bool(body.get("finetune", True))
        model_path = body.get("model_path", CFG.get("GENERAL", "ModelPath", "yolo11n.pt"))
        user_token = _extract_user_token(request)

        try:
            job_id = CoreEngine.start_train_job(
                dataset_dir=dataset_dir,
                run_name=run_name,
                finetune=finetune,
                model_path=model_path,
                user_token=user_token,
            )
        except RuntimeError as _rte:
            raise HTTPException(status_code=429, detail=str(_rte))
        logging.info(f"[SECTION 17] /train/start job_id={job_id[:8]} run={run_name}")
        return {"status": "started", "job_id": job_id}

