    # ─────────────────────────────────────────────────────────────────────────
    # TODO-WEB-002 [DONE]: Server-side directory browser
    # Two endpoints that power all Browse buttons in the web UI.
    #   GET  /api/v1/browse/roots      — drive roots (Windows) or home + /
    #   POST /api/v1/browse/directory  — list immediate subdirs of a given path
    # Security: _validate_folder enforced on every path; path traversal rejected.
    # ─────────────────────────────────────────────────────────────────────────
    @app.get("/api/v1/browse/roots", tags=["browse"])
    async def browse_roots():
        """Return filesystem roots: drive letters on Windows, [home, /] elsewhere."""
        import sys as _sys
        roots: List[str] = []
        if _sys.platform.startswith("win"):
            # Enumerate drive letters A-Z that actually exist
            import string
            for _dl in string.ascii_uppercase:
                _p = Path(f"{_dl}:\\")
                if _p.exists():
                    roots.append(str(_p))
        else:
            _home = str(Path.home())
            roots = [_home, "/"]
        return {"roots": roots}

    @app.post("/api/v1/browse/directory", tags=["browse"])
    async def browse_directory(request: Request):
        """List immediate subdirectories of *path*; returns sorted list with parent entry."""
        body    = await request.json()
        raw     = body.get("path", "").strip()

        # Allow empty/null → default to home directory
        if not raw:
            raw = str(Path.home())

        p = Path(raw).resolve()

        # AUDIT-SEC-004 FIX (v3.30.24): Restrict browseable roots to safe anchors.
        # Previously, any absolute path (including /etc, /root, /proc) was accepted.
        # The old relative_to(p.anchor) check is ineffective — every absolute path
        # passes that test. Now we enforce that p must be under an allowed root
        # (home directory or any existing drive root on Windows). This prevents a
        # web client from enumerating sensitive system directories.
        import sys as _sys_br
        _allowed_roots: list = []
        if _sys_br.platform.startswith("win"):
            import string as _string_br
            _allowed_roots = [Path(f"{dl}:\\") for dl in _string_br.ascii_uppercase
                              if Path(f"{dl}:\\").exists()]
        else:
            _allowed_roots = [Path.home(), Path("/")]
        _under_allowed = any(
            _is_path_under_root(p, root) for root in _allowed_roots
        )
        if not _under_allowed:
            raise HTTPException(status_code=403, detail="Path is outside browseable roots")

        # Security: reject non-existent or non-directory paths
        if not p.exists():
            raise HTTPException(status_code=404, detail="Path not found")
        if not p.is_dir():
            # If caller passed a file path, use its parent
            p = p.parent

        subdirs: List[str] = []
        try:
            for child in sorted(p.iterdir()):
                if child.is_dir() and not child.name.startswith("."):
                    subdirs.append(str(child))
        except PermissionError:
            pass   # Return whatever we gathered before the access denied

        parent = str(p.parent) if p != p.parent else None
        return {
            "current": str(p),
            "parent":  parent,
            "dirs":    subdirs,
        }

    # ─────────────────────────────────────────────────────────────────────────
    # TODO-WEB-004 [DONE]: Load detection model via API
    # POST /api/v1/detect/load-model  — load a .pt file into CoreEngine
    # ─────────────────────────────────────────────────────────────────────────
    @app.post("/api/v1/detect/load-model", tags=["detection"])
    async def detect_load_model(request: Request):
        """Load (or reload) the detection model from *model_path*."""
        body       = await request.json()
        model_path = body.get("model_path", "").strip()
        if not model_path:
            # Fall back to configured path
            model_path = CFG.get("GENERAL", "DetectionModelPath", "trained_model.pt")
        p = Path(model_path)
        if not p.exists():
            raise HTTPException(status_code=404, detail=f"Model file not found: {model_path}")
        try:
            result = CoreEngine.load_model(str(p))
        except Exception as _lm_err:
            raise HTTPException(status_code=500, detail=f"Model load failed: {_lm_err}")
        # Persist choice to config so it survives restart
        CFG.set("GENERAL", "DetectionModelPath", str(p))
        return {"ok": True, "model_path": str(p), "detail": result if isinstance(result, str) else "loaded"}

    # ─────────────────────────────────────────────────────────────────────────
    # TODO-WEB-005 [DONE]: Manual Correction trigger
    # POST /api/v1/detect/manual-correction — run_fix logic on a folder
    # ─────────────────────────────────────────────────────────────────────────
    @app.post("/api/v1/detect/manual-correction", tags=["detection"])
    async def detect_manual_correction(request: Request):
        """Trigger the manual-correction pipeline (run_fix) on an annotated folder."""
        body   = await request.json()
        folder = body.get("folder", "")
        p      = _validate_folder(folder, "annotated folder")
        try:
            result = CoreEngine.run_fix(str(p))
        except Exception as _rf_err:
            raise HTTPException(status_code=500, detail=f"Manual correction failed: {_rf_err}")
        return {"ok": True, "folder": str(p), "detail": result if isinstance(result, str) else "correction applied"}

    # ─────────────────────────────────────────────────────────────────────────
    # TODO-WEB-006 [DONE]: Preview What Model Sees
    # POST /api/v1/detect/preview — CLAHE + original side-by-side as base64 PNG
    # ─────────────────────────────────────────────────────────────────────────
    @app.post("/api/v1/detect/preview", tags=["detection"])
    async def detect_preview(request: Request):
        """Return a base64-encoded side-by-side comparison image:"""
        from fastapi.responses import JSONResponse  # noqa: F401
        body   = await request.json()
        folder = body.get("folder", "")
        p      = _validate_folder(folder, "folder")

        # Find first processable image
        exts   = {".jpg", ".jpeg", ".png", ".tif", ".tiff"}
        images = sorted([f for f in p.iterdir() if f.suffix.lower() in exts])
        if not images:
            raise HTTPException(status_code=404, detail="No images found in folder")

        img_path = images[0]
        try:
            result = CoreEngine.preview_detection_input(str(img_path))
        except Exception as _pv_err:
            raise HTTPException(status_code=500, detail=f"Preview failed: {_pv_err}")

        return {
            "ok":       True,
            "filename": img_path.name,
            "image_b64": result.get("image_b64", ""),
            "width":     result.get("width", 0),
            "height":    result.get("height", 0),
        }

    # ─────────────────────────────────────────────────────────────────────────
    # TODO-WEB-007 [DONE]: Cancel a running detection batch
    # DELETE /api/v1/detect/cancel/{job_id}
    # ─────────────────────────────────────────────────────────────────────────
    @app.delete("/api/v1/detect/cancel/{job_id}", tags=["detection"])
    async def detect_cancel(job_id: str, request: Request):
        """Request cancellation of a running detection job."""
        # AUDIT-SEC-008 FIX (v3.30.24): only owner or admin can cancel a job.
        user_token = _extract_user_token(request)
        s = CoreEngine.get_job_status(job_id)
        if s.get("ok"):
            _job_owner = s.get("user_token", "")
            _is_admin = bool(_API_TOKEN) and _secrets.compare_digest(user_token, _API_TOKEN)
            if not _is_admin and _job_owner and _job_owner != user_token:
                raise HTTPException(status_code=403, detail="Not authorized to cancel this job")
        result = CoreEngine.cancel_job(job_id)
        if not result.get("ok"):
            status_code = 404 if "not found" in result.get("error", "").lower() else 409
            raise HTTPException(status_code=status_code, detail=result.get("error"))
        return {"ok": True, "job_id": job_id, "status": "cancellation requested"}

    # ─────────────────────────────────────────────────────────────────────────
    # TODO-WEB-016 [DONE]: Batch Reports — multi-subfolder DOCX/PDF generation
    # POST /api/v1/report/generate-batch
    #   Body: {"folder": "<parent>", "regenerate_all": true}
    #   Returns: {ok, projects, generated, pdfs, skipped, errors, failed_folders, zips}
    # Mirrors MainApp._run_batch_report_generation_thread without Tkinter.
    # ─────────────────────────────────────────────────────────────────────────
    @app.post("/api/v1/report/generate-batch", tags=["reports"])
    async def report_generate_batch(request: Request):
        """WEB-016: Generate DOCX+PDF reports for every qualifying project sub-folder
        under *folder*.  A sub-folder qualifies when annotated/Report_*.csv exists.
        Each sub-folder receives its own ZIP package.  Long-running — call async."""
        body = await request.json()
        folder       = body.get("folder", "").strip()
        regen_all    = bool(body.get("regenerate_all", True))
        _validate_folder(folder, "folder")
        r = CoreEngine.generate_batch_reports(folder, regenerate_all=regen_all)
        if not r.get("ok"):
            raise HTTPException(status_code=422, detail=r.get("error"))
        AUDIT.log("BATCH_REPORT_API", {"folder": folder,
                                        "projects": r.get("projects")})
        return r

    # ─────────────────────────────────────────────────────────────────────────
    # TODO-WEB-018 [DONE]: Annotate New Data
    # POST /api/v1/train/annotate
    #   Body: {"folder": "<annotated_folder>"}
    #   Returns: {ok, processed, skipped, errors, message}
    # Runs headless re-annotation on not_marked/ images that have no JSON sidecar.
    # ─────────────────────────────────────────────────────────────────────────
    @app.post("/api/v1/train/annotate", tags=["training"])
    async def train_annotate(request: Request):
        """WEB-018: Annotate not_marked/ images that have no JSON sidecar yet.
        Requires a model to be loaded (POST /api/v1/detect/load-model first).
        Mirrors the Tkinter 'Annotate New Data' button workflow headlessly."""
        body   = await request.json()
        folder = body.get("folder", "").strip()
        _validate_folder(folder, "folder")
        try:
            r = CoreEngine.annotate_new_data(folder)
        except Exception as _ae:
            raise HTTPException(status_code=500, detail=f"Annotation failed: {_ae}")
        if not r.get("ok"):
            raise HTTPException(status_code=422, detail=r.get("error"))
        AUDIT.log("ANNOTATE_NEW_DATA_API", {"folder": folder,
                                             "processed": r.get("processed")})
        return r

    return app


