def startup_self_test() -> bool:
    """Boot-time validation checklist (FIX-STARTUP-001 v3.30.24)."""
    ok   = True
    cfg  = CFG  # module-level AppConfig singleton

    # ── 1. Detection model file ──────────────────────────────────────────
    model_path = Path(cfg.get("GENERAL", "DetectionModelPath", "trained_model.pt"))
    if model_path.exists():
        logging.info(f"[self-test] ✓ Model found: {model_path}")
    else:
        logging.warning(f"[self-test] ✗ Model NOT found: {model_path}  "
                        "(detection will fail until a model is loaded)")
        ok = False  # non-fatal — user can load at runtime

    # ── 2. Report template (DOCX) ────────────────────────────────────────
    tpl_path = Path(cfg.get("PATHS", "ReportTemplate", "report_template.docx"))
    if tpl_path.exists():
        logging.info(f"[self-test] ✓ Report template found: {tpl_path}")
    else:
        logging.warning(f"[self-test] ✗ Report template NOT found: {tpl_path}  "
                        "(report generation will fail)")
        ok = False

    # ── 3. Output folder writability ─────────────────────────────────────
    out_path = Path(cfg.get("PATHS", "QCOutputFolder", "QC_Output"))  # matches PATHS default key
    try:
        out_path.mkdir(parents=True, exist_ok=True)
        _probe = out_path / ".write_probe"
        _probe.write_text("ok")
        _probe.unlink()
        logging.info(f"[self-test] ✓ Output folder writable: {out_path}")
    except OSError as _oe:
        logging.error(f"[self-test] ✗ Output folder not writable: {out_path} — {_oe}")
        ok = False

    # ── 4. Temp working directory ────────────────────────────────────────
    import tempfile as _tf
    try:
        with _tf.TemporaryFile(dir=_tf.gettempdir()):
            pass
        logging.info(f"[self-test] ✓ Temp dir writable: {_tf.gettempdir()}")
    except OSError as _te:
        logging.error(f"[self-test] ✗ Temp dir not writable: {_te}")
        ok = False

    status = "PASS" if ok else "PARTIAL (see warnings above)"
    logging.info(f"[self-test] Startup self-test: {status}")
    return ok


class StartupController:
    """Hybrid startup orchestrator — headless/local/web/hybrid mode routing."""

    _READY_TIMEOUT_S  = int(os.environ.get("FLIR_READY_TIMEOUT", "30"))  # v3.30.23 FIX-TIMEOUT: was hardcoded 10; raised to 30 and made env-configurable so slow CPU/disk model loads don't trigger premature Tkinter fallback
    _STARTUP_RETRY_S  = 0.5      # seconds between /health polls
    _POLL_INTERVAL_S  = 2.0      # seconds between monitor polls (unused, using Event.wait)

    def __init__(self, port: int = 8000, host: str = "127.0.0.1") -> None:
        self.port = int(os.environ.get("FLIR_PORT", str(port)))
        self.host = os.environ.get("FLIR_HOST", host)
        self._server_url  = f"http://{self.host}:{self.port}"
        self._health_url  = f"{self._server_url}/api/v1/health"
        self._open_browser = os.environ.get("FLIR_NO_BROWSER", "").strip() \
                             not in ("1", "true", "yes")
        self._server_thread:  Optional[threading.Thread] = None
        self._monitor_thread: Optional[threading.Thread] = None

    # ── Public entry point ───────────────────────────────────────────────
    # Web/FastAPI backend remains available when WEB_AVAILABLE=True.
    # Startup mode dialog removed — always launches Tkinter directly.

    def run(self) -> None:
        """Launch Tkinter directly; web-only mode still supported via RUNTIME_MODE=web."""
        startup_self_test()  # validate env before any UI/server starts
        if RUNTIME_MODE == "headless":
            logging.info("[StartupController] headless mode — CoreEngine ready, no UI started.")
            return

        if RUNTIME_MODE == "web":
            # Explicit web-only mode (env var): start FastAPI without Tkinter
            logging.info(f"[StartupController] web-only mode @ {self._server_url}")
            self._start_fastapi_thread(block=True)
            return

        # All other modes → launch Tkinter directly (no mode-selector dialog)
        logging.info("[StartupController] Launching desktop Tkinter UI.")
        self._launch_tkinter_directly()

    # ── FastAPI thread ───────────────────────────────────────────────────

    def _start_fastapi_thread(self, block: bool = False) -> None:
        """Build and start uvicorn.  If block=True, runs on calling thread."""
        global _FASTAPI_APP
        if not WEB_AVAILABLE:
            raise RuntimeError("fastapi/uvicorn not installed — "
                               "pip install fastapi 'uvicorn[standard]' --break-system-packages")
        _FASTAPI_APP = _build_fastapi_app()

        import uvicorn  # type: ignore[import]
        cfg = uvicorn.Config(_FASTAPI_APP, host=self.host, port=self.port,
                              log_level="warning", access_log=False, loop="asyncio")
        server = uvicorn.Server(cfg)

        def _run():
            try:
                server.run()
            except Exception as _srv_err:
                logging.error(f"[StartupController] uvicorn: {_srv_err}")
            finally:
                _FASTAPI_SHUTDOWN_EVENT.set()
                logging.info("[StartupController] uvicorn exited.")

        if block:
            _run()
        else:
            self._server_thread = threading.Thread(target=_run, daemon=True,
                                                    name="uvicorn-server")
            self._server_thread.start()
            logging.info(f"[StartupController] uvicorn thread started (:{self.port})")

    # ── Readiness probe ──────────────────────────────────────────────────

    def _wait_for_server_ready(self) -> bool:
        """Poll /health up to _READY_TIMEOUT_S seconds. Returns True if ready."""
        import urllib.request as _ur, urllib.error as _ue
        deadline = time.monotonic() + self._READY_TIMEOUT_S
        logging.info(f"[StartupController] Waiting for {self._health_url} …")
        while time.monotonic() < deadline:
            try:
                with _ur.urlopen(self._health_url, timeout=1) as resp:
                    if resp.status == 200:
                        logging.info("[StartupController] Server ready ✓")
                        _FASTAPI_READY_EVENT.set()
                        return True
            except (_ue.URLError, OSError):
                pass
            time.sleep(self._STARTUP_RETRY_S)
        logging.warning(f"[StartupController] Timeout after {self._READY_TIMEOUT_S} s.")
        return False

    # ── Browser auto-open ────────────────────────────────────────────────

    def _open_browser_tab(self) -> None:
        """Open default browser to _server_url after a 0.5 s stabilisation delay."""
        import webbrowser
        url = self._server_url
        def _open():
            time.sleep(0.5)
            webbrowser.open(url)
            logging.info(f"[StartupController] Browser opened: {url}")
        threading.Thread(target=_open, daemon=True, name="browser-open").start()

    # ── Health monitor ───────────────────────────────────────────────────

    def _start_health_monitor(self) -> None:
        """Start daemon thread that waits on _FASTAPI_SHUTDOWN_EVENT."""
        # The main thread already waits on _FASTAPI_SHUTDOWN_EVENT.wait()
        # in run().  The monitor thread here is only needed when run() has
        # already returned (web-only mode — not applicable for hybrid).
        # For hybrid mode the main thread handles the wait directly in run().
        # This thread is a no-op safety net.
        def _monitor():
            _FASTAPI_SHUTDOWN_EVENT.wait()
            logging.info("[StartupController] Monitor thread: shutdown confirmed.")
        self._monitor_thread = threading.Thread(target=_monitor, daemon=True,
                                                 name="fastapi-monitor")
        self._monitor_thread.start()

    # ── Option A dialog & Tkinter launch ────────────────────────────────

    def _offer_desktop_fallback(self) -> None:
        """Show Option A confirmation dialog on the main thread."""
        if not UI_AVAILABLE:
            logging.info("[StartupController] UI_AVAILABLE=False — no dialog.")
            return
        # v3.30.23 FIX-HEADLESS: On Linux/Mac check $DISPLAY; on Windows Server Core
        # tkinter will raise TclError if no display is available.  Detect early so we
        # log a clear message instead of a silent exception swallowed by the outer try.
        import sys as _sys
        _is_windows = _sys.platform.startswith("win")
        _has_display = _is_windows or bool(os.environ.get("DISPLAY") or os.environ.get("WAYLAND_DISPLAY"))
        if not _has_display:
            logging.warning("[StartupController] No display detected ($DISPLAY/$WAYLAND_DISPLAY not set) — skipping fallback dialog.")
            return
        try:
            import tkinter as _tk
            import tkinter.messagebox as _mb

            # Minimal hidden root to host the messagebox
            _root = _tk.Tk()
            _root.withdraw()
            _root.attributes("-topmost", True)

            answer = _mb.askyesno(
                title="FLIR Thermal — Web Interface Stopped",
                message=(
                    "The web interface has stopped.\n\n"
                    "Would you like to switch to desktop mode?"
                ),
                icon=_mb.QUESTION,
                default=_mb.YES,
                parent=_root,
            )
            _root.destroy()

            if answer:
                logging.info("[StartupController] User chose desktop → MainApp.")
                self._launch_tkinter_directly()
            else:
                logging.info("[StartupController] User declined — exiting.")

        except Exception as _e:
            logging.error(f"[StartupController] Dialog error: {_e}")

    def _launch_tkinter_directly(self) -> None:
        """Instantiate and run MainApp on the calling (main) thread."""
        if not UI_AVAILABLE:
            logging.error("[StartupController] Cannot launch Tkinter — no display.")
            return
        logging.info("[StartupController] Launching MainApp.")
        app = MainApp()
        app.mainloop()


