# ║  freeze_support() always first (Windows PyInstaller requirement).       ║
# ╚══════════════════════════════════════════════════════════════════════════╝

if __name__ == "__main__":
    multiprocessing.freeze_support()

    if RUNTIME_MODE == "headless":
        logging.info(
            f"[SECTION 19] FLIR Thermal Engine v{APP_VERSION} headless mode — "
            "CoreEngine ready.  Import and call CORE.* methods directly."
        )

    elif RUNTIME_MODE == "local" and not WEB_AVAILABLE:
        # Web libs not present → skip controller overhead, go direct
        logging.info("[SECTION 19] WEB_AVAILABLE=False → direct Tkinter launch.")
        _app = MainApp()
        _app.mainloop()

    else:
        # Hybrid (default) or explicit web mode
        _controller = StartupController(
            port=int(os.environ.get("FLIR_PORT", "8000")),
            host=os.environ.get("FLIR_HOST", "127.0.0.1"),
        )
        _controller.run()

